INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 1, '¿POR qué se amotinan las gentes, Y los pueblos piensan vanidad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 2, 'Estarán los reyes de la tierra, Y príncipes consultarán unidos Contra Jehová, y contra su ungido, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 3, 'Rompamos sus coyundas, Y echemos de nosotros sus cuerdas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 4, 'El que mora en los cielos se reirá; El Señor se burlará de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 5, 'Entonces hablará á ellos en su furor, Y turbarálos con su ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 6, 'Yo empero he puesto mi rey Sobre Sión, monte de mi santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 7, 'Yo publicaré el decreto: Jehová me ha dicho: Mi hijo eres tú; Yo te engendré hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 8, 'Pídeme, y te daré por heredad las gentes, Y por posesión tuya los términos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 9, 'Quebrantarlos has con vara de hierro: Como vaso de alfarero los desmenuzarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 10, 'Y ahora, reyes, entended: Admitid corrección, jueces de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 11, 'Servid á Jehová con temor, Y alegraos con temblor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 2, 12, 'Besad al Hijo, porque no se enoje, y perezcáis en el camino, Cuando se encendiere un poco su furor. Bienaventurados todos los que en él confían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 1, '¡OH Jehová, cuánto se han multiplicado mis enemigos! Muchos se levantan contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 2, 'Muchos dicen de mi vida: No hay para él salud en Dios. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 3, 'Mas tú, Jehová, eres escudo alrededor de mí: Mi gloria, y el que ensalza mi cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 4, 'Con mi voz clamé á Jehová, Y él me respondió desde el monte de su santidad. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 5, 'Yo me acosté, y dormí, Y desperté; porque Jehová me sostuvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 6, 'No temeré de diez millares de pueblos, Que pusieren cerco contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 7, 'Levántate, Jehová; sálvame, Dios mío: Porque tú heriste á todos mis enemigos en la quijada; Los dientes de los malos quebrantaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 3, 8, 'De Jehová es la salud: Sobre tu pueblo será tu bendición. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 1, 'RESPONDEME cuando clamo, oh Dios de mi justicia: Estando en angustia, tú me hiciste ensanchar: Ten misericordia de mí, y oye mi oración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 2, 'Hijos de los hombres, ¿hasta cuándo volveréis mi honra en infamia, Amaréis la vanidad, y buscaréis la mentira? (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 3, 'Sabed pues, que Jehová hizo apartar al pío para sí: Jehová oirá cuando yo á él clamare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 4, 'Temblad, y no pequéis: Conversad en vuestro corazón sobre vuestra cama, y desistid. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 5, 'Ofreced sacrificios de justicia, Y confiad en Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 6, 'Muchos dicen: ¿Quién nos mostrará el bien? Alza sobre nosotros, oh Jehová, la luz de tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 7, 'Tú diste alegría en mi corazón, Más que tienen ellos en el tiempo que se multiplicó su grano y su mosto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 4, 8, 'En paz me acostaré, y asimismo dormiré; Porque solo tú, Jehová, me harás estar confiado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 1, 'ESCUCHA, oh Jehová, mis palabras; Considera la meditación mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 2, 'Está atento á la voz de mi clamor, Rey mío y Dios mío, Porque á ti oraré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 3, 'Oh Jehová, de mañana oirás mi voz; De mañana me presentaré á ti, y esperaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 4, 'Porque tú no eres un Dios que ame la maldad: El malo no habitará junto á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 5, 'No estarán los insensatos delante de tus ojos: Aborreces á todos los que obran iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 6, 'Destruirás á los que hablan mentira: Al hombre de sangres y de engaño abominará Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 7, 'Y yo en la multitud de tu misericordia entraré en tu casa: Adoraré hacia el templo de tu santidad en tu temor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 8, 'Guíame, Jehová, en tu justicia á causa de mis enemigos; Endereza delante de mí tu camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 9, 'Porque no hay en su boca rectitud: Sus entrañas son pravedades; Sepulcro abierto su garganta: Con su lengua lisonjearán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 10, 'Desbarátalos, oh Dios; Caigan de sus consejos: Por la multitud de sus rebeliones échalos, Porque se rebelaron contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 11, 'Y alegrarse han todos los que en ti confían; Para siempre darán voces de júbilo, porque tú los defiendes: Y en ti se regocijarán los que aman tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 5, 12, 'Porque tú, oh Jehová, bendecirás al justo; Lo cercarás de benevolencia como con un escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 1, 'JEHOVA, no me reprendas en tu furor, Ni me castigues con tu ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 2, 'Ten misericordia de mí, oh Jehová, porque yo estoy debilitado: Sáname, oh Jehová, porque mis huesos están conmovidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 3, 'Mi alma asimismo está muy conturbada: Y tú, Jehová, ¿hasta cuándo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 4, 'Vuelve, oh Jehová, libra mi alma; Sálvame por tu misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 5, 'Porque en la muerte no hay memoria de ti: ¿Quién te loará en el sepulcro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 6, 'Heme consumido á fuerza de gemir: Todas las noches inundo mi lecho, Riego mi estrado con mis lágrimas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 7, 'Mis ojos están carcomidos de descontento; Hanse envejecido á causa de todos mis angustiadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 8, 'Apartaos de mí, todos los obradores de iniquidad; Porque Jehová ha oído la voz de mi lloro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 9, 'Jehová ha oído mi ruego; Ha recibido Jehová mi oración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 6, 10, 'Se avergonzarán, y turbaránse mucho todos mis enemigos; Volveránse y serán avergonzados subitáneamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 1, 'JEHOVA Dios mío, en ti he confiado: Sálvame de todos los que me persiguen, y líbrame;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 2, 'No sea que arrebate mi alma, cual león Que despedaza, sin que haya quien libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 3, 'Jehová Dios mío, si yo he hecho esto, Si hay en mis manos iniquidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 4, 'Si dí mal pago al pacífico conmigo, (Hasta he libertado al que sin causa era mi enemigo;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 5, 'Persiga el enemigo mi alma, y alcánce la; Y pise en tierra mi vida, Y mi honra ponga en el polvo. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 6, 'Levántate; oh Jehová, con tu furor; Alzate á causa de las iras de mis angustiadores, Y despierta en favor mío el juicio que mandaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 7, 'Y te rodeará concurso de pueblo; Por cuyo amor vuélvete luego á levantar en alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 8, 'Jehová juzgará los pueblos: Júzgame, oh Jehová, conforme á mi justicia y conforme á mi integridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 9, 'Consúmase ahora la malicia de los inicuos, y establece al justo; Pues el Dios justo prueba los corazones y los riñones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 10, 'Mi escudo está en Dios, Que salva á los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 11, 'Dios es el que juzga al justo: Y Dios está airado todos los días contra el impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 12, 'Si no se convirtiere, él afilará su espada: Armado tiene ya su arco, y lo ha preparado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 13, 'Asimismo ha aparejado para él armas de muerte; Ha labrado sus saetas para los que persiguen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 14, 'He aquí ha tenido parto de iniquidad: Concibió trabajo, y parió mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 15, 'Pozo ha cavado, y ahondádolo; Y en la fosa que hizo caerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 16, 'Su trabajo se tornará sobre su cabeza, Y su agravio descenderá sobre su mollera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 7, 17, 'Alabaré yo á Jehová conforme á su justicia, Y cantaré al nombre de Jehová el Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 1, 'OH Jehová, Señor nuestro, ¡Cuán grande es tu nombre en toda la tierra, Que has puesto tu gloria sobre los cielos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 2, 'De la boca de los chiquitos y de los que maman, fundaste la fortaleza, A causa de tus enemigos, Para hacer cesar al enemigo, y al que se venga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 3, 'Cuando veo tus cielos, obra de tus dedos, La luna y las estrellas que tú formaste:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 4, 'Digo: ¿Qué es el hombre, para que tengas de él memoria, Y el hijo del hombre, que lo visites?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 5, 'Pues le has hecho poco menor que los ángeles, Y coronástelo de gloria y de lustre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 6, 'Hicístelo enseñorear de las obras de tus manos; Todo lo pusiste debajo de sus pies:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 7, 'Ovejas, y bueyes, todo ello; Y asimismo las bestias del campo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 8, 'Las aves de los cielos, y los peces de la mar; Todo cuanto pasa por los senderos de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 8, 9, 'Oh Jehová, Señor nuestro, ¡Cuán grande es tu nombre en toda la tierra!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 1, 'TE alabaré, oh Jehová, con todo mi corazón; Contaré todas tus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 2, 'Alegraréme y regocijaréme en ti: Cantaré á tu nombre, oh Altísimo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 3, 'Por haber sido mis enemigos vueltos atrás: Caerán y perecerán delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 4, 'Porque has hecho mi juicio y mi causa: Sentástete en silla juzgando justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 5, 'Reprendiste gentes, destruiste al malo, Raíste el nombre de ellos para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 6, 'Oh enemigo, acabados son para siempre los asolamientos; Y las ciudades que derribaste, Su memoria pereció con ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 7, 'Mas Jehová permanecerá para siempre: Dispuesto ha su trono para juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 8, 'Y él juzgará el mundo con justicia; Y juzgará los pueblos con rectitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 9, 'Y será Jehová refugio al pobre, Refugio para el tiempo de angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 10, 'Y en ti confiarán los que conocen tu nombre; Por cuanto tú, oh Jehová, no desamparaste á los que te buscaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 11, 'Cantad á Jehová, que habita en Sión: Noticiad en los pueblos sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 12, 'Porque demandando la sangre se acordó de ellos: No se olvidó del clamor de los pobres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 13, 'Ten misericordia de mí, Jehová: Mira mi aflicción que padezco de los que me aborrecen, Tú que me levantas de las puertas de la muerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 14, 'Porque cuente yo todas tus alabanzas En las puertas de la hija de Sión, Y me goce en tu salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 15, 'Hundiéronse las gentes en la fosa que hicieron; En la red que escondieron fué tomado su pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 16, 'Jehová fué conocido en el juicio que hizo; En la obra de sus manos fué enlazado el malo. (Higaion. Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 17, 'Los malos serán trasladados al infierno, Todas las gentes que se olvidan de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 18, 'Porque no para siempre será olvidado el pobre; Ni la esperanza de los pobres perecerá perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 19, 'Levántate, oh Jehová; no se fortalezca el hombre; Sean juzgadas las gentes delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 9, 20, 'Pon, oh Jehová, temor en ellos: Conozcan las gentes que son no más que hombres. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 1, '¿POR qué estás lejos, oh Jehová, Y te escondes en el tiempo de la tribulación?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 2, 'Con arrogancia el malo persigue al pobre: Serán cogidos en los artificios que han ideado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 3, 'Por cuanto se alaba el malo del deseo de su alma, Y bendice al codicioso ó quien Jehová aborrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 4, 'El malo, por la altivez de su rostro, no busca á Dios: No hay Dios en todos sus pensamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 5, 'Sus caminos son viciosos en todo tiempo: Tus juicios los tiene muy lejos de su vista: Echa bocanadas en orden á todos sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 6, 'Dice en su corazón: No seré movido en ningún tiempo, Ni jamás me alcanzará el infortunio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 7, 'Llena está su boca de maldición, y de engaños y fraude: Debajo de su lengua, vejación y maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 8, 'Está en las guaridas de las aldeas: En los escondrijos mata al inocente: Sus ojos están acechando al pobre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 9, 'Acecha en oculto, como el león desde su cama: Acecha para arrebatar al pobre: Arrebata al pobre trayéndolo á su red.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 10, 'Encógese, agáchase, Y caen en sus fuerzas muchos desdichados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 11, 'Dice en su corazón: Dios está olvidado, Ha encubierto su rostro; nunca lo verá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 12, 'Levántate, oh Jehová Dios, alza tu mano, No te olvides de los pobres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 13, '¿Por qué irrita el malo á Dios? En su corazón ha dicho que no lo inquirirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 14, 'Tú lo tienes visto: porque tú miras el trabajo, y la vejación, para vengar le por tu mano: A ti se acoge el pobre, Tú eres el amparo del huérfano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 15, 'Quebranta el brazo del malo: Del maligno buscarás su maldad, hasta que ninguna halles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 16, 'Jehová, Rey eterno y perpetuo: De su tierra fueron destruídas las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 17, 'El deseo de los humildes oíste, oh Jehová: Tú dispones su corazón, y haces atento tu oído;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 10, 18, 'Para juzgar al huérfano y al pobre, A fin de que no vuelva más á hacer violencia el hombre de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 1, 'EN Jehová he confiado; ¿Cómo decís á mi alma: Escapa al monte cual ave?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 2, 'Porque he aquí, los malos flecharon el arco, Apercibieron sus saetas sobre la cuerda, Para asaetear en oculto á los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 3, 'Si fueren destruídos los fundamentos, ¿Qué ha de hacer el justo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 4, 'Jehová en el templo de su santidad: La silla de Jehová está en el cielo: Sus ojos ven, sus párpados examinan á los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 5, 'Jehová prueba al justo; Empero al malo y al que ama la violencia, su alma aborrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 6, 'Sobre los malos lloverá lazos; Fuego y azufre, con vientos de torbellinos, será la porción del cáliz de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 11, 7, 'Porque el justo Jehová ama la justicia: Al recto mirará su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 1, 'SALVA, oh Jehová, porque se acabaron los misericordiosos: Porque se han acabado los fieles de entre los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 2, 'Mentira habla cada uno con su prójimo; Con labios lisonjeros, con corazón doble hablan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 3, 'Destruirá Jehová todos los labios lisonjeros, La lengua que habla grandezas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 4, 'Que dijeron: Por nuestra lengua prevaleceremos; Nuestros labios están con nosotros: ¿quién nos es señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 5, 'Por la opresión de los pobres, por el gemido de los menesterosos, Ahora me levantaré, dice Jehová: Pondrélos en salvo del que contra ellos se engríe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 6, 'Las palabras de Jehová, palabras limpias; Plata refinada en horno de tierra, Purificada siete veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 7, 'Tú, Jehová, los guardarás; Guárdalos para siempre de aquesta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 12, 8, 'Cercando andan los malos, Mientras son exaltados los más viles de los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 13, 1, '¿HASTA cuándo, Jehová? ¿me olvidarás para siempre? ¿Hasta cuándo esconderás tu rostro de mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 13, 2, '¿Hasta cuándo pondré consejos en mi alma, Con ansiedad en mi corazón cada día? ¿Hasta cuándo será enaltecido mi enemigo sobre mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 13, 3, 'Mira, óyeme, Jehová Dios mío: Alumbra mis ojos, porque no duerma en muerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 13, 4, 'Porque no diga mi enemigo, Vencílo: Mis enemigos se alegrarán, si yo resbalare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 13, 5, 'Mas yo en tu misericordia he confiado: Alegraráse mi corazón en tu salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 13, 6, 'Cantaré á Jehová, Porque me ha hecho bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 1, 'DIJO el necio en su corazón: No hay Dios. Corrompiéronse, hicieron obras abominables; No hay quien haga bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 2, 'Jehová miró desde los cielos sobre los hijos de los hombres, Por ver si había algún entendido, Que buscara á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 3, 'Todos declinaron, juntamente se han corrompido: No hay quien haga bien, no hay ni siquiera uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 4, '¿No tendrán conocimiento todos los que obran iniquidad, Que devoran á mi pueblo como si pan comiesen, Y á Jehová no invocaron?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 5, 'Allí temblaron de espanto; Porque Dios está con la nación de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 6, 'El consejo del pobre habéis escarnecido, Por cuanto Jehová es su esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 14, 7, '¡Quién diese de Sión la salud de Israel! En tornando Jehová la cautividad de su pueblo, Se gozará Jacob, y alegraráse Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 15, 1, 'JEHOVA, ¿quién habitará en tu tabernáculo? ¿Quién residirá en el monte de tu santidad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 15, 2, 'El que anda en integridad, y obra justicia, Y habla verdad en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 15, 3, 'El que no detrae con su lengua, Ni hace mal á su prójimo, Ni contra su prójimo acoge oprobio alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 15, 4, 'Aquel á cuyos ojos es menospreciado el vil; Mas honra á los que temen á Jehová: Y habiendo jurado en daño suyo, no por eso muda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 15, 5, 'Quien su dinero no dió á usura, Ni contra el inocente tomó cohecho. El que hace estas cosas, no resbalará para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 1, 'GUARDAME, oh Dios, porque en ti he confiado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 2, 'Dijiste, oh alma mía, á Jehová: Tú eres el Señor: Mi bien á ti no aprovecha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 3, 'Sino á los santos que están en la tierra, Y á los íntegros: toda mi afición en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 4, 'Multiplicaránse los dolores de aquellos que sirven diligentes á otro dios: No ofreceré yo sus libaciones de sangre, Ni en mis labios tomaré sus nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 5, 'Jehová es la porción de mi parte y de mi copa; Tú sustentarás mi suerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 6, 'Las cuerdas me cayeron en lugares deleitosos, Y es hermosa la heredad que me ha tocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 7, 'Bendeciré á Jehová que me aconseja: Aun en las noches me enseñan mis riñones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 8, 'A Jehová he puesto siempre delante de mí: Porque está á mi diestra no seré conmovido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 9, 'Alegróse por tanto mi corazón, y se gozó mi gloria: También mi carne reposará segura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 10, 'Porque no dejarás mi alma en el sepulcro; Ni permitirás que tu santo vea corrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 16, 11, 'Me mostrarás la senda de la vida: Hartura de alegrías hay con tu rostro; Deleites en tu diestra para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 1, 'OYE, oh Jehová, justicia; está atento á mi clamor; Escucha mi oración hecha sin labios de engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 2, 'De delante de tu rostro salga mi juicio; Vean tus ojos la rectitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 3, 'Tú has probado mi corazón, hasme visitado de noche; Me has apurado, y nada inicuo hallaste: Heme propuesto que mi boca no ha de propasarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 4, 'Para las obras humanas, por la palabra de tus labios Yo me he guardado de las vías del destructor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 5, 'Sustenta mis pasos en tus caminos, Porque mis pies no resbalen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 6, 'Yo te he invocado, por cuanto tú me oirás, oh Dios: Inclina á mí tu oído, escucha mi palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 7, 'Muestra tus estupendas misericordias, tú que salvas á los que en ti confían. De los que se levantan contra tu diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 8, 'Guárdame como lo negro de la niñeta del ojo, Escóndeme con la sombra de tus alas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 9, 'De delante de los malos que me oprimen, De mis enemigos que me cercan por la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 10, 'Cerrados están con su grosura; Con su boca hablan soberbiamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 11, 'Nuestros pasos nos han cercado ahora: Puestos tienen sus ojos para echar nos por tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 12, 'Parecen al león que desea hacer presa, Y al leoncillo que está escondido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 13, 'Levántate, oh Jehová; Prevén su encuentro, póstrale: Libra mi alma del malo con tu espada;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 14, 'De los hombres con tu mano, oh Jehová, De los hombres de mundo, cuya parte es en esta vida, Y cuyo vientre hinches de tu tesoro: Hartan sus hijos, Y dejan el resto á sus chiquitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 17, 15, 'Yo en justicia veré tu rostro: Seré saciado cuando despertare á tu semejanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 1, 'AMARTE he, oh Jehová, fortaleza mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 2, 'Jehová, roca mía y castillo mío, y mi libertador; Dios mío, fuerte mío, en él confiaré; Escudo mío, y el cuerno de mi salud, mi refugio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 3, 'Invocaré á Jehová, digno de ser alabado, Y seré salvo de mis enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 4, 'Cercáronme dolores de muerte, Y torrentes de perversidad me atemorizaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 5, 'Dolores del sepulcro me rodearon, Previniéronme lazos de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 6, 'En mi angustia invoqué á Jehová, Y clamé á mi Dios: El oyó mi voz desde su templo, Y mi clamor llegó delante de él, á sus oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 7, 'Y la tierra fué conmovida y tembló; Y moviéronse los fundamentos de los montes, Y se estremecieron, porque se indignó él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 8, 'Humo subió de su nariz, Y de su boca consumidor fuego; Carbones fueron por él encendidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 9, 'Y bajó los cielos, y descendió; Y oscuridad debajo de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 10, 'Y cabalgó sobre un querubín, y voló: Voló sobre las alas del viento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 11, 'Puso tinieblas por escondedero suyo, su pabellón en derredor de sí; Oscuridad de aguas, nubes de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 12, 'Por el resplandor delante de él, sus nubes pasaron; Granizo y carbones ardientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 13, 'Y tronó en los cielos Jehová, Y el Altísimo dió su voz; Granizo y carbones de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 14, 'Y envió sus saetas, y desbaratólos; Y echó relámpagos, y los destruyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 15, 'Y aparecieron las honduras de las aguas, Y descubriéronse los cimientos del mundo, A tu reprensión, oh Jehová, Por el soplo del viento de tu nariz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 16, 'Envió desde lo alto; tomóme, Sácome de las muchas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 17, 'Libróme de mi poderoso enemigo, Y de los que me aborrecían, aunque eran ellos más fuertes que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 18, 'Asaltáronme en el día de mi quebranto: Mas Jehová fué mi apoyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 19, 'Y sacóme á anchura: Libróme, porque se agradó de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 20, 'Hame pagado Jehová conforme á mi justicia: Conforme á la limpieza de mis manos me ha vuelto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 21, 'Porque yo he guardado los caminos de Jehová, Y no me aparté impíamente de mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 22, 'Pues todos sus juicios estuvieron delante de mí, Y no eché de mí sus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 23, 'Y fuí integro para con él, y cauteléme de mi maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 24, 'Pagóme pues Jehová conforme á mi justicia; Conforme á la limpieza de mis manos delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 25, 'Con el misericordioso te mostrarás misericordioso, Y recto para con el hombre íntegro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 26, 'Limpio te mostrarás para con el limpio, Y severo serás para con el perverso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 27, 'Y tú salvarás al pueblo humilde, Y humillarás los ojos altivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 28, 'Tú pues alumbrarás mi lámpara: Jehová mi Dios alumbrará mis tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 29, 'Porque contigo desharé ejércitos; Y con mi Dios asaltaré muros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 30, 'Dios, perfecto su camino: Es acendrada la palabra de Jehová: Escudo es á todos los que en él esperan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 31, 'Porque ¿qué Dios hay fuera de Jehová? ¿Y qué fuerte fuera de nuestro Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 32, 'Dios es el que me ciñe de fuerza, E hizo perfecto mi camino;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 33, 'Quien pone mis pies como pies de ciervas, E hízome estar sobre mis alturas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 34, 'Quien enseña mis manos para la batalla, Y será quebrado con mis brazos el arco de acero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 35, 'Dísteme asimismo el escudo de tu salud: Y tu diestra me sustentó, Y tu benignidad me ha acrecentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 36, 'Ensanchaste mis pasos debajo de mí, Y no titubearon mis rodillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 37, 'Perseguido he mis enemigos, y alcancélos, Y no volví hasta acabarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 38, 'Helos herido, y no podrán levantarse: Cayeron debajo de mis pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 39, 'Pues me ceñiste de fortaleza para la pelea; Has agobiado mis enemigos debajo de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 40, 'Y dísteme la cerviz de mis enemigos, Y destruí á los que me aborrecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 41, 'Clamaron, y no hubo quien salvase: Aun á Jehová, mas no los oyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 42, 'Y molílos como polvo delante del viento; Esparcílos como lodo de las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 43, 'Librásteme de contiendas de pueblo: Pusísteme por cabecera de gentes: Pueblo que yo no conocía, me sirvió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 44, 'Así que hubo oído, me obedeció; Los hijos de extraños me mintieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 45, 'Los extraños flaquearon, Y tuvieron miedo desde sus encerramientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 46, 'Viva Jehová, y sea bendita mi roca; Y ensalzado sea el Dios de mi salud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 47, 'El Dios que me da las venganzas, Y sujetó pueblos á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 48, 'Mi libertador de mis enemigos: Hicísteme también superior de mis adversarios; Librásteme de varón violento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 49, 'Por tanto yo te confesaré entre las gentes, oh Jehová, Y cantaré á tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 18, 50, 'El cual engrandece las saludes de su rey, Y hace misericordia á su ungido, A David y á su simiente, para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 1, 'LOS cielos cuentan la gloria de Dios, Y la expansión denuncia la obra de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 2, 'El un día emite palabra al otro día, Y la una noche á la otra noche declara sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 3, 'No hay dicho, ni palabras, Ni es oída su voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 4, 'Por toda la tierra salió su hilo, Y al cabo del mundo sus palabras. En ellos puso tabernáculo para el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 5, 'Y él, como un novio que sale de su tálamo, Alégrase cual gigante para correr el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 6, 'Del un cabo de los cielos es su salida, Y su giro hasta la extremidad de ellos: Y no hay quien se esconda de su calor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 7, 'La ley de Jehová es perfecta, que vuelve el alma: El testimonio de Jehová, fiel, que hace sabio al pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 8, 'Los mandamientos de Jehová son rectos, que alegran el corazón: El precepto de Jehová, puro, que alumbra los ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 9, 'El temor de Jehová, limpio, que permanece para siempre; Los juicios de Jehová son verdad, todos justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 10, 'Deseables son más que el oro, y más que mucho oro afinado; Y dulces más que miel, y que la que destila del panal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 11, 'Tu siervo es además amonestado con ellos: En guardarlos hay grande galardón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 12, 'Los errores, ¿quién los entenderá? Líbrame de los que me son ocultos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 13, 'Detén asimismo á tu siervo de las soberbias; Que no se enseñoreen de mí: Entonces seré íntegro, y estaré limpio de gran rebelión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 19, 14, 'Sean gratos los dichos de mi boca y la meditación de mi corazón delante de ti, Oh Jehová, roca mía, y redentor mío');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 1, 'OIGATE Jehová en el día de conflicto; Defiéndate el nombre del Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 2, 'Envíete ayuda desde el santuario, Y desde Sión te sostenga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 3, 'Haga memoria de todos tus presentes, Y reduzca á ceniza tu holocausto. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 4, 'Déte conforme á tu corazón, Y cumpla todo tu consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 5, 'Nosotros nos alegraremos por tu salud, Y alzaremos pendón en el nombre de nuestro Dios: Cumpla Jehová todas tus peticiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 6, 'Ahora echo de ver que Jehová guarda á su ungido: Oirálo desde los cielos de su santidad, Con la fuerza de la salvación de su diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 7, 'Estos confían en carros, y aquéllos en caballos: Mas nosotros del nombre de Jehová nuestro Dios tendremos memoria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 8, 'Ellos arrodillaron, y cayeron; Mas nosotros nos levantamos, y nos enhestamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 20, 9, 'Salva, Jehová: Que el Rey nos oiga el día que lo invocáremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 1, 'ALEGRARASE el rey en tu fortaleza, oh Jehová; Y en tu salud se gozará mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 2, 'El deseo de su corazón le diste, Y no le negaste lo que sus labios pronunciaron. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 3, 'Pues le has salido al encuentro con bendiciones de bien: Corona de oro fino has puesto sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 4, 'Vida te demandó, y dístele Largura de días por siglos y siglos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 5, 'Grande es su gloria en tu salud: Honra y majestad has puesto sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 6, 'Porque lo has bendecido para siempre; Llenástelo de alegría con tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 7, 'Por cuanto el rey confía en Jehová, Y en la misericordia del Altísimo, no será conmovido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 8, 'Alcanzará tu mano á todos tus enemigos; Tu diestra alcanzará á los que te aborrecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 9, 'Ponerlos has como horno de fuego en el tiempo de tu ira: Jehová los deshará en su furor, Y fuego los consumirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 10, 'Su fruto destruirás de la tierra, Y su simiente de entre los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 11, 'Porque trazaron el mal contra ti: Fraguaron maquinaciones, mas no prevalecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 12, 'Pues tú los pondrás en fuga, Cuando aparejares en tus cuerdas las saetas contra sus rostros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 21, 13, 'Ensálzate, oh Jehová, con tu fortaleza: Cantaremos y alabaremos tu poderío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 1, 'DIOS mío, Dios mío, ¿por qué me has dejado? ¿Por qué estás lejos de mi salud, y de las palabras de mi clamor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 2, 'Dios mío, clamo de día, y no oyes; Y de noche, y no hay para mí silencio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 3, 'Tú empero eres santo, Tú que habitas entre las alabanzas de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 4, 'En ti esperaron nuestros padres: Esperaron, y tú los libraste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 5, 'Clamaron á ti, y fueron librados: Esperaron en ti, y no se avergonzaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 6, 'Mas yo soy gusano, y no hombre; Oprobio de los hombres, y desecho del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 7, 'Todos los que me ven, escarnecen de mí; Estiran los labios, menean la cabeza, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 8, 'Remítese á Jehová, líbrelo; Sálvele, puesto que en él se complacía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 9, 'Empero tú eres el que me sacó del vientre, El que me haces esperar desde que estaba á los pechos de mi madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 10, 'Sobre ti fuí echado desde la matriz: Desde el vientre de mi madre, tú eres mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 11, 'No te alejes de mí, porque la angustia está cerca; Porque no hay quien ayude.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 12, 'Hanme rodeado muchos toros; Fuertes toros de Basán me han cercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 13, 'Abrieron sobre mí su boca, Como león rapante y rugiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 14, 'Heme escurrido como aguas, Y todos mis huesos se descoyuntaron: Mi corazón fué como cera, Desliéndose en medio de mis entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 15, 'Secóse como un tiesto mi vigor, Y mi lengua se pegó á mi paladar; Y me has puesto en el polvo de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 16, 'Porque perros me han rodeado, Hame cercado cuadrilla de malignos: Horadaron mis manos y mis pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 17, 'Contar puedo todos mis huesos; Ellos miran, considéranme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 18, 'Partieron entre sí mis vestidos, Y sobre mi ropa echaron suertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 19, 'Mas tú, Jehová, no te alejes; Fortaleza mía, apresúrate para mi ayuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 20, 'Libra de la espada mi alma; Del poder del perro mi única.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 21, 'Sálvame de la boca del león, Y óyeme librándome de los cuernos de los unicornios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 22, 'Anunciaré tu nombre á mis hermanos: En medio de la congregación te alabaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 23, 'Los que teméis á Jehová, alabadle; Glorificadle, simiente toda de Jacob; Y temed de él, vosotros, simiente toda de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 24, 'Porque no menospreció ni abominó la aflicción del pobre, Ni de él escondió su rostro; Sino que cuando clamó á él, oyóle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 25, 'De ti será mi alabanza en la grande congregación; Mis votos pagaré delante de los que le temen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 26, 'Comerán los pobres, y serán saciados: Alabarán á Jehová los que le buscan: Vivirá vuestro corazón para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 27, 'Acordarse han, y volveránse á Jehová todos los términos de la tierra; Y se humillarán delante de ti todas las familias de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 28, 'Porque de Jehová es el reino; Y él se enseñoreará de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 29, 'Comerán y adorarán todos los poderosos de la tierra: Postraránse delante de él todos los que descienden al polvo, Si bien ninguno puede conservar la vida á su propia alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 30, 'La posteridad le servirá; Será ella contada por una generación de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 22, 31, 'Vendrán, y anunciarán al pueblo que naciere, Su justicia que él hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 23, 1, 'JEHOVA es mi pastor; nada me faltará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 23, 2, 'En lugares de delicados pastos me hará yacer: Junto á aguas de reposo me pastoreará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 23, 3, 'Confortará mi alma; Guiárame por sendas de justicia por amor de su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 23, 4, 'Aunque ande en valle de sombra de muerte, No temeré mal alguno; porque tú estarás conmigo: Tu vara y tu cayado me infundirán aliento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 23, 5, 'Aderezarás mesa delante de mí, en presencia de mis angustiadores: Ungiste mi cabeza con aceite: mi copa está rebosando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 23, 6, 'Ciertamente el bien y la misericordia me seguirán todos los días de mi vida: Y en la casa de Jehová moraré por largos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 1, 'DE Jehová es la tierra y su plenitud; El mundo, y los que en él habitan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 2, 'Porque él la fundó sobre los mares, Y afirmóla sobre los ríos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 3, '¿Quién subirá al monte de Jehová? ¿Y quién estará en el lugar de su santidad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 4, 'El limpio de manos, y puro de corazón: El que no ha elevado su alma á la vanidad, Ni jurado con engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 5, 'El recibirá bendición de Jehová, Y justicia del Dios de salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 6, 'Tal es la generación de los que le buscan, De los que buscan tu rostro, oh Dios de Jacob. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 7, 'Alzad, oh puertas, vuestras cabezas, Y alzaos vosotras, puertas eternas, Y entrará el Rey de gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 8, '¿Quién es este Rey de gloria? Jehová el fuerte y valiente, Jehová el poderoso en batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 9, 'Alzad, oh puertas, vuestras cabezas, Y alzaos vosotras, puertas eternas, Y entrará el Rey de gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 24, 10, '¿Quién es este Rey de gloria? Jehová de los ejércitos, El es el Rey de la gloria. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 1, 'A TI, oh Jehová, levantaré mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 2, 'Dios mío, en ti confío; No sea yo avergonzado, No se alegren de mí mis enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 3, 'Ciertamente ninguno de cuantos en ti esperan será confundido: Serán avergonzados los que se rebelan sin causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 4, 'Muéstrame, oh Jehová, tus caminos; Enséñame tus sendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 5, 'Encamíname en tu verdad, y enséñame; Porque tú eres el Dios de mi salud: En ti he esperado todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 6, 'Acuérdate, oh Jehová, de tus conmiseraciones y de tus misericordias, Que son perpetuas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 7, 'De los pecados de mi mocedad, y de mis rebeliones, no te acuerdes; Conforme á tu misericordia acuérdate de mí, Por tu bondad, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 8, 'Bueno y recto es Jehová: Por tanto él enseñará á los pecadores el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 9, 'Encaminará á los humildes por el juicio, Y enseñará á los mansos su carrera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 10, 'Todas las sendas de Jehová son misericordia y verdad, Para los que guardan su pacto y sus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 11, 'Por amor de tu nombre, oh Jehová, Perdonarás también mi pecado; porque es grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 12, '¿Quién es el hombre que teme á Jehová? El le enseñará el camino que ha de escoger.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 13, 'Su alma reposará en el bien, Y su simiente heredará la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 14, 'El secreto de Jehová es para los que le temen; Y á ellos hará conocer su alianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 15, 'Mis ojos están siempre hacia Jehová; Porque él sacará mis pies de la red.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 16, 'Mírame, y ten misericordia de mí; Porque estoy solo y afligido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 17, 'Las angustias de mi corazón se han aumentado: Sácame de mis congojas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 18, 'Mira mi aflicción y mi trabajo: Y perdona todos mis pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 19, 'Mira mis enemigos, que se han multiplicado, Y con odio violento me aborrecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 20, 'Guarda mi alma, y líbrame: No sea yo avergonzado, porque en ti confié.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 21, 'Integridad y rectitud me guarden; Porque en ti he esperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 25, 22, 'Redime, oh Dios, á Israel De todas sus angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 1, 'JUZGAME, oh Jehová, porque yo en mi integridad he andado: Confiado he asimismo en Jehová, no vacilaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 2, 'Pruébame, oh Jehová, y sondéame: Examina mis riñones y mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 3, 'Porque tu misericordia está delante de mis ojos, Y en tu verdad ando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 4, 'No me he sentado con hombres de falsedad; Ni entré con los que andan encubiertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 5, 'Aborrecí la reunión de los malignos, Y con los impíos nunca me senté.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 6, 'Lavaré en inocencia mis manos, Y andaré alrededor de tu altar, oh Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 7, 'Para exclamar con voz de acción de gracias, Y para contar todas tus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 8, 'Jehová, la habitación de tu casa he amado, Y el lugar del tabernáculo de tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 9, 'No juntes con los pecadores mi alma, Ni con los hombres de sangres mi vida:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 10, 'En cuyas manos está el mal, Y su diestra está llena de sobornos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 11, 'Yo empero andaré en mi integridad: Redímeme, y ten misericordia de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 26, 12, 'Mi pie ha estado en rectitud: En las congregaciones bendeciré á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 1, 'JEHOVA es mi luz y mi salvación: ¿de quién temeré? Jehová es la fortaleza de mi vida: ¿de quién he de atemorizarme?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 2, 'Cuando se allegaron contra mí los malignos, mis angustiadores y mis enemigos, Para comer mis carnes, ellos tropezaron y cayeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 3, 'Aunque se asiente campo contra mí, No temerá mi corazón: Aunque contra mí se levante guerra, Yo en esto confío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 4, 'Una cosa he demandado á Jehová, ésta buscaré: Que esté yo en la casa de Jehová todos los días de mi vida, Para contemplar la hermosura de Jehová, y para inquirir en su templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 5, 'Porque él me esconderá en su tabernáculo en el día del mal; Ocultaráme en lo reservado de su pabellón; Pondráme en alto sobre una roca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 6, 'Y luego ensalzará mi cabeza sobre mis enemigos en derredor de mí: Y yo sacrificaré en su tabernáculo sacrificios de júbilo: Cantaré y salmearé á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 7, 'Oye, oh Jehová, mi voz con que á ti clamo; Y ten misericordia de mí, respóndeme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 8, 'Mi corazón ha dicho de ti: Buscad mi rostro. Tu rostro buscaré, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 9, 'No escondas tu rostro de mí, No apartes con ira á tu siervo: Mi ayuda has sido; No me dejes y no me desampares, Dios de mi salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 10, 'Aunque mi padre y mi madre me dejaran, Jehová con todo me recogerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 11, 'Enséñame, oh Jehová, tu camino, Y guíame por senda de rectitud, A causa de mis enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 12, 'No me entregues á la voluntad de mis enemigos; Porque se han levantado contra mí testigos falsos, y los que respiran crueldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 13, 'Hubiera yo desmayado, si no creyese que tengo de ver la bondad de Jehová En la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 27, 14, 'Aguarda á Jehová; Esfuérzate, y aliéntese tu corazón: Sí, espera á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 1, 'A TI clamaré, oh Jehová, Fortaleza mía: no te desentiendas de mí; Porque no sea yo, dejándome tú, Semejante á los que descienden al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 2, 'Oye la voz de mis ruegos cuando clamo á ti, Cuando alzo mis manos hacia el templo de tu santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 3, 'No me arrebates á una con los malos, Y con los que hacen iniquidad: Los cuales hablan paz con sus prójimos, Y la maldad está en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 4, 'Dales conforme á su obra, y conforme á la malicia de sus hechos: Dales conforme á la obra de sus manos, Dales su paga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 5, 'Porque no atendieron á las obras de Jehová, Ni al hecho de sus manos, Derribarálos, y no los edificará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 6, 'Bendito Jehová, Que oyó la voz de mis ruegos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 7, 'Jehová es mi fortaleza y mi escudo: En él esperó mi corazón, y fuí ayudado; Por lo que se gozó mi corazón, Y con mi canción le alabaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 8, 'Jehová es su fuerza, Y la fortaleza de las saludes de su ungido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 28, 9, 'Salva á tu pueblo, y bendice á tu heredad; Y pastoréalos y ensálzalos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 1, 'DAD á Jehová, oh hijos de fuertes, Dad á Jehová la gloria y la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 2, 'Dad á Jehová la gloria debida á su nombre: Humillaos á Jehová en el glorioso santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 3, 'Voz de Jehová sobre las aguas: Hizo tronar el Dios de gloria: Jehová sobre las muchas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 4, 'Voz de Jehová con potencia; Voz de Jehová con gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 5, 'Voz de Jehová que quebranta los cedros; Y quebrantó Jehová los cedros del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 6, 'E hízolos saltar como becerros; Al Líbano y al Sirión como hijos de unicornios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 7, 'Voz de Jehová que derrama llamas de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 8, 'Voz de Jehová que hará temblar el desierto; Hará temblar Jehová el desierto de Cades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 9, 'Voz de Jehová que hará estar de parto á las ciervas, Y desnudará la breñas: Y en su templo todos los suyos le dicen gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 10, 'Jehová preside en el diluvio, Y asentóse Jehová por rey para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 29, 11, 'Jehová dará fortaleza á su pueblo: Jehová bendecirá á su pueblo en paz. Salmo de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 1, 'GLORIFICARTE he, oh Jehová; porque me has ensalzado, Y no hiciste á mis enemigos alegrarse de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 2, 'Jehová Dios mío, A ti clamé, y me sanaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 3, 'Oh Jehová, hiciste subir mi alma del sepulcro; Dísteme vida, para que no descendiese á la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 4, 'Cantad á Jehová, vosotros sus santos, Y celebrad la memoria de su santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 5, 'Porque un momento será su furor; Mas en su voluntad está la vida: Por la tarde durará el lloró, Y á la mañana vendrá la alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 6, 'Y dije yo en mi prosperidad: No seré jamás conmovido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 7, 'Porque tú, Jehová, por tu benevolencia has asentado mi monte con fortaleza. Escondiste tu rostro, fuí conturbado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 8, 'A ti, oh Jehová, clamaré; Y al Señor suplicaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 9, '¿Qué provecho hay en mi muerte, cuando yo descienda al hoyo? ¿Te alabará el polvo? ¿anunciará tu verdad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 10, 'Oye, oh Jehová, y ten misericordia de mí: Jehová, sé tú mi ayudador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 11, 'Has tornado mi endecha en baile; Desataste mi saco, y ceñísteme de alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 30, 12, 'Por tanto á ti cantaré, gloria mía, y no estaré callado. Jehová Dios mío, te alabaré para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 1, 'EN ti, oh Jehová, he esperado; no sea yo confundido para siempre: Líbrame en tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 2, 'Inclina á mí tu oído, líbrame presto; Séme por roca de fortaleza, por casa fuerte para salvarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 3, 'Porque tú eres mi roca y mi castillo; Y por tu nombre me guiarás, y me encaminarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 4, 'Me sacarás de la red que han escondido para mí; Porque tú eres mi fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 5, 'En tu mano encomiendo mi espíritu: Tú me has redimido, oh Jehová, Dios de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 6, 'Aborrecí á los que esperan en vanidades ilusorias; Mas yo en Jehová he esperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 7, 'Me gozaré y alegraré en tu misericordia; Porque has visto mi aflicción; Has conocido mi alma en las angustias:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 8, 'Y no me encerraste en mano del enemigo; Hiciste estar mis pies en anchura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 9, 'Ten misericordia de mí, oh Jehová, que estoy en angustia: Hanse consumido de pesar mis ojos, mi alma, y mis entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 10, 'Porque mi vida se va gastando de dolor, y mis años de suspirar: Hase enflaquecido mi fuerza á causa de mi iniquidad, y mis huesos se han consumido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 11, 'De todos mis enemigos he sido oprobio, Y de mis vecinos en gran manera, y horror á mis conocidos: Los que me veían fuera, huían de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 12, 'He sido olvidado de su corazón como un muerto: He venido á ser como un vaso perdido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 13, 'Porque he oído afrenta de muchos; Miedo por todas partes, Cuando consultaban juntos contra mí, E ideaban quitarme la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 14, 'Mas yo en ti confié, oh Jehová: Yo dije: Dios mío eres tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 15, 'En tu mano están mis tiempos: Líbrame de la mano de mis enemigos, y de mis perseguidores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 16, 'Haz resplandecer tu rostro sobre tu siervo: Sálvame por tu misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 17, 'No sea yo confundido, oh Jehová, ya que te he invocado; Sean corridos los impíos, estén mudos en el profundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 18, 'Enmudezcan los labios mentirosos, Que hablan contra el justo cosas duras, Con soberbia y menosprecio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 19, '¡Cuán grande es tu bien, que has guardado para los que te temen, Que has obrado para los que esperan en ti, delante de los hijos de los hombres!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 20, 'Los esconderás en el secreto de tu rostro de las arrogancias del hombre: Los pondrás en un tabernáculo á cubierto de contención de lenguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 21, 'Bendito Jehová, Porque ha hecho maravillosa su misericordia para conmigo en ciudad fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 22, 'Y decía yo en mi premura: Cortado soy de delante de tus ojos: Tú empero oíste la voz de mis ruegos, cuando á ti clamaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 23, 'Amad á Jehová todos vosotros sus santos: A los fieles guarda Jehová, Y paga abundantemente al que obra con soberbia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 31, 24, 'Esforzaos todos vosotros los que esperáis en Jehová, Y tome vuestro corazón aliento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 1, 'BIENAVENTURADO aquel cuyas iniquidades son perdonadas, y borrados sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 2, 'Bienaventurado el hombre á quien no imputa Jehová la iniquidad, Y en cuyo espíritu no hay superchería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 3, 'Mientras callé, envejeciéronse mis huesos En mi gemir todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 4, 'Porque de día y de noche se agravó sobre mí tu mano; Volvióse mi verdor en sequedades de estío. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 5, 'Mi pecado te declaré, y no encubrí mi iniquidad. Confesaré, dije, contra mí mis rebeliones á Jehová; Y tú perdonaste la maldad de mi pecado. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 6, 'Por esto orará á ti todo santo en el tiempo de poder hallarte: Ciertamente en la inundación de muchas aguas no llegarán éstas á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 7, 'Tú eres mi refugio; me guardarás de angustia; Con cánticos de liberación me rodearás. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 8, 'Te haré entender, y te enseñaré el camino en que debes andar: Sobre ti fijaré mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 9, 'No seáis como el caballo, ó como el mulo, sin entendimiento: Con cabestro y con freno su boca ha de ser reprimida, Para que no lleguen á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 10, 'Muchos dolores para el impío; Mas el que espera en Jehová, lo cercará misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 32, 11, 'Alegraos en Jehová, y gozaos, justos: Y cantad todos vosotros los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 1, 'ALEGRAOS, justos, en Jehová: A los rectos es hermosa la alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 2, 'Celebrad á Jehová con arpa: Cantadle con salterio y decacordio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 3, 'Cantadle canción nueva: Hacedlo bien tañendo con júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 4, 'Porque recta es la palabra de Jehová, Y toda su obra con verdad hecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 5, 'El ama justicia y juicio: De la misericordia de Jehová está llena la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 6, 'Por la palabra de Jehová fueron hechos los cielos, Y todo el ejército de ellos por el espíritu de su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 7, 'El junta como en un montón las aguas de la mar: El pone en depósitos los abismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 8, 'Tema á Jehová toda la tierra: Teman de él todos los habitadores del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 9, 'Porque él dijo, y fué hecho; El mandó, y existió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 10, 'Jehová hace nulo el consejo de las gentes, Y frustra las maquinaciones de los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 11, 'El consejo de Jehová permanecerá para siempre; Los pensamientos de su corazón por todas las generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 12, 'Bienaventurada la gente de que Jehová es su Dios; El pueblo á quien escogió por heredad para sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 13, 'Desde los cielos miró Jehová; Vió á todos los hijos de los hombres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 14, 'Desde la morada de su asiento miró Sobre todos los moradores de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 15, 'El formó el corazón de todos ellos; El considera todas sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 16, 'El rey no es salvo con la multitud del ejército: No escapa el valiente por la mucha fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 17, 'Vanidad es el caballo para salvarse: Por la grandeza de su fuerza no librará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 18, 'He aquí, el ojo de Jehová sobre los que le temen, Sobre los que esperan en su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 19, 'Para librar sus almas de la muerte, Y para darles vida en el hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 20, 'Nuestra alma esperó á Jehová; Nuestra ayuda y nuestro escudo es él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 21, 'Por tanto en él se alegrará nuestro corazón, Porque en su santo nombre hemos confiado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 33, 22, 'Sea tu misericordia, oh Jehová, sobre nosotros, Como esperamos en ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 1, 'BENDECIRÉ á Jehová en todo tiempo; Su alabanza será siempre en mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 2, 'En Jehová se gloriará mi alma: Oiránlo los mansos, y se alegrarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 3, 'Engrandeced á Jehová conmigo, Y ensalcemos su nombre á una.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 4, 'Busqué á Jehová, y él me oyó, Y libróme de todos mis temores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 5, 'A él miraron y fueron alumbrados: Y sus rostros no se avergonzaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 6, 'Este pobre clamó, y oyóle Jehová, Y librólo de todas sus angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 7, 'El ángel de Jehová acampa en derredor de los que le temen, Y los defiende.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 8, 'Gustad, y ved que es bueno Jehová: Dichoso el hombre que confiará en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 9, 'Temed á Jehová, vosotros sus santos; Porque no hay falta para los que le temen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 10, 'Los leoncillos necesitaron, y tuvieron hambre; Pero los que buscan á Jehová, no tendrán falta de ningún bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 11, 'Venid, hijos, oidme; El temor de Jehová os enseñaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 12, '¿Quién es el hombre que desea vida, Que codicia días para ver bien?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 13, 'Guarda tu lengua de mal, Y tus labios de hablar engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 14, 'Apártate del mal, y haz el bien; Busca la paz, y síguela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 15, 'Los ojos de Jehová están sobre los justos, Y atentos sus oídos al clamor de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 16, 'La ira de Jehová contra los que mal hacen, Para cortar de la tierra la memoria de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 17, 'Clamaron los justos, y Jehová oyó, Y librólos de todas sus angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 18, 'Cercano está Jehová á los quebrantados de corazón; Y salvará á los contritos de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 19, 'Muchos son los males del justo; Mas de todos ellos lo librará Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 20, 'El guarda todos sus huesos; Ni uno de ellos será quebrantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 21, 'Matará al malo la maldad; Y los que aborrecen al justo serán asolados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 34, 22, 'Jehová redime el alma de sus siervos; Y no serán asolados cuantos en él confían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 1, 'DISPUTA, oh Jehová, con los que contra mí contienden; Pelea con los que me combaten.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 2, 'Echa mano al escudo y al pavés, Y levántate en mi ayuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 3, 'Y saca la lanza, cierra contra mis perseguidores; Di á mi alma: Yo soy tu salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 4, 'Avergüéncense y confúndanse los que buscan mi alma: Vuelvan atrás, y sean avergonzados los que mi mal intentan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 5, 'Sean como el tamo delante del viento; Y el ángel de Jehová los acose.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 6, 'Sea su camino oscuridad y resbaladeros; Y el ángel de Jehová los persiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 7, 'Porque sin causa escondieron para mí su red en un hoyo; Sin causa hicieron hoyo para mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 8, 'Véngale el quebrantamiento que no sepa, Y su red que escondió lo prenda: Con quebrantamiento en ella caiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 9, 'Y gócese mi alma en Jehová; Y alégrese en su salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 10, 'Todos mis huesos dirán: Jehová, ¿quién como tú, Que libras al afligido del más fuerte que él, Y al pobre y menesteroso del que le despoja?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 11, 'Levantáronse testigos falsos; Demandáronme lo que no sabía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 12, 'Volviéronme mal por bien, Para abatir á mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 13, 'Mas yo, cuando ellos enfermaron, me vestí de saco; Afligí con ayuno mi alma, Y mi oración se revolvía en mi seno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 14, 'Como por mi compañero, como por mi hermano andaba; Como el que trae luto por madre, enlutado me humillaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 15, 'Pero ellos se alegraron en mi adversidad, y se juntaron; Juntáronse contra mí gentes despreciables, y yo no lo entendía: Despedazábanme, y no cesaban;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 16, 'Con los lisonjeros escarnecedores truhanes, Crujiendo sobre mí sus dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 17, 'Señor, ¿hasta cuándo verás esto? Recobra mi alma de sus quebrantamientos, mi única de los leones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 18, 'Te confesaré en grande congregación; Te alabaré entre numeroso pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 19, 'No se alegren de mí mis enemigos injustos: Ni los que me aborrecen sin causa hagan del ojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 20, 'Porque no hablan paz; Y contra los mansos de la tierra piensan palabras engañosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 21, 'Y ensancharon sobre mí su boca; Dijeron: ¡Ea, ea, nuestros ojos lo han visto!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 22, 'Tú lo has visto, oh Jehová; no calles: Señor, de mí no te alejes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 23, 'Muévete y despierta para mi juicio, Para mi causa, Dios mío y Señor mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 24, 'Júzgame conforme á tu justicia, Jehová Dios mío; Y no se alegren de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 25, 'No digan en su corazón: ¡Ea, alma nuestra! No digan: ¡Hémoslo devorado!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 26, 'Avergüencense, y sean confundidos á una los que de mi mal se alegran: Vístanse de vergüenza y de confusión los que se engrandecen contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 27, 'Canten y alégrense los que están á favor de mi justa causa, Y digan siempre: Sea ensalzado Jehová, Que ama la paz de su siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 35, 28, 'Y mi lengua hablará de tu justicia, Y de tu loor todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 1, 'LA iniquidad del impío me dice al corazón: No hay temor de Dios delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 2, 'Lisonjéase, por tanto, en sus propios ojos, Hasta que su iniquidad sea hallada aborrecible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 3, 'Las palabras de su boca son iniquidad y fraude; No quiso entender para bien hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 4, 'Iniquidad piensa sobre su cama; Está en camino no bueno, El mal no aborrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 5, 'Jehová, hasta los cielos es tu misericordia; Tu verdad hasta las nubes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 6, 'Tu justicia como los montes de Dios, Tus juicios abismo grande: Oh Jehová, al hombre y al animal conservas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 7, '¡Cuán ilustre, oh Dios, es tu misericordia! Por eso los hijos de los hombres se amparan bajo la sombra de tus alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 8, 'Embriagarse han de la grosura de tu casa; Y tú los abrevarás del torrente de tus delicias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 9, 'Porque contigo está el manantial de la vida: En tu luz veremos la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 10, 'Extiende tu misericordia á los que te conocen, Y tu justicia á los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 11, 'No venga contra mí pie de soberbia; Y mano de impíos no me mueva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 36, 12, 'Allí cayeron los obradores de iniquidad; Fueron rempujados, y no pudieron levantarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 1, 'NO te impacientes á causa de los malignos, Ni tengas envidia de los que hacen iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 2, 'Porque como hierba serán presto cortados, Y decaerán como verdor de renuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 3, 'Espera en Jehová, y haz bien; Vivirás en la tierra, y en verdad serás alimentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 4, 'Pon asimismo tu delicia en Jehová, Y él te dará las peticiones de tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 5, 'Encomienda á Jehová tu camino, Y espera en él; y él hará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 6, 'Y exhibirá tu justicia como la luz, Y tus derechos como el medio día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 7, 'Calla á Jehová, y espera en él: No te alteres con motivo del que prospera en su camino, Por el hombre que hace maldades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 8, 'Déjate de la ira, y depón el enojo: No te excites en manera alguna á hacer lo malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 9, 'Porque los malignos serán talados, Mas los que esperan en Jehová, ellos heredarán la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 10, 'Pues de aquí á poco no será el malo: Y contemplarás sobre su lugar, y no parecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 11, 'Pero los mansos heredarán la tierra, Y se recrearán con abundancia de paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 12, 'Maquina el impío contra el justo, Y cruje sobre él sus dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 13, 'El Señor se reirá de él; Porque ve que viene su día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 14, 'Los impíos desenvainaron espada, y entesaron su arco, Para derribar al pobre y al menesteroso, Para matar á los de recto proceder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 15, 'La espada de ellos entrará en su mismo corazón, Y su arco será quebrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 16, 'Mejor es lo poco del justo, Que las riquezas de muchos pecadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 17, 'Porque los brazos de los impíos serán quebrados: Mas el que sostiene á los justos es Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 18, 'Conoce Jehová los días de los perfectos: Y la heredad de ellos será para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 19, 'No serán avergonzados en el mal tiempo; Y en los días de hambre serán hartos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 20, 'Mas los impíos perecerán, Y los enemigos de Jehová como la grasa de los carneros Serán consumidos: se disiparán como humo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 21, 'El impío toma prestado, y no paga; Mas el justo tiene misericordia, y da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 22, 'Porque los benditos de él heredarán la tierra; Y los malditos de él serán talados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 23, 'Por Jehová son ordenados los pasos del hombre, Y aprueba su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 24, 'Cuando cayere, no quedará postrado; Porque Jehová sostiene su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 25, 'Mozo fuí, y he envejecido, Y no he visto justo desamparado, Ni su simiente que mendigue pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 26, 'En todo tiempo tiene misericordia, y presta; Y su simiente es para bendición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 27, 'Apártate del mal, y haz el bien, Y vivirás para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 28, 'Porque Jehová ama la rectitud, Y no desampara sus santos: Mas la simiente de los impíos será extirpada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 29, 'Los justos heredarán la tierra, Y vivirán para siempre sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 30, 'La boca del justo hablara sabiduría; Y su lengua proferirá juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 31, 'La ley de su Dios está en su corazón; Por tanto sus pasos no vacilarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 32, 'Acecha el impío al justo, Y procura matarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 33, 'Jehová no lo dejará en sus manos, Ni lo condenará cuando le juzgaren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 34, 'Espera en Jehová, y guarda su camino, Y él te ensalzará para heredar la tierra: Cuando serán talados los pecadores, lo verás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 35, 'Vi yo al impío sumamente ensalzado, Y que se extendía como un laurel verde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 36, 'Empero pasóse, y he aquí no parece; Y busquélo, y no fué hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 37, 'Considera al íntegro, y mira al justo: Que la postrimería de cada uno de ellos es paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 38, 'Mas los transgresores fueron todos á una destruídos: La postrimería de los impíos fué talada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 39, 'Pero la salvación de los justos es de Jehová, Y él es su fortaleza en el tiempo de angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 37, 40, 'Y Jehová los ayudará, Y los librará: y libertarálos de los impíos, y los salvará, Por cuanto en él esperaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 1, 'JEHOVA, no me reprendas en tu furor, Ni me castigues en tu ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 2, 'Porque tus saetas descendieron á mí, Y sobre mí ha caído tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 3, 'No hay sanidad en mi carne á causa de tu ira; Ni hay paz en mis huesos á causa de mi pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 4, 'Porque mis iniquidades han pasado mi cabeza: Como carga pesada se han agravado sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 5, 'Pudriéronse, corrompiéronse mis llagas, A causa de mi locura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 6, 'Estoy encorvado, estoy humillado en gran manera, Ando enlutado todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 7, 'Porque mis lomos están llenos de irritación, Y no hay sanidad en mi carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 8, 'Estoy debilitado y molido en gran manera; Bramo á causa de la conmoción de mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 9, 'Señor, delante de ti están todos mis deseos; Y mi suspiro no te es oculto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 10, 'Mi corazón está acongojado, hame dejado mi vigor; Y aun la misma luz de mis ojos no está conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 11, 'Mis amigos y mis compañeros se quitaron de delante de mi plaga; Y mis cercanos se pusieron lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 12, 'Y los que buscaban mi alma armaron lazos; Y los que procuraban mi mal hablaban iniquidades, Y meditaban fraudes todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 13, 'Mas yo, como si fuera sordo no oía; Y estaba como un mudo, que no abre su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 14, 'Fuí pues como un hombre que no oye, Y que en su boca no tiene reprensiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 15, 'Porque á ti, oh Jehová, esperé yo: Tú responderás, Jehová Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 16, 'Porque dije: Que no se alegren de mí: Cuando mi pie resbalaba, sobre mí se engrandecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 17, 'Empero yo estoy á pique de claudicar, Y mi dolor está delante de mí continuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 18, 'Por tanto denunciaré mi maldad; Congojaréme por mi pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 19, 'Porque mis enemigos están vivos y fuertes: Y hanse aumentado los que me aborrecen sin causa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 20, 'Y pagando mal por bien Me son contrarios, por seguir yo lo bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 21, 'No me desampares, oh Jehová: Dios mío, no te alejes de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 38, 22, 'Apresúrate á ayudarme, Oh Señor, mi salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 1, 'YO DIJE: Atenderé á mis caminos, Para no pecar con mi lengua: Guardaré mi boca con freno, En tanto que el impío fuere contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 2, 'Enmudecí con silencio, calléme aun respecto de lo bueno: Y excitóse mi dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 3, 'Enardecióse mi corazón dentro de mí; Encendióse fuego en mi meditación, Y así proferí con mi lengua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 4, 'Hazme saber, Jehová, mi fin, Y cuánta sea la medida de mis días; Sepa yo cuánto tengo de ser del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 5, 'He aquí diste á mis días término corto, Y mi edad es como nada delante de ti: Ciertamente es completa vanidad todo hombre que vive. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 6, 'Ciertamente en tinieblas anda el hombre; Ciertamente en vano se inquieta: Junta, y no sabe quién lo allegará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 7, 'Y ahora, Señor, ¿qué esperaré? Mi esperanza en ti está.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 8, 'Líbrame de todas mis rebeliones; No me pongas por escarnio del insensato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 9, 'Enmudecí, no abrí mi boca; Porque tú lo hiciste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 10, 'Quita de sobre mí tu plaga; De la guerra de tu mano soy consumido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 11, 'Con castigos sobre el pecado corriges al hombre, Y haces consumirse como de polilla su grandeza: Ciertamente vanidad es todo hombre. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 12, 'Oye mi oración, oh Jehová, y escucha mi clamor: No calles á mis lágrimas; Porque peregrino soy para contigo, Y advenedizo, como todos mis padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 39, 13, 'Déjame, y tomaré fuerzas, Antes que vaya y perezca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 1, 'RESIGNADAMENTE esperé á Jehová, E inclinóse á mí, y oyó mi clamor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 2, 'E hízome sacar de un lago de miseria, del lodo cenagoso; Y puso mis pies sobre peña, y enderezó mis pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 3, 'Puso luego en mi boca canción nueva, alabanza á nuestro Dios. Verán esto muchos, y temerán, Y esperarán en Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 4, 'Bienaventurado el hombre que puso á Jehová por su confianza, Y no mira á los soberbios, ni á los que declinan á la mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 5, 'Aumentado has tú, oh Jehová Dios mío, tus maravillas; Y tus pensamientos para con nosotros, No te los podremos contar: Si yo anunciare y hablare de ellos, No pueden ser enarrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 6, 'Sacrificio y presente no te agrada; Has abierto mis oídos; Holocausto y expiación no has demandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 7, 'Entonces dije: He aquí, vengo; En el envoltorio del libro está escrito de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 8, 'El hacer tu voluntad, Dios mío, hame agradado; Y tu ley está en medio de mis entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 9, 'Anunciado he justicia en grande congregación: He aquí no detuve mis labios, Jehová, tú lo sabes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 10, 'No encubrí tu justicia dentro de mi corazón: Tu verdad y tu salvación he dicho: No oculté tu misericordia y tu verdad en grande concurso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 11, 'Tú, Jehová, no apartes de mí tus misericordias: Tu misericordia y tu verdad me guarden siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 12, 'Porque me han cercado males hasta no haber cuento: Hanme comprendido mis maldades, y no puedo levantar la vista: Hanse aumentado más que los cabellos de mi cabeza, y mi corazón me falta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 13, 'Quieras, oh Jehová, librarme; Jehová, apresúrate á socorrerme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 14, 'Sean avergonzados y confusos á una Los que buscan mi vida para cortarla: Vuelvan atrás y avergüéncense Los que mi mal desean.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 15, 'Sean asolados en pago de su afrenta Los que me dicen: ¡Ea, ea!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 16, 'Gócense y alégrense en ti todos los que te buscan; Y digan siempre los que aman tu salud: Jehová sea ensalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 40, 17, 'Aunque afligido yo y necesitado, Jehová pensará de mí: Mi ayuda y mi libertador eres tú; Dios mío, no te tardes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 1, 'BIENAVENTURADO el que piensa en el pobre: En el día malo lo librará Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 2, 'Jehová lo guardé, y le dé vida: sea bienaventurado en la tierra, Y no lo entregues á la voluntad de sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 3, 'Jehová lo sustentará sobre el lecho del dolor: Mullirás toda su cama en su enfermedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 4, 'Yo dije: Jehová, ten misericordia de mí; Sana mi alma, porque contra ti he pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 5, 'Mis enemigos dicen mal de mí preguntando: ¿Cuándo morirá, y perecerá su nombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 6, 'Y si venía á ver me, hablaba mentira: Su corazón se amontonaba iniquidad; Y salido fuera, hablába la.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 7, 'Reunidos murmuraban contra mí todos los que me aborrecían: Contra mí pensaban mal, diciendo de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 8, 'Cosa pestilencial de él se ha apoderado; Y el que cayó en cama, no volverá á levantarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 9, 'Aun el hombre de mi paz, en quien yo confiaba, el que de mi pan comía, Alzó contra mí el calcañar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 10, 'Mas tú, Jehová, ten misericordia de mí, y hazme levantar, Y daréles el pago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 11, 'En esto habré conocido que te he agradado, Que mi enemigo no se holgará de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 12, 'En cuanto á mí, en mi integridad me has sustentado, Y me has hecho estar delante de ti para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 41, 13, 'Bendito sea Jehová, el Dios de Israel, Por siglos de siglos. Amén y Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 1, 'COMO el ciervo brama por las corrientes de las aguas, Así clama por ti, oh Dios, el alma mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 2, 'Mi alma tiene sed de Dios, del Dios vivo: ¡Cuándo vendré, y pareceré delante de Dios!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 3, 'Fueron mis lágrimas mi pan de día y de noche, Mientras me dicen todos los días: ¿Dónde está tu Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 4, 'Acordaréme de estas cosas, y derramaré sobre mí mi alma: Cuando pasaré en el número, iré con ellos hasta la casa de Dios, Con voz de alegría y de alabanza, haciendo fiesta la multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 5, '¿Por qué te abates, oh alma mía, Y te conturbas en mí? Espera á Dios; porque aun le tengo de alabar Por las saludes de su presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 6, 'Dios mío, mi alma está en mí abatida: Acordaréme por tanto de ti desde tierra del Jordán, Y de los Hermonitas, desde el monte de Mizhar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 7, 'Un abismo llama á otro á la voz de tus canales: Todas tus ondas y tus olas han pasado sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 8, 'De día mandará Jehová su misericordia, Y de noche su canción será conmigo, Y oración al Dios de mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 9, 'Diré á Dios: Roca mía, ¿por qué te has olvidado de mí? ¿Por qué andaré yo enlutado por la opresión del enemigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 10, 'Mientras se están quebrantando mis huesos, mis enemigos me afrentan, Diciéndome cada día: ¿Dónde está tu Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 42, 11, '¿Por qué te abates, oh alma mía, Y por qué te conturbas en mí? Espera á Dios; porque aun le tengo de alabar; Es él salvamento delante de mí, y el Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 43, 1, 'JUZGAME, oh Dios, y aboga mi causa: Líbrame de gente impía, del hombre de engaño é iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 43, 2, 'Pues que tú eres el Dios de mi fortaleza, ¿por qué me has desechado? ¿Por qué andaré enlutado por la opresión del enemigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 43, 3, 'Envía tu luz y tu verdad: éstas me guiarán, Me conducirán al monte de tu santidad, Y á tus tabernáculos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 43, 4, 'Y entraré al altar de Dios, Al Dios alegría de mi gozo; Y alabaréte con arpa, oh Dios, Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 43, 5, '¿Por qué te abates, oh alma mía, Y por qué te conturbes en mí? Espera á Dios; porque aun le tengo de alabar; Es él salvamento delante de mí, y el Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 1, 'OH Dios, con nuestros oídos hemos oído, nuestros padres nos han contado, La obra que hiciste en sus días, en los tiempos antiguos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 2, 'Tú con tu mano echaste las gentes, y los plantaste á ellos; Afligiste los pueblos, y los arrojaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 3, 'Porque no se apoderaron de la tierra por su espada, Ni su brazo los libró; Sino tu diestra, y tu brazo, y la luz de tu rostro, Porque te complaciste en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 4, 'Tú, oh Dios, eres mi rey: Manda saludes á Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 5, 'Por medio de ti sacudiremos á nuestros enemigos: En tu nombre atropellaremos á nuestros adversarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 6, 'Porque no confiaré en mi arco, Ni mi espada me salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 7, 'Pues tú nos has guardado de nuestros enemigos, Y has avergonzado á los que nos aborrecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 8, 'En Dios nos gloriaremos todo tiempo, Y para siempre loaremos tu nombre. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 9, 'Empero nos has desechado, y nos has hecho avergonzar; Y no sales en nuestros ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 10, 'Nos hiciste retroceder del enemigo, Y saqueáron nos para sí los que nos aborrecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 11, 'Pusístenos como á ovejas para comida, Y esparcístenos entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 12, 'Has vendido tu pueblo de balde, Y no pujaste en sus precios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 13, 'Pusístenos por vergüenza á nuestros vecinos, Por escarnio y por burla á los que nos rodean.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 14, 'Pusístenos por proverbio entre las gentes, Por movimiento de cabeza en los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 15, 'Cada día mi vergüenza está delante de mí, Y cúbreme la confusión de mi rostro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 16, 'Por la voz del que me vitupera y deshonra, Por razón del enemigo y del que se venga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 17, 'Todo esto nos ha venido, y no nos hemos olvidado de ti; Y no hemos faltado á tu pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 18, 'No se ha vuelto atrás nuestro corazón, Ni tampoco se han apartado nuestros pasos de tus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 19, 'Cuando nos quebrantaste en el lugar de los dragones, Y nos cubriste con sombra de muerte,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 20, 'Si nos hubiésemos olvidado del nombre de nuestro Dios, O alzado nuestras manos á dios ajeno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 21, '¿No demandaría Dios esto? Porque él conoce los secretos del corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 22, 'Empero por tu causa nos matan cada día; Somos tenidos como ovejas para el matadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 23, 'Despierta; ¿por qué duermes, Señor? Despierta, no te alejes para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 24, '¿Por qué escondes tu rostro, Y te olvidas de nuestra aflicción, y de la opresión nuestra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 25, 'Porque nuestra alma está agobiada hasta el polvo: Nuestro vientre está pegado con la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 44, 26, 'Levántate para ayudarnos, Y redímenos por tu misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 1, 'REBOSA mi corazón palabra buena: Refiero yo al Rey mis obras: Mi lengua es pluma de escribiente muy ligero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 2, 'Haste hermoseado más que los hijos de los hombres; La gracia se derramó en tus labios: Por tanto Dios te ha bendecido para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 3, 'Cíñete tu espada sobre el muslo, oh valiente, Con tu gloria y con tu majestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 4, 'Y en tu gloria sé prosperado: Cabalga sobre palabra de verdad, y de humildad, y de justicia; Y tu diestra te enseñará cosas terribles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 5, 'Tus saetas agudas Con que caerán pueblos debajo de ti, Penetrarán en el corazón de los enemigos del Rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 6, 'Tu trono, oh Dios, eterno y para siempre: Vara de justicia la vara de tu reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 7, 'Amaste la justicia y aborreciste la maldad: Por tanto te ungió Dios, el Dios tuyo, Con óleo de gozo sobre tus compañeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 8, 'Mirra, áloe, y casia exhalan todos tus vestidos: En estancias de marfil te han recreado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 9, 'Hijas de reyes entre tus ilustres: Está la reina á tu diestra con oro de Ophir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 10, 'Oye, hija, y mira, é inclina tu oído; Y olvida tu pueblo, y la casa de tu padre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 11, 'Y deseará el rey tu hermosura: E inclínate á él, porque él es tu Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 12, 'Y las hijas de Tiro vendrán con presente; Implorarán tu favor los ricos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 13, 'Toda ilustre es de dentro la hija del rey: De brocado de oro es su vestido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 14, 'Con vestidos bordados será llevada al rey; Vírgenes en pos de ella: Sus compañeras serán traídas á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 15, 'Serán traídas con alegría y gozo: Entrarán en el palacio del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 16, 'En lugar de tus padres serán tus hijos, A quienes harás príncipes en toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 45, 17, 'Haré perpetua la memoria de tu nombre en todas las generaciones: Por lo cual te alabarán los pueblos eternamente y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 1, 'DIOS es nuestro amparo y fortaleza, Nuestro pronto auxilio en las tribulaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 2, 'Por tanto no temeremos aunque la tierra sea removida; Aunque se traspasen los montes al corazón de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 3, 'Bramarán, turbaránse sus aguas; Temblarán los montes á causa de su braveza. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 4, 'Del río sus conductos alegrarán la ciudad de Dios, El santuario de las tiendas del Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 5, 'Dios está en medio de ella; no será conmovida: Dios la ayudará al clarear la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 6, 'Bramaron las gentes, titubearon los reinos; Dió él su voz, derritióse la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 7, 'Jehová de los ejércitos es con nosotros; Nuestro refugio es el Dios de Jacob. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 8, 'Venid, ved las obras de Jehová, Que ha puesto asolamientos en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 9, 'Que hace cesar las guerras hasta los fines de la tierra: Que quiebra el arco, corta la lanza, Y quema los carros en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 10, 'Estad quietos, y conoced que yo soy Dios: Ensalzado he de ser entre las gentes, ensalzado seré en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 46, 11, 'Jehová de los ejércitos es con nosotros; Nuestro refugio es el Dios de Jacob. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 1, 'PUEBLOS todos, batid las manos; Aclamad á Dios con voz de júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 2, 'Porque Jehová el Altísimo es terrible; Rey grande sobre toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 3, 'El sujetará á los pueblos debajo de nosotros, Y á las gentes debajo de nuestros pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 4, 'El nos elegirá nuestras heredades; La hermosura de Jacob, al cual amó. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 5, 'Subió Dios con júbilo, Jehová con sonido de trompeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 6, 'Cantad á Dios, cantad: Cantad á nuestro Rey, cantad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 7, 'Porque Dios es el Rey de toda la tierra: Cantad con inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 8, 'Reinó Dios sobre las gentes: Asentóse Dios sobre su santo trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 47, 9, 'Los príncipes de los pueblos se juntaron Al pueblo del Dios de Abraham: Porque de Dios son los escudos de la tierra; El es muy ensalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 1, 'GRANDE es Jehová y digno de ser en gran manera alabado, En la ciudad de nuestro Dios, en el monte de su santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 2, 'Hermosa provincia, el gozo de toda la tierra Es el monte de Sión, á los lados del aquilón, La ciudad del gran Rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 3, 'Dios en sus palacios es conocido por refugio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 4, 'Porque he aquí los reyes de la tierra se reunieron; Pasaron todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 5, 'Y viéndola ellos así, maravilláronse, Se turbaron, diéronse priesa á huir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 6, 'Tomólos allí temblor; Dolor, como á mujer que pare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 7, 'Con viento solano Quiebras tú las naves de Tharsis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 8, 'Como lo oímos, así hemos visto En la ciudad de Jehová de los ejércitos, en la ciudad de nuestro Dios: Afirmarála Dios para siempre. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 9, 'Esperamos tu misericordia, oh Dios, En medio de tu templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 10, 'Conforme á tu nombre, oh Dios, Así es tu loor hasta los fines de la tierra: De justicia está llena tu diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 11, 'Alegraráse el monte de Sión; Se gozarán las hijas de Judá Por tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 12, 'Andad alrededor de Sión, y rodeadla: Contad sus torres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 13, 'Poned vuestro corazón á su antemuro, Mirad sus palacios; Para que lo contéis á la generación venidera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 48, 14, 'Porque este Dios es Dios nuestro eternalmente y para siempre: El nos capitaneará hasta la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 1, 'OID esto, pueblos todos; Escuchad, habitadores todos del mundo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 2, 'Así los plebeyos como los nobles, El rico y el pobre juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 3, 'Mi boca hablará sabiduría; Y el pensamiento de mi corazón inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 4, 'Acomodaré á ejemplos mi oído: Declararé con el arpa mi enigma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 5, '¿Por qué he de temer en los días de adversidad, Cuando la iniquidad de mis insidiadores me cercare?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 6, 'Los que confían en sus haciendas, Y en la muchedumbre de sus riquezas se jactan,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 7, 'Ninguno de ellos podrá en manera alguna redimir al hermano, Ni dar á Dios su rescate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 8, '(Porque la redención de su vida es de gran precio, Y no se hará jamás;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 9, 'Que viva adelante para siempre, Y nunca vea la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 10, 'Pues se ve que mueren los sabios, Así como el insensato y el necio perecen, Y dejan á otros sus riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 11, 'En su interior tienen que sus casas serán eternas, Y sus habitaciones para generación y generación: Llamaron sus tierras de sus nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 12, 'Mas el hombre no permanecerá en honra: Es semejante á las bestias que perecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 13, 'Este su camino es su locura: Con todo, corren sus descendientes por el dicho de ellos. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 14, 'Como rebaños serán puestos en la sepultura; La muerte se cebará en ellos; Y los rectos se enseñorearán de ellos por la mañana: Y se consumirá su bien parecer en el sepulcro de su morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 15, 'Empero Dios redimirá mi vida del poder de la sepultura, Cuando me tomará. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 16, 'No temas cuando se enriquece alguno, Cuando aumenta la gloria de su casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 17, 'Porque en muriendo no llevará nada, Ni descenderá tras él su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 18, 'Si bien mientras viviere, dirá dichosa á su alma: Y tú serás loado cuando bien te tratares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 19, 'Entrará á la generación de sus padres: No verán luz para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 49, 20, 'El hombre en honra que no entiende, Semejante es á las bestias que perecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 1, 'EL Dios de dioses, Jehová, ha hablado, Y convocado la tierra desde el nacimiento del sol hasta donde se pone.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 2, 'De Sión, perfección de hermosura, Ha Dios resplandecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 3, 'Vendrá nuestro Dios, y no callará: Fuego consumirá delante de él, Y en derredor suyo habrá tempestad grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 4, 'Convocará á los cielos de arriba, Y á la tierra, para juzgar á su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 5, 'Juntadme mis santos; Los que hicieron conmigo pacto con sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 6, 'Y denunciarán los cielos su justicia; Porque Dios es el juez. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 7, 'Oye, pueblo mío, y hablaré: Escucha, Israel, y testificaré contra ti: Yo soy Dios, el Dios tuyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 8, 'No te reprenderé sobre tus sacrificios, Ni por tus holocaustos, que delante de mí están siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 9, 'No tomaré de tu casa becerros, Ni machos cabríos de tus apriscos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 10, 'Porque mía es toda bestia del bosque, Y los millares de animales en los collados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 11, 'Conozco todas las aves de los montes, Y en mi poder están las fieras del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 12, 'Si yo tuviese hambre, no te lo diría á ti: Porque mío es el mundo y su plenitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 13, '¿Tengo de comer yo carne de toros, O de beber sangre de machos cabríos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 14, 'Sacrifica á Dios alabanza, Y paga tus votos al Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 15, 'E invócame en el día de la angustia: Te libraré, y tú me honrarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 16, 'Pero al malo dijo Dios: ¿Qué tienes tú que enarrar mis leyes, Y que tomar mi pacto en tu boca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 17, 'Pues que tú aborreces el castigo, Y echas á tu espalda mis palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 18, 'Si veías al ladrón, tú corrías con él; Y con los adúlteros era tu parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 19, 'Tu boca metías en mal, Y tu lengua componía engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 20, 'Tomabas asiento, y hablabas contra tu hermano: Contra el hijo de tu madre ponías infamia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 21, 'Estas cosas hiciste, y yo he callado: Pensabas que de cierto sería yo como tú: Yo te argüiré, y pondré las delante de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 22, 'Entended ahora esto, los que os olvidáis de Dios; No sea que arrebate, sin que nadie libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 50, 23, 'El que sacrifica alabanza me honrará: Y al que ordenare su camino, Le mostraré la salud de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 1, 'TEN piedad de mí, oh Dios, conforme á tu misericordia: Conforme á la multitud de tus piedades borra mis rebeliones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 2, 'Lávame más y más de mi maldad, Y límpiame de mi pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 3, 'Porque yo reconozco mis rebeliones; Y mi pecado está siempre delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 4, 'A ti, á ti solo he pecado, Y he hecho lo malo delante de tus ojos: Porque seas reconocido justo en tu palabra, Y tenido por puro en tu juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 5, 'He aquí, en maldad he sido formado, Y en pecado me concibió mi madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 6, 'He aquí, tú amas la verdad en lo íntimo: Y en lo secreto me has hecho comprender sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 7, 'Purifícame con hisopo, y será limpio: Lávame, y seré emblanquecido más que la nieve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 8, 'Hazme oir gozo y alegría; Y se recrearán los huesos que has abatido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 9, 'Esconde tu rostro de mis pecados, Y borra todas mis maldades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 10, 'Crea en mí, oh Dios, un corazón limpio; Y renueva un espíritu recto dentro de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 11, 'No me eches de delante de ti; Y no quites de mí tu santo espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 12, 'Vuélveme el gozo de tu salud; Y el espíritu libre me sustente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 13, 'Enseñaré á los prevaricadores tus caminos; Y los pecadores se convertirán á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 14, 'Líbrame de homicidios, oh Dios, Dios de mi salud: Cantará mi lengua tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 15, 'Señor, abre mis labios; Y publicará mi boca tu alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 16, 'Porque no quieres tú sacrificio, que yo daría; No quieres holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 17, 'Los sacrificios de Dios son el espíritu quebrantado: Al corazón contrito y humillado no despreciarás tú, oh Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 18, 'Haz bien con tu benevolencia á Sión: Edifica los muros de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 51, 19, 'Entonces te agradarán los sacrificios de justicia, el holocausto ú ofrenda del todo quemada: Entonces ofrecerán sobre tu altar becerros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 1, '¿POR qué te glorías de maldad, oh poderoso? La misericordia de Dios es continua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 2, 'Agravios maquina tu lengua: Como navaja amolada hace engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 3, 'Amaste el mal más que el bien; La mentira más que hablar justicia. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 4, 'Has amado toda suerte de palabras perniciosas, Engañosa lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 5, 'Por tanto Dios te derribará para siempre: Te asolará y te arrancará de tu morada, Y te desarraigará de la tierra de los vivientes. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 6, 'Y verán los justos, y temerán; Y reiránse de él, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 7, 'He aquí el hombre que no puso á Dios por su fortaleza, Sino que confió en la multitud de sus riquezas. Y se mantuvo en su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 8, 'Mas yo estoy como oliva verde en la casa de Dios: En la misericordia de Dios confío perpetua y eternalmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 52, 9, 'Te alabaré para siempre por lo que has hecho: Y esperaré en tu nombre, porque es bueno, delante de tus santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 53, 1, 'DIJO el necio en su corazón: No hay Dios. Corrompiéronse é hicieron abominable maldad: No hay quien haga bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 53, 2, 'Dios desde los cielos miró sobre los hijos de los hombres, Por ver si hay algún entendido Que busque á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 53, 3, 'Cada uno se había vuelto atrás; todos se habían corrompido: No hay quien haga bien, no hay ni aun uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 53, 4, '¿No tienen conocimiento todos esos que obran iniquidad? Que comen á mi pueblo como si comiesen pan: A Dios no han invocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 53, 5, 'Allí se sobresaltaron de pavor donde no había miedo: Porque Dios ha esparcido los huesos del que asentó campo contra ti: Los avergonzaste, porque Dios los desechó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 53, 6, '¡Oh quién diese de Sión saludes á Israel! En volviendo Dios la cautividad de su pueblo, Gozarse ha Jacob, y alegraráse Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 1, 'OH Dios, sálvame por tu nombre, Y con tu poder defiéndeme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 2, 'Oh Dios, oye mi oración; Escucha las razones de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 3, 'Porque extraños se han levantado contra mí, Y fuertes buscan mi alma: No han puesto á Dios delante de sí. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 4, 'He aquí, Dios es el que me ayuda; El Señor es con los que sostienen mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 5, 'El volverá el mal á mis enemigos: Córtalos por tu verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 6, 'Voluntariamente sacrificaré á ti; Alabaré tu nombre, oh Jehová, porque es bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 54, 7, 'Porque me ha librado de toda angustia, Y en mis enemigos vieron mis ojos mi deseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 1, 'ESCUCHA, oh Dios, mi oración, Y no te escondas de mi súplica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 2, 'Estáme atento, y respóndeme: Clamo en mi oración, y levanto el grito,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 3, 'A causa de la voz del enemigo, Por la opresión del impío; Porque echaron sobre mí iniquidad, Y con furor me han amenazado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 4, 'Mi corazón está doloroso dentro de mí, Y terrores de muerte sobre mí han caído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 5, 'Temor y temblor vinieron sobre mí, Y terror me ha cubierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 6, 'Y dije: ¡Quién me diese alas como de paloma! Volaría yo, y descansaría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 7, 'Ciertamente huiría lejos: Moraría en el desierto. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 8, 'Apresuraríame á escapar Del viento tempestuoso, de la tempestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 9, 'Deshace, oh Señor, divide la lengua de ellos; Porque he visto violencia y rencilla en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 10, 'Día y noche la rodean sobre sus muros; E iniquidad y trabajo hay en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 11, 'Agravios hay en medio de ella, Y el fraude y engaño no se apartan de sus plazas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 12, 'Porque no me afrentó un enemigo, Lo cual habría soportado; Ni se alzó contra mí el que me aborrecía, Porque me hubiera ocultado de él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 13, 'Mas tú, hombre, al parecer íntimo mío, Mi guía, y mi familiar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 14, 'Que juntos comunicábamos dulcemente los secretos, A la casa de Dios andábamos en compañía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 15, 'Condenados sean á muerte, Desciendan vivos al infierno: Porque maldades hay en su compañía, entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 16, 'Yo á Dios clamaré; Y Jehová me salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 17, 'Tarde y mañana y á medio día oraré y clamaré; Y él oirá mi voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 18, 'El ha redimido en paz mi alma de la guerra contra mí; Pues fueron contra mí muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 19, 'Dios oirá, y los quebrantará luego, El que desde la antigüedad permanece (Selah); Por cuanto no se mudan, Ni temen á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 20, 'Extendió sus manos contra sus pacíficos: Viólo su pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 21, 'Ablandan más que manteca su boca, Pero guerra hay en su corazón: Suavizan sus palabras más que el aceite, Mas ellas son cuchillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 22, 'Echa sobre Jehová tu carga, y él te sustentará; No dejará para siempre caído al justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 55, 23, 'Mas tú, oh Dios, harás descender aquéllos al pozo de la sepultura: Los hombres sanguinarios y engañadores no demediarán sus días: Empero yo confiaré en ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 1, 'TEN misericordia de mí, oh Dios, porque me devoraría el hombre: Me oprime combatiéndome cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 2, 'Apúranme mis enemigos cada día; Porque muchos son los que pelean contra mí, oh Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 3, 'En el día que temo, Yo en ti confío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 4, 'En Dios alabaré su palabra: En Dios he confiado, no temeré Lo que la carne me hiciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 5, 'Todos los días me contristan mis negocios; Contra mí son todos sus pensamientos para mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 6, 'Reúnense, escóndense, Miran ellos atentamente mis pasos, Esperando mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 7, '¿Escaparán ellos por la iniquidad? Oh Dios, derriba en tu furor los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 8, 'Mis huídas has tú contado: Pon mis lágrimas en tu redoma: ¿No están ellas en tu libro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 9, 'Serán luego vueltos atrás mis enemigos el día que yo clamare: En esto conozco que Dios es por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 10, 'En Dios alabaré su palabra; En Jehová alabaré su palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 11, 'En Dios he confiado: no temeré Lo que me hará el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 12, 'Sobre mí, oh Dios, están tus votos: Te tributaré alabanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 56, 13, 'Porque has librado mi vida de la muerte, Y mis pies de caída, Para que ande delante de Dios En la luz de los que viven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 1, 'TEN misericordia de mí, oh Dios, ten misericordia de mí; Porque en ti ha confiado mi alma, Y en la sombra de tus alas me ampararé, Hasta que pasen los quebrantos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 2, 'Clamaré al Dios Altísimo, Al Dios que me favorece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 3, 'El enviará desde los cielos, y me salvará De la infamia del que me apura; (Selah) Dios enviará su misericordia y su verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 4, 'Mi vida está entre leones; Estoy echado entre hijos de hombres encendidos: Sus dientes son lanzas y saetas, Y su lengua cuchillo agudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 5, 'Ensálzate sobre los cielos, oh Dios; Sobre toda la tierra tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 6, 'Red han armado á mis pasos; Hase abatido mi alma: Hoyo han cavado delante de mí; En medio de él han caído. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 7, 'Pronto está mi corazón, oh Dios, mi corazón está dispuesto: Cantaré, y trovaré salmos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 8, 'Despierta, oh gloria mía; despierta, salterio y arpa: Levantaréme de mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 9, 'Alabarte he en los pueblos, oh Señor; Cantaré de ti en las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 10, 'Porque grande es hasta los cielos tu misericordia, Y hasta las nubes tu verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 57, 11, 'Ensálzate sobre los cielos, oh Dios; Sobre toda la tierra tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 1, 'OH congregación, ¿pronunciáis en verdad justicia? ¿Juzgáis rectamente, hijos de los hombres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 2, 'Antes con el corazón obráis iniquidades: Hacéis pesar la violencia de vuestras manos en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 3, 'Enajenáronse los impíos desde la matriz; Descarriáronse desde el vientre, hablando mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 4, 'Veneno tienen semejante al veneno de la serpiente: Son como áspide sordo que cierra su oído;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 5, 'Que no oye la voz de los que encantan, Por más hábil que el encantador sea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 6, 'Oh Dios, quiebra sus dientes en sus bocas: Quiebra, oh Jehová, las muelas de los leoncillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 7, 'Corránse como aguas que se van de suyo: En entesando sus saetas, luego sean hechas pedazos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 8, 'Pasen ellos como el caracol que se deslíe: Como el abortivo de mujer, no vean el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 9, 'Antes que vuestras ollas sientan las espinas, Así vivos, así airados, los arrebatará él con tempestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 10, 'Alegraráse el justo cuando viere la venganza: Sus pies lavará en la sangre del impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 58, 11, 'Entonces dirá el hombre: Ciertamente hay fruto para el justo; Ciertamente hay Dios que juzga en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 1, 'LIBRAME de mis enemigos, oh Dios mío: Ponme en salvo de los que contra mí se levantan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 2, 'Líbrame de los que obran iniquidad, Y sálvame de hombres sanguinarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 3, 'Porque he aquí están acechando mi vida: Hanse juntado contra mí fuertes, No por falta mía, ni pecado mío, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 4, 'Sin delito mío corren y se aperciben: Despierta para venir á mi encuentro, y mira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 5, 'Y tú, Jehová Dios de los ejércitos, Dios de Israel, Despierta para visitar todas las gentes: No hayas misericordia de todos los que se rebelan con iniquidad. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 6, 'Volveránse á la tarde, ladrarán como perros, Y rodearán la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 7, 'He aquí proferirán con su boca; Cuchillos están en sus labios, Porque dicen: ¿Quién oye?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 8, 'Mas tú, Jehová, te reirás de ellos, Te burlarás de todas las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 9, 'De su fuerza esperaré yo en ti: Porque Dios es mi defensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 10, 'El Dios de mi misericordia me prevendrá: Dios me hará ver en mis enemigos mi deseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 11, 'No los matarás, porque mi pueblo no se olvide: Hazlos vagar con tu fortaleza, y abátelos. Oh Jehová, escudo nuestro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 12, 'Por el pecado de su boca, por la palabra de sus labios; Y sean presos por su soberbia, Y por la maldición y mentira que profieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 13, 'Acábalos con furor, acábalos, y no sean: Y sepan que Dios domina en Jacob Hasta los fines de la tierra. (Selah).');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 14, 'Vuelvan pues á la tarde, y ladren como perros, Y rodeen la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 15, 'Anden ellos errantes para hallar qué comer: Y si no se saciaren, murmuren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 16, 'Yo empero cantaré tu fortaleza, Y loaré de mañana tu misericordia: Porque has sido mi amparo Y refugio en el día de mi angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 59, 17, 'Fortaleza mía, á ti cantaré; Porque eres Dios de mi amparo, Dios de mi misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 1, 'OH Dios, tú nos has desechado, nos disipaste; Te has airado: vuélvete á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 2, 'Hiciste temblar la tierra, abrístela: Sana sus quiebras, porque titubea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 3, 'Has hecho ver á tu pueblo duras cosas: Hicístenos beber el vino de agitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 4, 'Has dado á los que te temen bandera Que alcen por la verdad. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 5, 'Para que se libren tus amados, Salva con tu diestra, y óyeme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 6, 'Dios pronunció por su santuario; yo me alegraré; Partiré á Sichêm, y mediré el valle de Succoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 7, 'Mío es Galaad, y mío es Manasés; Y Ephraim es la fortaleza de mi cabeza; Judá, mi legislador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 8, 'Moab, la vasija de mi lavatorio; Sobre Edom echaré mi zapato: Haz júbilo sobre mí, oh Palestina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 9, '¿Quién me llevará á la ciudad fortalecida? ¿Quién me llevará hasta Idumea?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 10, 'Ciertamente, tú, oh Dios, que nos habías desechado; Y no salías, oh Dios, con nuestros ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 11, 'Danos socorro contra el enemigo, Que vana es la salud de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 60, 12, 'En Dios haremos proezas; Y él hollará nuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 1, 'OYE, oh Dios, mi clamor; A mi oración atiende.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 2, 'Desde el cabo de la tierra clamaré á ti, cuando mi corazón desmayare: A la peña más alta que yo me conduzcas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 3, 'Porque tú has sido mi refugio, Y torre de fortaleza delante del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 4, 'Yo habitaré en tu tabernáculo para siempre: Estaré seguro bajo la cubierta de tus alas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 5, 'Porque tú, oh Dios, has oído mis votos, Has dado heredad á los que temen tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 6, 'Días sobre días añadirás al rey: Sus años serán como generación y generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 7, 'Estará para siempre delante de Dios: Misericordia y verdad prepara que lo conserven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 61, 8, 'Así cantaré tu nombre para siempre, Pagando mis votos cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 1, 'EN Dios solamente está callada mi alma: De él viene mi salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 2, 'El solamente es mi fuerte, y mi salud; Es mi refugio, no resbalaré mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 3, '¿Hasta cuándo maquinaréis contra un hombre? Pereceréis todos vosotros, Caeréis como pared acostada, como cerca ruinosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 4, 'Solamente consultan de arrojarle de su grandeza; Aman la mentira, Con su boca bendicen, pero maldicen en sus entrañas. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 5, 'Alma mía, en Dios solamente reposa; Porque de él es mi esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 6, 'El solamente es mi fuerte y mi salud: Es mi refugio, no resbalaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 7, 'En Dios está mi salvación y mi gloria: En Dios está la roca de mi fortaleza, y mi refugio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 8, 'Esperad en él en todo tiempo, oh pueblos; Derramad delante de él vuestro corazón: Dios es nuestro amparo. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 9, 'Por cierto, vanidad son los hijos de los hombres, mentira los hijos de varón: Pesándolos á todos igualmente en la balanza, Serán menos que la vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 10, 'No confiéis en la violencia, Ni en la rapiña; no os envanezcáis: Si se aumentare la hacienda, no pongáis el corazón en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 11, 'Una vez habló Dios; Dos veces he oído esto: Que de Dios es la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 62, 12, 'Y de ti, oh Señor, es la misericordia: Porque tú pagas á cada uno conforme á su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 1, 'DIOS, Dios mío eres tú: levantaréme á ti de mañana: Mi alma tiene sed de ti, mi carne te desea, En tierra de sequedad y transida sin aguas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 2, 'Para ver tu fortaleza y tu gloria, Así como te he mirado en el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 3, 'Porque mejor es tu misericordia que la vida: Mis labios te alabarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 4, 'Así te bendeciré en mi vida: En tu nombre alzaré mis manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 5, 'Como de meollo y de grosura será saciada mi alma; Y con labios de júbilo te alabará mi boca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 6, 'Cuando me acordaré de ti en mi lecho, Cuando meditaré de ti en las velas de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 7, 'Porque has sido mi socorro; Y así en la sombra de tus alas me regocijaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 8, 'Está mi alma apegada á ti: Tu diestra me ha sostenido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 9, 'Mas los que para destrucción buscaron mi alma, Caerán en los sitios bajos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 10, 'Destruiránlos á filo de espada; Serán porción de las zorras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 63, 11, 'Empero el rey se alegrará en Dios; Será alabado cualquiera que por él jura: Porque la boca de los que hablan mentira, será cerrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 1, 'ESCUCHA, oh Dios, mi voz en mi oración: Guarda mi vida del miedo del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 2, 'Escóndeme del secreto consejo de los malignos; De la conspiración de los que obran iniquidad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 3, 'Que amolaron su lengua como cuchillo, Y armaron por su saeta palabra amarga;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 4, 'Para asaetear á escondidas al íntegro: De improviso lo asaetean, y no temen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 5, 'Obstinados en su inicuo designio, Tratan de esconder los lazos, Y dicen: ¿Quién los ha de ver?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 6, 'Inquieren iniquidades, hacen una investigación exacta; Y el íntimo pensamiento de cada uno de ellos, así como el corazón, es profundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 7, 'Mas Dios los herirá con saeta; De repente serán sus plagas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 8, 'Y harán caer sobre sí sus mismas lenguas: Se espantarán todos los que los vieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 9, 'Y temerán todos los hombres, Y anunciarán la obra de Dios, Y entenderán su hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 64, 10, 'Alegraráse el justo en Jehová, y confiaráse en él; Y se gloriarán todos los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 1, 'A TI es plácida la alabanza en Sión, oh Dios: Y á ti se pagarán los votos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 2, 'Tú oyes la oración: A ti vendrá toda carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 3, 'Palabras de iniquidades me sobrepujaron: Mas nuestras rebeliones tú las perdonarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 4, 'Dichoso el que tú escogieres, é hicieres llegar á ti, Para que habite en tus atrios: Seremos saciados del bien de tu casa, De tu santo templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 5, 'Con tremendas cosas, en justicia, nos responderás tú, Oh Dios de nuestra salud, Esperanza de todos los términos de la tierra, Y de los más remotos confines de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 6, 'Tú, el que afirma los montes con su potencia, Ceñido de valentía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 7, 'El que amansa el estruendo de los mares, el estruendo de sus ondas, Y el alboroto de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 8, 'Por tanto los habitadores de los fines de la tierra temen de tus maravillas. Tú haces alegrar las salidas de la mañana y de la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 9, 'Visitas la tierra, y la riegas: En gran manera la enriqueces Con el río de Dios, lleno de aguas: Preparas el grano de ellos, cuando así la dispones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 10, 'Haces se empapen sus surcos, Haces descender sus canales: Ablándasla con lluvias, Bendices sus renuevos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 11, 'Tú coronas el año de tus bienes; Y tus nubes destilan grosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 12, 'Destilan sobre las estancias del desierto; Y los collados se ciñen de alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 65, 13, 'Vístense los llanos de manadas, Y los valles se cubren de grano: Dan voces de júbilo, y aun cantan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 1, 'ACLAMAD á Dios con alegría, toda la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 2, 'Cantad la gloria de su nombre: Poned gloria en su alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 3, 'Decid á Dios: ¡Cuán terribles tus obras! Por lo grande de tu fortaleza te mentirán tus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 4, 'Toda la tierra te adorará, Y cantará á ti; Cantarán á tu nombre. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 5, 'Venid, y ved las obras de Dios, Terrible en hechos sobre los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 6, 'Volvió la mar en seco; Por el río pasaron á pie; Allí en él nos alegramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 7, 'El se enseñorea con su fortaleza para siempre: Sus ojos atalayan sobre las gentes: Los rebeldes no serán ensalzados. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 8, 'Bendecid, pueblos, á nuestro Dios, Y haced oir la voz de su alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 9, 'El es el que puso nuestra alma en vida, Y no permitió que nuestros pies resbalasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 10, 'Porque tú nos probaste, oh Dios: Ensayástenos como se afina la plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 11, 'Nos metiste en la red; Pusiste apretura en nuestros lomos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 12, 'Hombres hiciste subir sobre nuestra cabeza; Entramos en fuego y en aguas, Y sacástenos á hartura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 13, 'Entraré en tu casa con holocaustos: Te pagaré mis votos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 14, 'Que pronunciaron mis labios, Y habló mi boca, cuando angustiado estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 15, 'Holocaustos de cebados te ofreceré, Con perfume de carneros: Sacrificaré bueyes y machos cabríos. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 16, 'Venid, oid todos los que teméis á Dios, Y contaré lo que ha hecho á mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 17, 'A él clamé con mi boca, Y ensalzado fué con mi lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 18, 'Si en mi corazón hubiese yo mirado á la iniquidad, El Señor no me oyera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 19, 'Mas ciertamente me oyó Dios; Antendió á la voz de mi súplica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 66, 20, 'Bendito Dios, Que no echó de sí mi oración, ni de mí su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 1, 'DIOS tenga misericordia de nosotros, y nos bendiga; Haga resplandecer su rostro sobre nosotros (Selah);');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 2, 'Para que sea conocido en la tierra tu camino, En todas las gentes tu salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 3, 'Alábente los pueblos, oh Dios; Alábente los pueblos todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 4, 'Alégrense y gocénse las gentes; Porque juzgarás los pueblos con equidad, Y pastorearás las naciones en la tierra. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 5, 'Alábente los pueblos, oh Dios: Todos los pueblos te alaben.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 6, 'La tierra dará su fruto: Nos bendecirá Dios, el Dios nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 67, 7, 'Bendíganos Dios, Y témanlo todos los fines de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 1, 'LEVANTESE Dios, sean esparcidos sus enemigos, Y huyan de su presencia los que le aborrecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 2, 'Como es lanzado el humo, los lanzarás: Como se derrite la cera delante del fuego, Así perecerán los impíos delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 3, 'Mas los justos se alegrarán: gozarse han delante de Dios, Y saltarán de alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 4, 'Cantad á Dios, cantad salmos á su nombre: Ensalzad al que sube sobre los cielos En JAH su nombre, y alegraos delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 5, 'Padre de huérfanos y defensor de viudas, Es Dios en la morada de su santuario:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 6, 'El Dios que hace habitar en familia los solos; Que saca á los aprisionados con grillos: Mas los rebeldes habitan en sequedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 7, 'Oh Dios, cuando tú saliste delante de tu pueblo, Cuando anduviste por el desierto, (Selah,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 8, 'La tierra tembló; También destilaron los cielos á la presencia de Dios: Aquel Sinaí tembló delante de Dios, del Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 9, 'Abundante lluvia esparciste, oh Dios, á tu heredad; Y cuando se cansó, tú la recreaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 10, 'Los que son de tu grey han morado en ella: Por tu bondad, oh Dios, has provisto al pobre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 11, 'El Señor daba palabra: De las evangelizantes había grande ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 12, 'Huyeron, huyeron reyes de ejércitos; Y las que se quedaban en casa partían los despojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 13, 'Bien que fuiesteis echados entre los tiestos, Seréis como las alas de la paloma cubierta de plata, Y sus plumas con amarillez de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 14, 'Cuando esparció el Omnipotente los reyes en ella, Emblanquecióse ésta como la nieve en Salmón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 15, 'Monte de Dios es el monte de Basán; Monte alto el de Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 16, '¿Por qué os levantáis, oh montes altos? Este monte amó Dios para su asiento; Ciertamente Jehová habitará en él para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 17, 'Los carros de Dios son veinte mil, y más millares de ángeles. El Señor entre ellos, como en Sinaí, así en el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 18, 'Subiste á lo alto, cautivaste la cautividad, Tomaste dones para los hombres, Y también para los rebeldes, para que habite entre ellos JAH Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 19, 'Bendito el Señor; cada día nos colma de beneficios El Dios de nuestra salud. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 20, 'Dios, nuestro Dios ha de salvarnos; Y de Dios Jehová es el librar de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 21, 'Ciertamente Dios herirá la cabeza de sus enemigos, La cabelluda mollera del que camina en sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 22, 'El Señor dijo: De Basán haré volver, Te haré volver de los profundos de la mar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 23, 'Porque tu pie se enrojecerá de sangre de tus enemigos, Y de ella la lengua de tus perros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 24, 'Vieron tus caminos, oh Dios; Los caminos de mi Dios, de mi Rey, en el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 25, 'Los cantores iban delante, los tañedores detrás; En medio, las doncellas, con adufes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 26, 'Bendecid á Dios en congregaciones: Al Señor, vosotros de la estirpe de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 27, 'Allí estaba el joven Benjamín señoreador de ellos, Los príncipes de Judá en su congregación, Los príncipes de Zabulón, los príncipes de Nephtalí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 28, 'Tu Dios ha ordenado tu fuerza; Confirma, oh Dios, lo que has obrado en nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 29, 'Por razón de tu templo en Jerusalem Los reyes te ofrecerán dones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 30, 'Reprime la reunión de gentes armadas, La multitud de toros con los becerros de los pueblos, Hasta que todos se sometan con sus piezas de plata: Disipa los pueblos que se complacen en la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 31, 'Vendrán príncipes de Egipto; Etiopía apresurará sus manos á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 32, 'Reinos de la tierra, cantad á Dios, Cantad al Señor (Selah);');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 33, 'Al que cabalga sobre los cielos de los cielos que son de antiguo: He aquí á su voz dará voz de fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 34, 'Atribuid fortaleza á Dios: Sobre Israel es su magnificencia, Y su poder está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 68, 35, 'Terrible eres, oh Dios, desde tus santuarios: El Dios de Israel, él da fortaleza y vigor á su pueblo. Bendito Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 1, 'SALVAME, oh Dios, Porque las aguas han entrado hasta el alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 2, 'Estoy hundido en cieno profundo, donde no hay pie: He venido á abismos de aguas, y la corriente me ha anegado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 3, 'Cansado estoy de llamar; mi garganta se ha enronquecido; Han desfallecido mis ojos esperando á mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 4, 'Hanse aumentado más que los cabellos de mi cabeza los que me aborrecen sin causa; Hanse fortalecido mis enemigos, los que me destruyen sin por qué: He venido pues á pagar lo que no he tomado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 5, 'Dios, tú sabes mi locura; Y mis delitos no te son ocultos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 6, 'No sean avergonzados por mi causa los que te esperan, oh Señor Jehová de los ejércitos; No sean confusos por mí los que te buscan, oh Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 7, 'Porque por amor de ti he sufrido afrenta; Confusión ha cubierto mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 8, 'He sido extrañado de mis hermanos, Y extraño á los hijos de mi madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 9, 'Porque me consumió el celo de tu casa; Y los denuestos de los que te vituperaban, cayeron sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 10, 'Y lloré afligiendo con ayuno mi alma; Y esto me ha sido por afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 11, 'Puse además saco por mi vestido; Y vine á serles por proverbio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 12, 'Hablaban contra mí los que se sentaban á la puerta, Y me zaherían en las canciones de los bebederos de sidra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 13, 'Empero yo enderezaba mi oración á ti, oh Jehová, al tiempo de tu buena voluntad: Oh Dios, por la multitud de tu misericordia, Por la verdad de tu salud, óyeme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 14, 'Sácame del lodo, y no sea yo sumergido: Sea yo libertado de los que me aborrecen, y del profundo de las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 15, 'No me anegue el ímpetu de las aguas, Ni me suerba la hondura, Ni el pozo cierre sobre mí su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 16, 'Oyeme, Jehová, porque apacible es tu misericordia; Mírame conforme á la multitud de tus miseraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 17, 'Y no escondas tu rostro de tu siervo; Porque estoy angustiado; apresúrate, óyeme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 18, 'Acércate á mi alma, redímela: Líbrame á causa de mis enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 19, 'Tú sabes mi afrenta, y mi confusión, y mi oprobio: Delante de ti están todos mis enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 20, 'La afrenta ha quebrantado mi corazón, y estoy acongojado: Y esperé quien se compadeciese de mí, y no lo hubo: Y consoladores, y ninguno hallé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 21, 'Pusiéronme además hiel por comida, Y en mi sed me dieron á beber vinagre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 22, 'Sea su mesa delante de ellos por lazo, Y lo que es para bien por tropiezo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 23, 'Sean oscurecidos sus ojos para ver, Y haz siempre titubear sus lomos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 24, 'Derrama sobre ellos tu ira, Y el furor de tu enojo los alcance.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 25, 'Sea su palacio asolado: En sus tiendas no haya morador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 26, 'Porque persiguieron al que tú heriste; Y cuentan del dolor de los que tú llagaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 27, 'Pon maldad sobre su maldad, Y no entren en tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 28, 'Sean raídos del libro de los vivientes, Y no sean escritos con los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 29, 'Y yo afligido y dolorido, Tu salud, oh Dios, me defenderá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 30, 'Alabaré yo el nombre de Dios con cántico, Ensalzarélo con alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 31, 'Y agradará á Jehová más que sacrificio de buey, O becerro que echa cuernos y uñas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 32, 'Veránlo los humildes, y se gozarán; Buscad á Dios, y vivirá vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 33, 'Porque Jehová oye á los menesterosos, Y no menosprecia á sus prisioneros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 34, 'Alábenlo los cielos y la tierra, Los mares, y todo lo que se mueve en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 35, 'Porque Dios guardará á Sión, y reedificará las ciudades de Judá; Y habitarán allí, y la poseerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 69, 36, 'Y la simiente de sus siervos la heredará, Y los que aman su nombre habitarán en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 70, 1, 'OH Dios, acude á librarme; Apresúrate, oh Dios, á socorrerme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 70, 2, 'Sean avergonzados y confusos Los que buscan mi vida; Sean vueltos atrás y avergonzados Los que mi mal desean.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 70, 3, 'Sean vueltos, en pago de su afrenta hecha, Los que dicen: ¡Ah! ¡ah!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 70, 4, 'Gócense y alégrense en ti todos los que te buscan; Y digan siempre los que aman tu salud: Engrandecido sea Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 70, 5, 'Yo estoy afligido y menesteroso; Apresúrate á mí, oh Dios: Ayuda mía y mi libertador eres tú; Oh Jehová, no te detengas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 1, 'EN ti, oh Jehová, he esperado; No sea yo confuso para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 2, 'Hazme escapar, y líbrame en tu justicia: Inclina tu oído y sálvame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 3, 'Séme por peña de estancia, adonde recurra yo continuamente: Mandado has que yo sea salvo; Porque tú eres mi roca, y mi fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 4, 'Dios mío, líbrame de la mano del impío, De la mano del perverso y violento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 5, 'Porque tú, oh Señor Jehová, eres mi esperanza: Seguridad mía desde mi juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 6, 'Por ti he sido sustentado desde el vientre: De las entrañas de mi madre tú fuiste el que me sacaste: De ti será siempre mi alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 7, 'Como prodigio he sido á muchos; Y tú mi refugio fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 8, 'Sea llena mi boca de tu alabanza, De tu gloria todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 9, 'No me deseches en el tiempo de la vejez; Cuando mi fuerza se acabare, no me desampares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 10, 'Porque mis enemigos han tratado de mí; Y los que acechan mi alma, consultaron juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 11, 'Diciendo: Dios lo ha dejado: Perseguid y tomadle, porque no hay quien le libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 12, 'Oh Dios, no te alejes de mí: Dios mío, acude presto á mi socorro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 13, 'Sean avergonzados, fallezcan los adversarios de mi alma; Sean cubiertos de vergüenza y de confusión los que mi mal buscan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 14, 'Mas yo siempre esperaré, Y añadiré sobre toda tu alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 15, 'Mi boca publicará tu justicia Y tu salud todo el día, Aunque no sé el número de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 16, 'Vendré á las valentías del Señor Jehová: Haré memoria de sola tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 17, 'Oh Dios, enseñásteme desde mi mocedad; Y hasta ahora he manifestado tus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 18, 'Y aun hasta la vejez y las canas; oh Dios, no me desampares, Hasta que denuncie tu brazo á la posteridad, Tus valentías á todos los que han de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 19, 'Y tu justicia, oh Dios, hasta lo excelso; Porque has hecho grandes cosas: Oh Dios, ¿quién como tú?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 20, 'Tú, que me has hecho ver muchas angustias y males, Volverás á darme vida, Y de nuevo me levantarás de los abismos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 21, 'Aumentarás mi grandeza, Y volverás á consolarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 22, 'Asimismo yo te alabaré con instrumento de salterio, Oh Dios mío: tu verdad cantaré yo á ti en el arpa, Oh Santo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 23, 'Mis labios cantarán cuando á ti salmeare, Y mi alma, á la cual redimiste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 71, 24, 'Mi lengua hablará también de tu justicia todo el día: Por cuanto fueron avergonzados, porque fueron confusos los que mi mal procuraban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 1, 'OH Dios, da tus juicios al rey, Y tu justicia al hijo del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 2, 'El juzgará tu pueblo con justicia, Y tus afligidos con juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 3, 'Los montes llevarán paz al pueblo, Y los collados justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 4, 'Juzgará los afligidos del pueblo, Salvará los hijos del menesteroso, Y quebrantará al violento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 5, 'Temerte han mientras duren el sol Y la luna, por generación de generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 6, 'Descenderá como la lluvia sobre la hierba cortada; Como el rocío que destila sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 7, 'Florecerá en sus día justicia, Y muchedumbre de paz, hasta que no haya luna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 8, 'Y dominará de mar á mar, Y desde el río hasta los cabos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 9, 'Delante de él se postrarán los Etiopes; Y sus enemigos lamerán la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 10, 'Los reyes de Tharsis y de las islas traerán presentes: Los reyes de Sheba y de Seba ofrecerán dones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 11, 'Y arrodillarse han á él todos los reyes; Le servirán todas las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 12, 'Porque él librará al menesteroso que clamare, Y al afligido que no tuviere quien le socorra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 13, 'Tendrá misericordia del pobre y del menesteroso, Y salvará las almas de los pobres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 14, 'De engaño y de violencia redimirá sus almas: Y la sangre de ellos será preciosa en sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 15, 'Y vivirá, y darásele del oro de Seba; Y oraráse por él continuamente; Todo el día se le bendecirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 16, 'Será echado un puño de grano en tierra, en las cumbres de los montes; Su fruto hará ruido como el Líbano, Y los de la ciudad florecerán como la hierba de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 17, 'Será su nombre para siempre, Perpetuaráse su nombre mientras el sol dure: Y benditas serán en él todas las gentes: Llamarlo han bienaventurado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 18, 'Bendito Jehová Dios, el Dios de Israel, Que solo hace maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 19, 'Y bendito su nombre glorioso para siempre: Y toda la tierra sea llena de su gloria. Amén y Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 72, 20, 'Acábanse las oraciones de David, hijo de Isaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 1, 'CIERTAMENTE bueno es Dios á Israel, A los limpios de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 2, 'Mas yo, casi se deslizaron mis pies; Por poco resbalaron mis pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 3, 'Porque tuve envidia de los insensatos, Viendo la prosperidad de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 4, 'Porque no hay ataduras para su muerte; Antes su fortaleza está entera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 5, 'No están ellos en el trabajo humano; Ni son azotados con los otros hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 6, 'Por tanto soberbia los corona: Cúbrense de vestido de violencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 7, 'Sus ojos están salidos de gruesos: Logran con creces los antojos del corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 8, 'Soltáronse, y hablan con maldad de hacer violencia; Hablan con altanería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 9, 'Ponen en el cielo su boca, Y su lengua pasea la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 10, 'Por eso su pueblo vuelve aquí, Y aguas de lleno le son exprimidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 11, 'Y dicen: ¿Cómo sabe Dios? ¿Y hay conocimiento en lo alto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 12, 'He aquí estos impíos, Sin ser turbados del mundo, alcanzaron riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 13, 'Verdaderamente en vano he limpiado mi corazón, Y lavado mis manos en inocencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 14, 'Pues he sido azotado todo el día, Y empezaba mi castigo por las mañanas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 15, 'Si dijera yo, Discurriré de esa suerte; He aquí habría negado la nación de tus hijos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 16, 'Pensaré pues para saber esto: Es á mis ojos duro trabajo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 17, 'Hasta que venido al santuario de Dios, Entenderé la postrimería de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 18, 'Ciertamente los has puesto en deslizaderos; En asolamientos los harás caer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 19, '¡Cómo han sido asolados! ¡cuán en un punto! Acabáronse, fenecieron con turbaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 20, 'Como sueño del que despierta, Así, Señor, cuando despertares, menospreciarás sus apariencias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 21, 'Desazonóse á la verdad mi corazón, Y en mis riñones sentía punzadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 22, 'Mas yo era ignorante, y no entendía: Era como una bestia acerca de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 23, 'Con todo, yo siempre estuve contigo: Trabaste de mi mano derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 24, 'Hasme guiado según tu consejo, Y después me recibirás en gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 25, '¿A quién tengo yo en los cielos? Y fuera de ti nada deseo en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 26, 'Mi carne y mi corazón desfallecen: Mas la roca de mi corazón y mi porción es Dios para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 27, 'Porque he aquí, los que se alejan de ti perecerán: Tú cortarás á todo aquel que fornicando, de ti se aparta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 73, 28, 'Y en cuanto á mí, el acercarme á Dios es el bien: He puesto en el Señor Jehová mi esperanza, Para contar todas tus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 1, '¿POR qué, oh Dios, nos has desechado para siempre? ¿Por qué ha humeado tu furor contra las ovejas de tu dehesa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 2, 'Acuérdate de tu congregación, que adquiriste de antiguo, Cuando redimiste la vara de tu heredad; Este monte de Sión, donde has habitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 3, 'Levanta tus pies á los asolamientos eternos: A todo enemigo que ha hecho mal en el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 4, 'Tus enemigos han bramado en medio de tus sinagogas: Han puesto sus divisas por señas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 5, 'Cualquiera se hacía famoso según que había levantado El hacha sobre los gruesos maderos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 6, 'Y ahora con hachas y martillos Han quebrado todas sus entalladuras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 7, 'Han puesto á fuego tus santuarios, Han profanado el tabernáculo de tu nombre echándolo á tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 8, 'Dijeron en su corazón: Destruyámoslos de una vez; Han quemado todas las sinagogas de Dios en el tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 9, 'No vemos ya nuestras señales: No hay más profeta; Ni con nosotros hay quien sepa hasta cuándo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 10, '¿Hasta cuándo, oh Dios, el angustiador nos afrentará? ¿Ha de blasfemar el enemigo perpetuamente tu nombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 11, '¿Por qué retraes tu mano, y tu diestra? ¿Por qué la escondes dentro de tu seno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 12, 'Empero Dios es mi rey ya de antiguo; El que obra saludes en medio de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 13, 'Tú hendiste la mar con tu fortaleza: Quebrantaste cabezas de ballenas en las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 14, 'Tú magullaste las cabezas del leviathán; Dístelo por comida al pueblo de los desiertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 15, 'Tú abriste fuente y río; Tú secaste ríos impetuosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 16, 'Tuyo es el día, tuya también es la noche: Tú aparejaste la luna y el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 17, 'Tú estableciste todos los términos de la tierra: El verano y el invierno tú los formaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 18, 'Acuerdáte de esto: que el enemigo ha dicho afrentas á Jehová, Y que el pueblo insensato ha blasfemado tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 19, 'No entregues á las bestias el alma de tu tórtola: Y no olvides para siempre la congregación de tus afligidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 20, 'Mira al pacto: Porque las tenebrosidades de la tierra llenas están de habitaciones de violencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 21, 'No vuelva avergonzado el abatido: El afligido y el menesteroso alabarán tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 22, 'Levántate, oh Dios, aboga tu causa: Acuérdate de cómo el insensato te injuria cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 74, 23, 'No olvides las voces de tus enemigos: El alboroto de los que se levantan contra ti sube continuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 1, 'ALABARÉMOSTE, oh Dios, alabaremos; Que cercano está tu nombre: Cuenten tus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 2, 'Cuando yo tuviere tiempo, Yo juzgaré rectamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 3, 'Arruinábase la tierra y sus moradores: Yo sostengo sus columnas. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 4, 'Dije á los insensatos: No os infatuéis; Y á los impíos: No levantéis el cuerno:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 5, 'No levantéis en alto vuestro cuerno; No habléis con cerviz erguida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 6, 'Porque ni de oriente, ni de occidente, Ni del desierto viene el ensalzamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 7, 'Mas Dios es el juez: A éste abate, y á aquel ensalza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 8, 'Porque el cáliz está en la mano de Jehová, y el vino es tinto, Lleno de mistura; y él derrama del mismo: Ciertamente sus heces chuparán y beberán todos los impíos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 9, 'Mas yo anunciaré siempre, Cantaré alabanzas al Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 75, 10, 'Y quebraré todos los cuernos de los pecadores: Los cuernos del justo serán ensalzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 1, 'DIOS es conocido en Judá: En Israel es grande su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 2, 'Y en Salem está su tabernáculo, Y su habitación en Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 3, 'Allí quebró las saetas del arco, El escudo, y la espada, y tren de guerra. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 4, 'Ilustre eres tú; fuerte, más que los montes de caza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 5, 'Los fuertes de corazón fueron despojados, durmieron su sueño; Y nada hallaron en sus manos todos los varones fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 6, 'A tu reprensión, oh Dios de Jacob, El carro y el caballo fueron entorpecidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 7, 'Tú, terrible eres tú: ¿Y quién parará delante de ti, en comenzando tu ira?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 8, 'Desde los cielos hiciste oir juicio; La tierra tuvo temor y quedó suspensa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 9, 'Cuando te levantaste, oh Dios, al juicio, Para salvar á todos los mansos de la tierra. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 10, 'Ciertamente la ira del hombre te acarreará alabanza: Tú reprimirás el resto de las iras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 11, 'Prometed, y pagad á Jehová vuestro Dios: Todos los que están alrededor de él, traigan presentes al Terrible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 76, 12, 'Cortará él el espíritu de los príncipes: Terrible es á los reyes de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 1, 'CON mi voz clamé á Dios, A Dios clamé, y él me escuchará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 2, 'Al Señor busqué en el día de mi angustia: Mi mal corría de noche y no cesaba: Mi alma rehusaba consuelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 3, 'Acordábame de Dios, y gritaba: Quejábame, y desmayaba mi espíritu. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 4, 'Tenías los párpados de mis ojos: Estaba yo quebrantado, y no hablaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 5, 'Consideraba los días desde el principio, Los años de los siglos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 6, 'Acordábame de mis canciones de noche; Meditaba con mi corazón, Y mi espíritu inquiría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 7, '¿Desechará el Señor para siempre, Y no volverá más á amar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 8, '¿Hase acabado para siempre su misericordia? ¿Hase acabado la palabra suya para generación y generación?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 9, '¿Ha olvidado Dios el tener misericordia? ¿Ha encerrado con ira sus piedades? (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 10, 'Y dije: Enfermedad mía es esta; Traeré pues á la memoria los años de la diestra del Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 11, 'Acordaréme de las obras de JAH: Sí, haré yo memoria de tus maravillas antiguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 12, 'Y meditaré en todas tus obras, Y hablaré de tus hechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 13, 'Oh Dios, en santidad es tu camino: ¿Qué Dios grande como el Dios nuestro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 14, 'Tú eres el Dios que hace maravillas: Tú hiciste notoria en los pueblos tu fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 15, 'Con tu brazo redimiste á tu pueblo, A los hijos de Jacob y de José. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 16, 'Viéronte las aguas, oh Dios; Viéronte las aguas, temieron; Y temblaron los abismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 17, 'Las nubes echaron inundaciones de aguas; Tronaron los cielos, Y discurrieron tus rayos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 18, 'Anduvo en derredor el sonido de tus truenos; Los relámpagos alumbraron el mundo; Estremecióse y tembló la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 19, 'En la mar fué tu camino, Y tus sendas en las muchas aguas; Y tus pisadas no fueron conocidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 77, 20, 'Condujiste á tu pueblo como ovejas, Por mano de Moisés y de Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 1, 'ESCUCHA, pueblo mío, mi ley: Inclinad vuestro oído á las palabras de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 2, 'Abriré mi boca en parábola; Hablaré cosas reservadas de antiguo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 3, 'Las cuales hemos oído y entendido; Que nuestros padres nos las contaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 4, 'No las encubriremos á sus hijos, Contando á la generación venidera las alabanzas de Jehová, Y su fortaleza, y sus maravillas que hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 5, 'El estableció testimonio en Jacob, Y pusó ley en Israel; La cual mandó á nuestros padres Que la notificasen á sus hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 6, 'Para que lo sepa la generación venidera, y los hijos que nacerán; Y los que se levantarán, lo cuenten á sus hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 7, 'A fin de que pongan en Dios su confianza, Y no se olviden de las obras de Dios, Y guarden sus mandamientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 8, 'Y no sean como sus padres, Generación contumaz y rebelde; Generación que no apercibió su corazón, Ni fué fiel para con Dios su espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 9, 'Los hijos de Ephraim armados, flecheros, Volvieron las espaldas el día de la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 10, 'No guardaron el pacto de Dios, Ni quisieron andar en su ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 11, 'Antes se olvidaron de sus obras, Y de sus maravillas que les había mostrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 12, 'Delante de sus padres hizo maravillas En la tierra de Egipto, en el campo de Zoán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 13, 'Rompió la mar, é hízolos pasar; E hizo estar las aguas como en un montón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 14, 'Y llevólos de día con nube, Y toda la noche con resplandor de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 15, 'Hendió las peñas en el desierto: Y dióles á beber como de grandes abismos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 16, 'Pues sacó de la peña corrientes, E hizo descender aguas como ríos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 17, 'Empero aun tornaron á pecar contra él, Enojando en la soledad al Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 18, 'Pues tentaron á Dios en su corazón, Pidiendo comida á su gusto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 19, 'Y hablaron contra Dios, Diciendo: ¿Podrá poner mesa en el desierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 20, 'He aquí ha herido la peña, y corrieron aguas, Y arroyos salieron ondeando: ¿Podrá también dar pan? ¿Aparejará carne á su pueblo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 21, 'Por tanto oyó Jehová, é indignóse: Y encendióse el fuego contra Jacob, Y el furor subió también contra Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 22, 'Por cuanto no habían creído á Dios, Ni habían confiado en su salud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 23, 'A pesar de que mandó á las nubes de arriba, Y abrió las puertas de los cielos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 24, 'E hizo llover sobre ellos maná para comer, Y dióles trigo de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 25, 'Pan de nobles comió el hombre: Envióles comida á hartura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 26, 'Movió el solano en el cielo, Y trajo con su fortaleza el austro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 27, 'E hizo llover sobre ellos carne como polvo, Y aves de alas como arena de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 28, 'E hízolas caer en medio de su campo, Alrededor de sus tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 29, 'Y comieron, y hartáronse mucho: Cumplióles pues su deseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 30, 'No habían quitado de sí su deseo, Aun estaba su vianda en su boca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 31, 'Cuando vino sobre ellos el furor de Dios, Y mató los más robustos de ellos, Y derribo los escogidos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 32, 'Con todo esto pecaron aún, Y no dieron crédito á sus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 33, 'Consumió por tanto en nada sus días, Y sus años en la tribulación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 34, 'Si los mataba, entonces buscaban á Dios; Entonces se volvían solícitos en busca suya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 35, 'Y acordábanse que Dios era su refugio. Y el Dios Alto su redentor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 36, 'Mas le lisonjeaban con su boca, Y con su lengua le mentían:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 37, 'Pues sus corazones no eran rectos con él, Ni estuvieron firmes en su pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 38, 'Empero él misericordioso, perdonaba la maldad, y no los destruía: Y abundó para apartar su ira, Y no despertó todo su enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 39, 'Y acordóse que eran carne; Soplo que va y no vuelve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 40, '¡Cuántas veces lo ensañaron en el desierto, Lo enojaron en la soledad!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 41, 'Y volvían, y tentaban á Dios, Y ponían límite al Santo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 42, 'No se acordaron de su mano, Del día que los redimió de angustia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 43, 'Cuando puso en Egipto sus señales, Y sus maravillas en el campo de Zoán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 44, 'Y volvió sus ríos en sangre, Y sus corrientes, porque no bebiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 45, 'Envió entre ellos una mistura de moscas que los comían, Y ranas que los destruyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 46, 'Dió también al pulgón sus frutos, Y sus trabajos á la langosta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 47, 'Sus viñas destruyó con granizo, Y sus higuerales con piedra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 48, 'Y entregó al pedrisco sus bestias, Y al fuego sus ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 49, 'Envió sobre ellos el furor de su saña, Ira y enojo y angustia, Con misión de malos ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 50, 'Dispuso el camino á su furor; No eximió la vida de ellos de la muerte, Sino que entregó su vida á la mortandad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 51, 'E hirió á todo primogénito en Egipto, Las primicias de las fuerzas en las tiendas de Châm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 52, 'Empero hizo salir á su pueblo como ovejas, Y llevólos por el desierto, como un rebaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 53, 'Y guiólos con seguridad, que no tuvieron miedo; Y la mar cubrió á sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 54, 'Metiólos después en los términos de su santuario, En este monte que ganó su mano derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 55, 'Y echó las gentes de delante de ellos, Y repartióles una herencia con cuerdas; E hizo habitar en sus moradas á las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 56, 'Mas tentaron y enojaron al Dios Altísimo, Y no guardaron sus testimonios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 57, 'Sino que se volvieron, y se rebelaron como sus padres: Volviéronse como arco engañoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 58, 'Y enojáronlo con sus altos, Y provocáronlo á celo con sus esculturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 59, 'Oyólo Dios, y enojóse, Y en gran manera aborreció á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 60, 'Dejó por tanto el tabernáculo de Silo, La tienda en que habitó entre los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 61, 'Y dió en cautividad su fortaleza, Y su gloria en mano del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 62, 'Entregó también su pueblo á cuchillo, Y airóse contra su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 63, 'El fuego devoró sus mancebos, Y sus vírgenes no fueron loadas en cantos nupciales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 64, 'Sus sacerdotes cayeron á cuchillo, Y sus viudas no lamentaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 65, 'Entonces despertó el Señor á la manera del que ha dormido, Como un valiente que grita excitado del vino:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 66, 'E hirió á sus enemigos en las partes posteriores: Dióles perpetua afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 67, 'Y desechó el tabernáculo de José, Y no escogió la tribu de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 68, 'Sino que escogió la tribu de Judá, El monte de Sión, al cual amó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 69, 'Y edificó su santuario á manera de eminencia, Como la tierra que cimentó para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 70, 'Y eligió á David su siervo, Y tomólo de las majadas de las ovejas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 71, 'De tras las paridas lo trajo, Para que apacentase á Jacob su pueblo, y á Israel su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 78, 72, 'Y apacentólos con entereza de su corazón; Y pastoreólos con la pericia de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 1, 'OH Dios, vinieron las gentes á tu heredad; El templo de tu santidad han contaminado; Pusieron á Jerusalem en montones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 2, 'Dieron los cuerpos de tus siervos por comida á las aves de los cielos; La carne de tus santos á las bestias de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 3, 'Derramaron su sangre como agua en los alrededores de Jerusalem; Y no hubo quien los enterrase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 4, 'Somos afrentados de nuestros vecinos, Escarnecidos y burlados de los que están en nuestros alrededores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 5, '¿Hasta cuándo, oh Jehová? ¿has de estar airado para siempre? ¿Arderá como fuego tu celo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 6, 'Derrama tu ira sobre las gentes que no te conocen, Y sobre los reinos que no invocan tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 7, 'Porque han consumido á Jacob, Y su morada han asolado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 8, 'No recuerdes contra nosotros las iniquidades antiguas: Anticípennos presto tus misericordias, Porque estamos muy abatidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 9, 'Ayúdanos, oh Dios, salud nuestra, por la gloria de tu nombre: Y líbranos, y aplácate sobre nuestros pecados por amor de tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 10, 'Porque dirán las gentes: ¿Dónde está su Dios? Sea notoria en las gentes, delante de nuestros ojos, La venganza de la sangre de tus siervos, que fué derramada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 11, 'Entre ante tu acatamiento el gemido de los presos: Conforme á la grandeza de tu brazo preserva á los sentenciados á muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 12, 'Y torna á nuestros vecinos en su seno siete tantos De su infamia, con que te han deshonrado, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 79, 13, 'Y nosotros, pueblo tuyo, y ovejas de tu dehesa, Te alabaremos para siempre: Por generación y generación cantaremos tus alabanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 1, 'OH Pastor de Israel, escucha: Tú que pastoreas como á ovejas á José, Que estás entre querubines, resplandece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 2, 'Despierta tu valentía delante de Ephraim, y de Benjamín, y de Manasés, Y ven á salvarnos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 3, 'Oh Dios, haznos tornar; Y haz resplandecer tu rostro, y seremos salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 4, 'Jehová, Dios de los ejércitos, ¿Hasta cuándo humearás tú contra la oración de tu pueblo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 5, 'Dísteles á comer pan de lágrimas, Y dísteles á beber lágrimas en gran abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 6, 'Pusístenos por contienda á nuestros vecinos: Y nuestros enemigos se burlan entre sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 7, 'Oh Dios de los ejércitos, haznos tornar; Y haz resplandecer tu rostro, y seremos salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 8, 'Hiciste venir una vid de Egipto: Echaste las gentes, y plantástela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 9, 'Limpiaste sitio delante de ella, E hiciste arraigar sus raíces, y llenó la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 10, 'Los montes fueron cubiertos de su sombra; Y sus sarmientos como cedros de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 11, 'Extendió sus vástagos hasta la mar, Y hasta el río sus mugrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 12, '¿Por qué aportillaste sus vallados, Y la vendimian todos los que pasan por el camino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 13, 'Estropeóla el puerco montés, Y pacióla la bestia del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 14, 'Oh Dios de los ejércitos, vuelve ahora: Mira desde el cielo, y considera, y visita esta viña,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 15, 'Y la planta que plantó tu diestra, Y el renuevo que para ti corroboraste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 16, 'Quemada á fuego está, asolada: Perezcan por la reprensión de tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 17, 'Sea tu mano sobre el varón de tu diestra, Sobre el hijo del hombre que para ti corroboraste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 18, 'Así no nos volveremos de ti: Vida nos darás, é invocaremos tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 80, 19, 'Oh Jehová, Dios de los ejércitos, haznos tornar; Haz resplandecer tu rostro, y seremos salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 1, 'CANTAD á Dios, fortaleza nuestra: Al Dios de Jacob celebrad con júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 2, 'Tomad la canción, y tañed el adufe, El arpa deliciosa con el salterio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 3, 'Tocad la trompeta en la nueva luna, En el día señalado, en el día de nuestra solemnidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 4, 'Porque estatuto es de Israel, Ordenanza del Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 5, 'Por testimonio en José lo ha constituído, Cuando salió por la tierra de Egipto; Donde oí lenguaje que no entendía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 6, 'Aparté su hombro de debajo de la carga; Sus manos se quitaron de vasijas de barro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 7, 'En la calamidad clamaste, y yo te libré: Te respondí en el secreto del trueno; Te probé sobre las aguas de Meriba. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 8, 'Oye, pueblo mío y te protestaré. Israel, si me oyeres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 9, 'No habrá en ti dios ajeno, Ni te encorvarás á dios extraño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 10, 'Yo soy Jehová tu Dios, Que te hice subir de la tierra de Egipto: Ensancha tu boca, y henchirla he.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 11, 'Mas mi pueblo no oyó mi voz, E Israel no me quiso á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 12, 'Dejélos por tanto á la dureza de su corazón: Caminaron en sus consejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 13, '¡Oh, si me hubiera oído mi pueblo, Si en mis caminos hubiera Israel andado!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 14, 'En una nada habría yo derribado sus enemigos, Y vuelto mi mano sobre sus adversarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 15, 'Los aborrecedores de Jehová se le hubieran sometido; Y el tiempo de ellos fuera para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 81, 16, 'Y Dios lo hubiera mantenido de grosura de trigo: Y de miel de la piedra te hubiera saciado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 1, 'DIOS está en la reunión de los dioses; En medio de los dioses juzga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 2, '¿Hasta cuándo juzgaréis injustamente, Y aceptaréis las personas de los impíos? (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 3, 'Defended al pobre y al huérfano: Haced justicia al afligido y al menesteroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 4, 'Librad al afligido y al necesitado: Libradlo de mano de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 5, 'No saben, no entienden, Andan en tinieblas: Vacilan todos los cimientos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 6, 'Yo dije: Vosotros sois dioses. E hijos todos vosotros del Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 7, 'Empero como hombres moriréis. Y caeréis como cualquiera de los tiranos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 82, 8, 'Levántate, oh Dios, juzga la tierra: Porque tú heredarás en todas las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 1, 'OH Dios no tengas silencio: No calles, oh Dios, ni te estés quieto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 2, 'Porque he aquí que braman tus enemigos; Y tus aborrecedores han alzado cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 3, 'Sobre tu pueblo han consultado astuta y secretamente, Y han entrado en consejo contra tus escondidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 4, 'Han dicho: Venid, y cortémoslos de ser pueblo, Y no haya más memoria del nombre de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 5, 'Por esto han conspirado de corazón á una, Contra ti han hecho liga;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 6, 'Los pabellones de los Idumeos y de los Ismaelitas, Moab y los Agarenos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 7, 'Gebal, y Ammón, y Amalec; Los Filisteos con los habitadores de Tiro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 8, 'También el Assur se ha juntado con ellos: Son por brazo á los hijos de Lot. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 9, 'Hazles como á Madián; Como á Sísara, como á Jabín en el arroyo de Cisón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 10, 'Que perecieron en Endor, Fueron hechos muladar de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 11, 'Pon á ellos y á sus capitanes como á Oreb y como á Zeeb; Y como á Zeba y como á Zalmunna, á todos sus príncipes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 12, 'Que han dicho: Heredemos para nosotros Las moradas de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 13, 'Dios mío, ponlos como á torbellinos; Como á hojarascas delante del viento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 14, 'Como fuego que quema el monte, Como llama que abrasa las breñas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 15, 'Persíguelos así con tu tempestad, Y asómbralos con tu torbellino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 16, 'Llena sus rostros de vergüenza; Y busquen tu nombre, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 17, 'Sean afrentados y turbados para siempre; Y sean deshonrados, y perezcan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 83, 18, 'Y conozcan que tu nombre es JEHOVA; Tú solo Altísimo sobre toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 1, '¡CUAN amables son tus moradas, oh Jehová de los ejércitos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 2, 'Codicia y aun ardientemente desea mi alma los atrios de Jehová: Mi corazón y mi carne cantan al Dios vivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 3, 'Aun el gorrión halla casa, Y la golondrina nido para sí, donde ponga sus pollos En tus altares, oh Jehová de los ejércitos, Rey mío, y Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 4, 'Bienaventurados los que habitan en tu casa: Perpetuamente te alabarán (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 5, 'Bienaventurado el hombre que tiene su fortaleza en ti; En cuyo corazón están tus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 6, 'Atravesando el valle de Baca pónenle por fuente, Cuando la lluvia llena los estanques.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 7, 'Irán de fortaleza en fortaleza, Verán á Dios en Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 8, 'Jehová Dios de los ejércitos, oye mi oración: Escucha, oh Dios de Jacob (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 9, 'Mira, oh Dios, escudo nuestro, Y pon los ojos en el rostro de tu ungido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 10, 'Porque mejor es un día en tus atrios que mil fuera de ellos: Escogería antes estar á la puerta de la casa de mi Dios, Que habitar en las moradas de maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 11, 'Porque sol y escudo es Jehová Dios: Gracia y gloria dará Jehová: No quitará el bien á los que en integridad andan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 84, 12, 'Jehová de los ejércitos, Dichoso el hombre que en ti confía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 1, 'FUISTE propicio á tu tierra, oh Jehová: Volviste la cautividad de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 2, 'Perdonaste la iniquidad de tu pueblo; Todos los pecados de ellos cubriste. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 3, 'Dejaste toda tu saña: Te volviste de la ira de tu furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 4, 'Vuélvenos, oh Dios, salud nuestra, Y haz cesar tu ira de sobre nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 5, '¿Estarás enojado contra nosotros para siempre? ¿Extenderás tu ira de generación en generación?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 6, '¿No volverás tú á darnos vida, Y tu pueblo se alegrará en ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 7, 'Muéstranos, oh Jehová, tu misericordia, Y danos tu salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 8, 'Escucharé lo que hablará el Dios Jehová: Porque hablará paz á su pueblo y á sus santos, Para que no se conviertan á la locura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 9, 'Ciertamente cercana está su salud á los que le temen; Para que habite la gloria en nuestra tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 10, 'La misericordia y la verdad se encontraron: La justicia y la paz se besaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 11, 'La verdad brotará de la tierra; Y la justicia mirará desde los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 12, 'Jehová dará también el bien; Y nuestra tierra dará su fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 85, 13, 'La justicia irá delante de él; Y sus pasos pondrá en camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 1, 'INCLINA, oh Jehová, tu oído, y óyeme; Porque estoy afligido y menesteroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 2, 'Guarda mi alma, porque soy pío: Salva tú, oh Dios mío, á tu siervo que en ti confía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 3, 'Ten misericordia de mí, oh Jehová: Porque á ti clamo todo el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 4, 'Alegra el alma de tu siervo: Porque á ti, oh Señor, levanto mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 5, 'Porque tú, Señor, eres bueno y perdonador, Y grande en misericordia para con todos los que te invocan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 6, 'Escucha, oh Jehová, mi oración, Y está atento á la voz de mis ruegos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 7, 'En el día de mi angustia te llamaré: Porque tú me respondes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 8, 'Oh Señor, ninguno hay como tú entre los dioses, Ni obras que igualen tus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 9, 'Todas las gentes que hiciste vendrán y se humillarán delante de ti, Señor; Y glorificarán tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 10, 'Porque tú eres grande, y hacedor de maravillas: Tú solo eres Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 11, 'Enséñame, oh Jehová, tu camino; caminaré yo en tu verdad: Consolida mi corazón para que tema tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 12, 'Te alabaré, oh Jehová Dios mío, con todo mi corazón; Y glorificaré tu nombre para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 13, 'Porque tu misericordia es grande para conmigo; Y has librado mi alma del hoyo profundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 14, 'Oh Dios, soberbios se levantaron contra mí, Y conspiración de fuertes ha buscado mi alma, Y no te pusieron delante de sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 15, 'Mas tú, Señor, Dios misericordioso y clemente, Lento para la ira, y grande en misericordia y verdad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 16, 'Mírame, y ten misericordia de mí: Da tu fortaleza á tu siervo, Y guarda al hijo de tu sierva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 86, 17, 'Haz conmigo señal para bien, Y veánla los que me aborrecen, y sean avergonzados; Porque tú, Jehová, me ayudaste, y me consolaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 1, 'SU cimiento es en montes de santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 2, 'Ama Jehová las puertas de Sión Más que todas las moradas de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 3, 'Cosas ilustres son dichas de ti, Ciudad de Dios. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 4, 'Yo me acordaré de Rahab y de Babilonia entre los que me conocen: He aquí Palestina, y Tiro, con Etiopía: Este nació allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 5, 'Y de Sión se dirá: Este y aquél han nacido en ella; Y fortificarála el mismo Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 6, 'Jehová contará cuando se escribieren los pueblos: Este nació allí. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 87, 7, 'Y cantores y tañedores en ella dirán: Todas mis fuentes estarán en ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 1, 'OH Jehová, Dios de mi salud, Día y noche clamo delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 2, 'Entre mi oración en tu presencia: Inclina tu oído á mi clamor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 3, 'Porque mi alma está harta de males, Y mi vida cercana al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 4, 'Soy contado con los que descienden al hoyo, Soy como hombre sin fuerza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 5, 'Libre entre los muertos, Como los matados que yacen en el sepulcro, Que no te acuerdas más de ellos, Y que son cortados de tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 6, 'Hasme puesto en el hoyo profundo, En tinieblas, en honduras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 7, 'Sobre mí se ha acostado tu ira, Y me has afligido con todas tus ondas. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 8, 'Has alejado de mí mis conocidos: Hasme puesto por abominación á ellos: Encerrado estoy, y no puedo salir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 9, 'Mis ojos enfermaron á causa de mi aflicción: Hete llamado, oh Jehová, cada día; He extendido á ti mis manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 10, '¿Harás tú milagro á los muertos? ¿Levantaránse los muertos para alabarte? (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 11, '¿Será contada en el sepulcro tu misericordia, O tu verdad en la perdición?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 12, '¿Será conocida en las tinieblas tu maravilla, Ni tu justicia en la tierra del olvido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 13, 'Mas yo á ti he clamado, oh Jehová; Y de mañana mi oración te previno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 14, '¿Por qué, oh Jehová, desechas mi alma? ¿Por qué escondes de mí tu rostro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 15, 'Yo soy afligido y menesteroso: Desde la mocedad he llevado tus terrores, he estado medroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 16, 'Sobre mí han pasado tus iras; Tus espantos me han cortado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 17, 'Hanme rodeado como aguas de continuo; Hanme cercado á una.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 88, 18, 'Has alejado de mí el enemigo y el compañero; Y mis conocidos se esconden en la tiniebla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 1, 'LAS misericordias de Jehová cantaré perpetuamente; En generación y generación haré notoria tu verdad con mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 2, 'Porque dije: Para siempre será edificada misericordia; En los mismos cielos apoyarás tu verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 3, 'Hice alianza con mi escogido; Juré á David mi siervo: diciendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 4, 'Para siempre confirmaré tu simiente, Y edificaré tu trono por todas las generaciones. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 5, 'Y celebrarán los cielos tu maravilla, oh Jehová; Tu verdad también en la congregación de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 6, 'Porque ¿quién en los cielos se igualará con Jehová? ¿Quién será semejante á Jehová entre los hijos de los potentados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 7, 'Dios terrible en la grande congregación de los santos, Y formidable sobre todos cuantos están alrededor suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 8, 'Oh Jehová, Dios de los ejércitos, ¿Quién como tú? Poderoso eres, Jehová, Y tu verdad está en torno de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 9, 'Tú tienes dominio sobre la bravura de la mar: Cuando se levantan sus ondas, tú las sosiegas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 10, 'Tú quebrantaste á Rahab como á un muerto: Con el brazo de tu fortaleza esparciste á tus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 11, 'Tuyos los cielos, tuya también la tierra: El mundo y su plenitud, tú lo fundaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 12, 'Al aquilón y al austro tú los criaste: Tabor y Hermón cantarán en tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 13, 'Tuyo el brazo con valentía; Fuerte es tu mano, ensalzada tu diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 14, 'Justicia y juicio son el asiento de tu trono: Misericordia y verdad van delante de tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 15, 'Bienaventurado el pueblo que sabe aclamarte: Andarán, oh Jehová, á la luz de tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 16, 'En tu nombre se alegrarán todo el día; Y en tu justicia serán ensalzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 17, 'Porque tú eres la gloria de su fortaleza; Y por tu buena voluntad ensalzarás nuestro cuerno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 18, 'Porque Jehová es nuestro escudo; Y nuestro rey es el Santo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 19, 'Entonces hablaste en visión �� tu santo, Y dijiste: Yo he puesto el socorro sobre valiente; He ensalzado un escogido de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 20, 'Hallé á David mi siervo; Ungílo con el aceite de mi santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 21, 'Mi mano será firme con él, Mi brazo también lo fortificará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 22, 'No lo avasallará enemigo, Ni hijo de iniquidad lo quebrantará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 23, 'Mas yo quebrantaré delante de él á sus enemigos, Y heriré á sus aborrecedores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 24, 'Y mi verdad y mi misericordia serán con él; Y en mi nombre será ensalzado su cuerno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 25, 'Asimismo pondré su mano en la mar, Y en los ríos su diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 26, 'El me llamará: Mi padre eres tú, Mi Dios, y la roca de mi salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 27, 'Yo también le pondré por primogénito, Alto sobre los reyes de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 28, 'Para siempre le conservaré mi misericordia; Y mi alianza será firme con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 29, 'Y pondré su simiente para siempre, Y su trono como los días de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 30, 'Si dejaren sus hijos mi ley, Y no anduvieren en mis juicios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 31, 'Si profanaren mis estatutos, Y no guardaren mis mandamientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 32, 'Entonces visitaré con vara su rebelión, Y con azotes sus iniquidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 33, 'Mas no quitaré de él mi misericordia, Ni falsearé mi verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 34, 'No olvidaré mi pacto, Ni mudaré lo que ha salido de mis labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 35, 'Una vez he jurado por mi santidad, Que no mentiré á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 36, 'Su simiente será para siempre, Y su trono como el sol delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 37, 'Como la luna será firme para siempre, Y como un testigo fiel en el cielo. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 38, 'Mas tú desechaste y menospreciaste á tu ungido; Y te has airado con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 39, 'Rompiste el pacto de tu siervo; Has profanado su corona hasta la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 40, 'Aportillaste todos sus vallados; Has quebrantado sus fortalezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 41, 'Menoscabáronle todos los que pasaron por el camino: Es oprobio á sus vecinos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 42, 'Has ensalzado la diestra de sus enemigos; Has alegrado á todos sus adversarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 43, 'Embotaste asimismo el filo de su espada, Y no lo levantaste en la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 44, 'Hiciste cesar su brillo, Y echaste su trono por tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 45, 'Has acortado los días de su juventud; Hasle cubierto de afrenta. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 46, '¿Hasta cuándo, oh Jehová? ¿te esconderás para siempre? ¿Arderá tu ira como el fuego?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 47, 'Acuérdate de cuán corto sea mi tiempo: ¿Por qué habrás criado en vano á todos los hijos del hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 48, '¿Qué hombre vivirá y no verá muerte? ¿Librarás su vida del poder del sepulcro? (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 49, 'Señor, ¿dónde están tus antiguas misericordias, Que juraste á David por tu verdad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 50, 'Señor, acuérdate del oprobio de tus siervos; Oprobio que llevo yo en mi seno de muchos pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 51, 'Porque tus enemigos, oh Jehová, han deshonrado, Porque tus enemigos han deshonrado los pasos de tu ungido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 89, 52, 'Bendito Jehová para siempre. Amén, y Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 1, 'SEñOR, tú nos has sido refugio En generación y en generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 2, 'Antes que naciesen los montes Y formases la tierra y el mundo, Y desde el siglo y hasta el siglo, tú eres Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 3, 'Vuelves al hombre hasta ser quebrantado, Y dices: Convertíos, hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 4, 'Porque mil años delante de tus ojos, Son como el día de ayer, que pasó, Y como una de las vigilias de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 5, 'Háceslos pasar como avenida de aguas; son como sueño; Como la hierba que crece en la mañana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 6, 'En la mañana florece y crece; A la tarde es cortada, y se seca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 7, 'Porque con tu furor somos consumidos, Y con tu ira somos conturbados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 8, 'Pusiste nuestras maldades delante de ti, Nuestros yerros á la luz de tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 9, 'Porque todos nuestros días declinan á causa de tu ira; Acabamos nuestros años como un pensamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 10, 'Los días de nuestra edad son setenta años; Que si en los más robustos son ochenta años, Con todo su fortaleza es molestia y trabajo; Porque es cortado presto, y volamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 11, '¿Quién conoce la fortaleza de tu ira, Y tu indignación según que debes ser temido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 12, 'Enséñanos de tal modo á contar nuestros días, Que traigamos al corazón sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 13, 'Vuélvete, oh Jehová: ¿hasta cuándo? Y aplácate para con tus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 14, 'Sácianos presto de tu misericordia: Y cantaremos y nos alegraremos todos nuestros días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 15, 'Alégranos conforme á los días que nos afligiste, Y los años que vimos mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 16, 'Aparezca en tus siervos tu obra, Y tu gloria sobre sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 90, 17, 'Y sea la luz de Jehová nuestro Dios sobre nosotros: Y ordena en nosotros la obra de nuestras manos, La obra de nuestras manos confirma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 1, 'EL que habita al abrigo del Altísimo, Morará bajo la sombra del Omnipotente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 2, 'Diré yo á Jehová: Esperanza mía, y castillo mío; Mi Dios, en él confiaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 3, 'Y él te librará del lazo del cazador: De la peste destruidora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 4, 'Con sus plumas te cubrirá, Y debajo de sus alas estarás seguro: Escudo y adarga es su verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 5, 'No tendrás temor de espanto nocturno, Ni de saeta que vuele de día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 6, 'Ni de pestilencia que ande en oscuridad, Ni de mortandad que en medio del día destruya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 7, 'Caerán á tu lado mil, Y diez mil á tu diestra: Mas á ti no llegará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 8, 'Ciertamente con tus ojos mirarás, Y verás la recompensa de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 9, 'Porque tú has puesto á Jehová, que es mi esperanza. Al Altísimo por tu habitación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 10, 'No te sobrevendrá mal, Ni plaga tocará tu morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 11, 'Pues que á sus ángeles mandará acerca de ti, Que te guarden en todos tus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 12, 'En las manos te llevarán, Porque tu pie no tropiece en piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 13, 'Sobre el león y el basilisco pisarás; Hollarás al cachorro del león y al dragón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 14, 'Por cuanto en mí ha puesto su voluntad, yo también lo libraré: Pondrélo en alto, por cuanto ha conocido mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 15, 'Me invocará, y yo le responderé: Con él estare yo en la angustia: Lo libraré, y le glorificaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 91, 16, 'Saciarélo de larga vida, Y mostraréle mi salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 1, 'BUENO es alabar á Jehová, Y cantar salmos á tu nombre, oh Altísimo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 2, 'Anunciar por la mañana tu misericordia, Y tu verdad en las noches,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 3, 'En el decacordio y en el salterio, En tono suave con el arpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 4, 'Por cuanto me has alegrado, oh Jehová, con tus obras; En las obras de tus manos me gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 5, '¡Cuán grandes son tus obras, oh Jehová! Muy profundos son tus pensamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 6, 'El hombre necio no sabe, Y el insensato no entiende esto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 7, 'Que brotan los impíos como la hierba, Y florecen todos los que obran iniquidad, Para ser destruídos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 8, 'Mas tú, Jehová, para siempre eres Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 9, 'Porque he aquí tus enemigos, oh Jehová, Porque he aquí, perecerán tus enemigos; Serán disipados todos los que obran maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 10, 'Empero tú ensalzarás mi cuerno como el de unicornio: Seré ungido con aceite fresco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 11, 'Y mirarán mis ojos sobre mis enemigos: Oirán mis oídos de los que se levantaron contra mí, de los malignos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 12, 'El justo florecerá como la palma: Crecerá como cedro en el Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 13, 'Plantados en la casa de Jehová, En los atrios de nuestro Dios florecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 14, 'Aun en la vejez fructificarán; Estarán vigorosos y verdes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 92, 15, 'Para anunciar que Jehová mi fortaleza es recto. Y que en él no hay injusticia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 93, 1, 'JEHOVA reina, vistióse de magnificencia, Vistióse Jehová, ciñose de fortaleza; Afirmó también el mundo, que no se moverá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 93, 2, 'Firme es tu trono desde entonces: Tú eres eternalmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 93, 3, 'Alzaron los ríos, oh Jehová, Alzaron los ríos su sonido; Alzaron los ríos sus ondas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 93, 4, 'Jehová en las alturas es más poderoso Que el estruendo de las muchas aguas, Más que las recias ondas de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 93, 5, 'Tus testimonios son muy firmes: La santidad conviene á tu casa, Oh Jehová, por los siglos y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 1, 'JEHOVA, Dios de las venganzas, Dios de las venganzas, muéstrate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 2, 'Ensálzate, oh Juez de la tierra: Da el pago á los soberbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 3, '¿Hasta cuándo los impíos, Hasta cuándo, oh Jehová, se gozarán los impíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 4, '¿Hasta cuándo pronunciarán, hablarán cosas duras, Y se vanagloriarán todos los que obran iniquidad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 5, 'A tu pueblo, oh Jehová, quebrantan, Y á tu heredad afligen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 6, 'A la viuda y al extanjero matan, Y á los huérfanos quitan la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 7, 'Y dijeron: No verá JAH, Ni entenderá el Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 8, 'Entended, necios del pueblo; Y vosotros fatuos, ¿cuándo seréis sabios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 9, 'El que plantó el oído, ¿no oirá? El que formó el ojo, ¿no verá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 10, 'El que castiga las gentes, ¿no reprenderá? ¿No sabrá el que enseña al hombre la ciencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 11, 'Jehová conoce los pensamientos de los hombres, Que son vanidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 12, 'Bienaventurado el hombre á quien tú, JAH, castigares, Y en tu ley lo instruyeres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 13, 'Para tranquilizarle en los días de aflicción, En tanto que para el impío se cava el hoyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 14, 'Porque no dejará Jehová su pueblo, Ni desamparará su heredad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 15, 'Sino que el juicio será vuelto á justicia, Y en pos de ella irán todos los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 16, '¿Quién se levantará por mí contra los malignos? ¿Quién estará por mí contra los que obran iniquidad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 17, 'Si no me ayudara Jehová, Presto morara mi alma en el silencio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 18, 'Cuando yo decía: Mi pie resbala: Tu misericordia, oh Jehová, me sustentaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 19, 'En la multitud de mis pensamientos dentro de mí, Tus consolaciones alegraban mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 20, '¿Juntaráse contigo el trono de iniquidades, Que forma agravio en el mandamiento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 21, 'Pónense en corros contra la vida del justo, Y condenan la sangre inocente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 22, 'Mas Jehová me ha sido por refugio; Y mi Dios por roca de mi confianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 94, 23, 'Y él hará tornar sobre ellos su iniquidad, Y los destruirá por su propia maldad; Los talará Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 1, 'VENID, celebremos alegremente á Jehová: Cantemos con júbilo á la roca de nuestra salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 2, 'Lleguemos ante su acatamiento con alabanza; Aclamémosle con cánticos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 3, 'Porque Jehová es Dios grande; Y Rey grande sobre todos los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 4, 'Porque en su mano están las profundidades de la tierra, Y las alturas de los montes son suyas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 5, 'Suya también la mar, pues él la hizo; Y sus manos formaron la seca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 6, 'Venid, adoremos y postrémonos; Arrodillémonos delante de Jehová nuestro hacedor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 7, 'Porque él es nuestro Dios; Nosotros el pueblo de su dehesa, y ovejas de su mano. Si hoy oyereis su voz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 8, 'No endurezcáis vuestro corazón como en Meriba, Como el día de Masa en el desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 9, 'Donde me tentaron vuestros padres, Probáronme, y vieron mi obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 10, 'Cuarenta años estuve disgustado con la nación, Y dije: Pueblo es que divaga de corazón, Y no han conocido mis caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 95, 11, 'Por tanto juré en mi furor Que no entrarían en mi reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 1, 'CANTAD á Jehová canción nueva; Cantad á Jehová, toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 2, 'Cantad á Jehová, bendecid su nombre: Anunciad de día en día su salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 3, 'Contad entre las gentes su gloria, En todos los pueblos sus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 4, 'Porque grande es Jehová, y digno de suprema alabanza; Terrible sobre todos los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 5, 'Porque todos los dioses de los pueblos son ídolos: Mas Jehová hizo los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 6, 'Alabanza y magnificencia delante de él: Fortaleza y gloria en su santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 7, 'Dad á Jehová, oh familias de los pueblos, Dad á Jehová la gloria y la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 8, 'Dad á Jehová la honra debida á su nombre: Tomad presentes, y venid á sus atrios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 9, 'Encorvaos á Jehová en la hermosura de su santuario: Temed delante de él, toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 10, 'Decid en las gentes: Jehová reinó, También afirmó el mundo, no será conmovido: Juzgará á los pueblos en justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 11, 'Alégrense los cielos, y gócese la tierra: Brame la mar y su plenitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 12, 'Regocíjese el campo, y todo lo que en él está: Entonces todos los árboles del bosque rebosarán de contento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 96, 13, 'Delante de Jehová que vino: Porque vino á juzgar la tierra. Juzgará al mundo con justicia, Y á los pueblos con su verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 1, 'JEHOVA reinó: regocíjese la tierra: Alégrense las muchas islas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 2, 'Nube y oscuridad alrededor de él: Justicia y juicio son el asiento de su trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 3, 'Fuego irá delante de él, Y abrasará en derredor sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 4, 'Sus relámpagos alumbraron el mundo: La tierra vió, y estremecióse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 5, 'Los montes se derritieron como cera delante de Jehová, Delante del Señor de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 6, 'Los cielos denunciaron su justicia, Y todos los pueblos vieron su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 7, 'Avergüéncense todos los que sirven á las imágenes de talla, Los que se alaban de los ídolos: Los dioses todos á él se encorven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 8, 'Oyó Sión, y alegróse; Y las hijas de Judá, Oh Jehová, se gozaron por tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 9, 'Porque tú, Jehová, eres alto sobre toda la tierra: Eres muy ensalzado sobre todos los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 10, 'Los que á Jehová amáis, aborreced el mal: Guarda él las almas de sus santos; De mano de los impíos los libra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 11, 'Luz está sembrada para el justo, Y alegría para los rectos de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 97, 12, 'Alegraos, justos, en Jehová: Y alabad la memoria de su santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 1, 'CANTAD á Jehová canción nueva; Porque ha hecho maravillas: Su diestra lo ha salvado, y su santo brazo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 2, 'Jehová ha hecho notoria su salud: En ojos de las gentes ha descubierto su justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 3, 'Hase acordado de su misericordia y de su verdad para con la casa de Israel: Todos los términos de la tierra han visto la salud de nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 4, 'Cantad alegres á Jehová, toda la tierra; Levantad la voz, y aplaudid, y salmead.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 5, 'Salmead á Jehová con arpa; Con arpa y voz de cántico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 6, 'Aclamad con trompetas y sonidos De bocina delante del rey Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 7, 'Brame la mar y su plenitud; El mundo y los que en él habitan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 8, 'Los ríos batan las manos; Los montes todos hagan regocijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 98, 9, 'Delante de Jehová; porque vino á juzgar la tierra: Juzgará al mundo con justicia, Y á los pueblos con rectitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 1, 'JEHOVA reinó, temblarán los pueblos: El está sentado sobre los querubines, conmoveráse la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 2, 'Jehová en Sión es grande, Y ensalzado sobre todos los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 3, 'Alaben tu nombre grande y tremendo: El es santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 4, 'Y la gloria del rey ama el juicio: Tú confirmas la rectitud; Tú has hecho en Jacob juicio y justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 5, 'Ensalzad á Jehová nuestro Dios, Y encorvaos al estrado de sus pies: El es santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 6, 'Moisés y Aarón entre sus sacerdotes, Y Samuel entre los que invocaron su nombre; Invocaban á Jehová, y él les respondía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 7, 'En columna de nube hablaba con ellos: Guardaban sus testimonios, y el estatuto que les había dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 8, 'Jehová Dios nuestro, tú les respondías: Tú les fuiste un Dios perdonador, Y vengador de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 99, 9, 'Ensalzad á Jehová nuestro Dios, Y encorvaos al monte de su santidad; Porque Jehová nuestro Dios es santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 100, 1, 'CANTAD alegres á Dios, habitantes de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 100, 2, 'Servid á Jehová con alegría: Venid ante su acatamiento con regocijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 100, 3, 'Reconoced que Jehová él es Dios: El nos hizo, y no nosotros á nosotros mismos. Pueblo suyo somos, y ovejas de su prado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 100, 4, 'Entrad por sus puertas con reconocimiento, Por sus atrios con alabanza: Alabadle, bendecid su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 100, 5, 'Porque Jehová es bueno: para siempre es su misericordia, Y su verdad por todas las generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 1, 'MISERICORDIA y juicio cantaré: A ti cantaré yo, oh Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 2, 'Entenderé en el camino de la perfección Cuando vinieres á mí: En integridad de mi corazón andaré en medio de mi casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 3, 'No pondré delante de mis ojos cosa injusta: Aborrezco la obra de los que se desvían: Ninguno de ellos se allegará á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 4, 'Corazón perverso se apartará de mí; No conoceré al malvado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 5, 'Al que solapadamente infama á su prójimo, yo le cortaré; No sufriré al de ojos altaneros, y de corazón vanidoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 6, 'Mis ojos pondré en los fieles de la tierra, para que estén conmigo: El que anduviere en el camino de la perfección, éste me sevirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 7, 'No habitará dentro de mi casa el que hace fraude: El que habla mentiras no se afirmará delante de mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 101, 8, 'Por las mañanas cortaré á todos los impíos de la tierra; Para extirpar de la ciudad de Jehová á todos los que obraren iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 1, 'JEHOVA, oye mi oración, Y venga mi clamor á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 2, 'No escondas de mí tu rostro: en el día de mi angustia Inclina á mí tu oído; El día que te invocare, apresúrate á responderme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 3, 'Porque mis días se han consumido como humo; Y mis huesos cual tizón están quemados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 4, 'Mi corazón fué herido, y secóse como la hierba; Por lo cual me olvidé de comer mi pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 5, 'Por la voz de mi gemido Mis huesos se han pegado á mi carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 6, 'Soy semejante al pelícano del desierto; Soy como el buho de las soledades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 7, 'Velo, y soy Como el pájaro solitario sobre el tejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 8, 'Cada día me afrentan mis enemigos; Los que se enfurecen contra mí, hanse contra mí conjurado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 9, 'Por lo que como la ceniza á manera de pan, Y mi bebida mezclo con lloro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 10, 'A causa de tu enojo y de tu ira; Pues me alzaste, y me has arrojado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 11, 'Mis días son como la sombra que se va; Y heme secado como la hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 12, 'Mas tú, Jehová, permanecerás para siempre, Y tu memoria para generación y generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 13, 'Tú levantándote, tendrás misericordia de Sión; Porque el tiempo de tener misericordia de ella, porque el plazo es llegado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 14, 'Porque tus siervos aman sus piedras, Y del polvo de ella tienen compasión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 15, 'Entonces temerán las gentes el nombre de Jehová, Y todos los reyes de la tierra tu gloria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 16, 'Por cuanto Jehová habrá edificado á Sión, Y en su gloria será visto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 17, 'Habrá mirado á la oración de los solitarios, Y no habrá desechado el ruego de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 18, 'Escribirse ha esto para la generación venidera: Y el pueblo que se criará, alabará á JAH.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 19, 'Porque miró de lo alto de su santuario; Jehová miró de los cielos á la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 20, 'Para oir el gemido de los presos, Para soltar á los sentenciados á muerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 21, 'Porque cuenten en Sión el nombre de Jehová, Y su alabanza en Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 22, 'Cuando los pueblos se congregaren en uno, Y los reinos, para servir á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 23, 'El afligió mi fuerza en el camino; Acortó mis días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 24, 'Dije: Dios mío, no me cortes en el medio de mis días: Por generación de generaciones son tus años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 25, 'Tú fundaste la tierra antiguamente, Y los cielos son obra de tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 26, 'Ellos perecerán, y tú permanecerás; Y todos ellos como un vestido se envejecerán; Como una ropa de vestir los mudarás, y serán mudados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 27, 'Mas tú eres el mismo, Y tus años no se acabarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 102, 28, 'Los hijos de tus siervos habitarán, Y su simiente será afirmada delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 1, 'BENDICE, alma mía á Jehová; Y bendigan todas mis entrañas su santo nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 2, 'Bendice, alma mía, á Jehová, Y no olvides ninguno de sus beneficios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 3, 'El es quien perdona todas tus iniquidades, El que sana todas tus dolencias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 4, 'El que rescata del hoyo tu vida, El que te corona de favores y misericordias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 5, 'El que sacia de bien tu boca De modo que te rejuvenezcas como el águila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 6, 'Jehová el que hace justicia Y derecho á todos los que padecen violencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 7, 'Sus caminos notificó á Moisés, Y á los hijos de Israel sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 8, 'Misericordioso y clemente es Jehová; Lento para la ira, y grande en misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 9, 'No contenderá para siempre, Ni para siempre guardará el enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 10, 'No ha hecho con nosotros conforme á nuestras iniquidades; Ni nos ha pagado conforme á nuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 11, 'Porque como la altura de los cielos sobre la tierra, Engrandeció su misericordia sobre los que le temen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 12, 'Cuanto está lejos el oriente del occidente, Hizo alejar de nosotros nuestras rebeliones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 13, 'Como el padre se compadece de los hijos, Se compadece Jehová de los que le temen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 14, 'Porque él conoce nuestra condición; Acuérdase que somos polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 15, 'El hombre, como la hierba son sus días, Florece como la flor del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 16, 'Que pasó el viento por ella, y pereció: Y su lugar no la conoce más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 17, 'Mas la misericordia de Jehová desde el siglo y hasta el siglo sobre los que le temen, Y su justicia sobre los hijos de los hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 18, 'Sobre los que guardan su pacto, Y los que se acuerdan de sus mandamientos para ponerlos por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 19, 'Jehová afirmó en los cielos su trono; Y su reino domina sobre todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 20, 'Bendecid á Jehová, vosotros sus ángeles, Poderosos en fortaleza, que ejecutáis su palabra, Obedeciendo á la voz de su precepto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 21, 'Bendecid á Jehová, vosotros todos sus ejércitos, Ministros suyos, que hacéis su voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 103, 22, 'Bendecid á Jehová, vosotras todas sus obras, En todos los lugares de su señorío. Bendice, alma mía á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 1, 'BENDICE, alma mía, á Jehová. Jehová, Dios mío, mucho te has engrandecido; Haste vestido de gloria y de magnificencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 2, 'El que se cubre de luz como de vestidura, Que extiende los cielos como una cortina;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 3, 'Que establece sus aposentos entre las aguas; El que pone las nubes por su carroza, El que anda sobre las alas del viento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 4, 'El que hace á sus ángeles espíritus, Sus ministros al fuego flameante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 5, 'El fundó la tierra sobre sus basas; No será jamás removida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 6, 'Con el abismo, como con vestido, la cubriste; Sobre los montes estaban las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 7, 'A tu reprensión huyeron; Al sonido de tu trueno se apresuraron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 8, 'Subieron los montes, descendieron los valles, Al lugar que tú les fundaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 9, 'Pusísteles término, el cual no traspasarán; Ni volverán á cubrir la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 10, 'Tú eres el que envías las fuentes por los arroyos; Van entre los montes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 11, 'Abrevan á todas las bestias del campo: Quebrantan su sed los asnos montaraces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 12, 'Junto á aquellos habitarán las aves de los cielos; Entre las ramas dan voces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 13, 'El que riega los montes desde sus aposentos: Del fruto de sus obras se sacia la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 14, 'El que hace producir el heno para las bestias, Y la hierba para el servicio del hombre; Sacando el pan de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 15, 'Y el vino que alegra el corazón del hombre, Y el aceite que hace lucir el rostro, Y el pan que sustenta el corazón del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 16, 'Llénanse de jugo los árboles de Jehová, Los cedros del Líbano que él plantó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 17, 'Allí anidan las aves; En las hayas hace su casa la cigüeña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 18, 'Los montes altos para las cabras monteses; Las peñas, madrigueras para los conejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 19, 'Hizo la luna para los tiempos: El sol conoce su ocaso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 20, 'Pone las tinieblas, y es la noche: En ella corretean todas las bestias de la selva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 21, 'Los leoncillos braman á la presa, Y para buscar de Dios su comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 22, 'Sale el sol, recógense, Y échanse en sus cuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 23, 'Sale el hombre á su hacienda, Y á su labranza hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 24, '¡Cuán muchas son tus obras, oh Jehová! Hiciste todas ellas con sabiduría: La tierra está llena de tus beneficios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 25, 'Asimismo esta gran mar y ancha de términos: En ella pescados sin número, Animales pequeños y grandes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 26, 'Allí andan navíos; Allí este leviathán que hiciste para que jugase en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 27, 'Todos ellos esperan en ti, Para que les des su comida á su tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 28, 'Les das, recogen; Abres tu mano, hártanse de bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 29, 'Escondes tu rostro, túrbanse: Les quitas el espíritu, dejan de ser, Y tórnanse en su polvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 30, 'Envías tu espíritu, críanse: Y renuevas la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 31, 'Sea la gloria de Jehová para siempre; Alégrese Jehová en sus obras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 32, 'El cual mira á la tierra, y ella tiembla; Toca los montes, y humean.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 33, 'A Jehová cantaré en mi vida: A mi Dios salmearé mientras viviere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 34, 'Serme ha suave hablar de él: Yo me alegraré en Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 104, 35, 'Sean consumidos de la tierra los pecadores, Y los impíos dejen de ser. Bendice, alma mía, á Jehová. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 1, 'ALABAD á Jehová, invocad su nombre. Haced notorias sus obras en los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 2, 'Cantadle, cantadle salmos: Hablad de todas sus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 3, 'Gloriaos en su santo nombre: Alégrese el corazón de los que buscan á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 4, 'Buscad á Jehová, y su fortaleza: Buscad siempre su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 5, 'Acordaos de sus maravillas que hizo, De sus prodigios y de los juicios de su boca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 6, 'Oh vosotros, simiente de Abraham su siervo, Hijos de Jacob, sus escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 7, 'El es Jehová nuestro Dios; En toda la tierra son sus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 8, 'Acordóse para siempre de su alianza; De la palabra que mandó para mil generaciones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 9, 'La cual concertó con Abraham; Y de su juramento á Isaac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 10, 'Y establecióla á Jacob por decreto, A Israel por pacto sempiterno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 11, 'Diciendo: A ti daré la tierra de Canaán Por cordel de vuestra heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 12, 'Esto siendo ellos pocos hombres en número, Y extranjeros en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 13, 'Y anduvieron de gente en gente, De un reino á otro pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 14, 'No consintió que hombre los agraviase; Y por causa de ellos castigó los reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 15, 'No toquéis, dijo, á mis ungidos, Ni hagáis mal á mis profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 16, 'Y llamó al hambre sobre la tierra, Y quebrantó todo mantenimiento de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 17, 'Envió un varón delante de ellos, A José, que fué vendido por siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 18, 'Afligieron sus pies con grillos; En hierro fué puesta su persona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 19, 'Hasta la hora que llegó su palabra, El dicho de Jehová le probó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 20, 'Envió el rey, y soltóle; El señor de los pueblos, y desatóle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 21, 'Púsolo por señor de su casa, Y por enseñoreador en toda su posesión;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 22, 'Para que reprimiera á sus grandes como él quisiese, Y á sus ancianos enseñara sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 23, 'Después entró Israel en Egipto, Y Jacob fué extranjero en la tierra de Châm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 24, 'Y multiplicó su pueblo en gran manera, E hízolo fuerte más que sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 25, 'Volvió el corazón de ellos para que aborreciesen á su pueblo, Para que contra sus siervos pensasen mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 26, 'Envió á su siervo Moisés, Y á Aarón al cual escogió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 27, 'Pusieron en ellos las palabras de sus señales, Y sus prodigios en la tierra de Châm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 28, 'Echó tinieblas, é hizo oscuridad; Y no fueron rebeldes á su palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 29, 'Volvió sus aguas en sangre, Y mató sus pescados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 30, 'Produjo su tierra ranas, Aun en las cámaras de sus reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 31, 'Dijo, y vinieron enjambres de moscas, Y piojos en todo su término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 32, 'Volvió en su tierra sus lluvias en granizo, Y en fuego de llamaradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 33, 'E hirió sus viñas y sus higueras, Y quebró los árboles de su término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 34, 'Dijo, y vinieron langostas, Y pulgón sin número;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 35, 'Y comieron toda la hierba de su país, Y devoraron el fruto de su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 36, 'Hirió además á todos los primogénitos en su tierra, El principio de toda su fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 37, 'Y sacólos con plata y oro; Y no hubo en sus tribus enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 38, 'Egipto se alegró de que salieran; Porque su terror había caído sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 39, 'Extendió una nube por cubierta, Y fuego para alumbrar la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 40, 'Pidieron, é hizo venir codornices; Y saciólos de pan del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 41, 'Abrió la peña, y fluyeron aguas; Corrieron por los secadales como un río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 42, 'Porque se acordó de su santa palabra, Dada á Abraham su siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 43, 'Y sacó á su pueblo con gozo; Con júbilo á sus escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 44, 'Y dióles las tierras de las gentes; Y las labores de las naciones heredaron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 105, 45, 'Para que guardasen sus estatutos, Y observasen sus leyes. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 1, 'ALELUYA. Alabad á Jehová, porque es bueno; Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 2, '¿Quién expresará las valentías de Jehová? ¿Quién contará sus alabanzas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 3, 'Dichosos los que guardan juicio, Los que hacen justicia en todo tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 4, 'Acuérdate de mí, oh Jehová, según tu benevolencia para con tu pueblo: Visítame con tu salud;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 5, 'Para que yo vea el bien de tus escogidos, Para que me goce en la alegría de tu gente, Y me gloríe con tu heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 6, 'Pecamos con nuestros padres, Hicimos iniquidad, hicimos impiedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 7, 'Nuestros padres en Egipto no entendieron tus maravillas; No se acordaron de la muchedumbre de tus misericordias; Sino que se rebelaron junto á la mar, en el mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 8, 'Salvólos empero por amor de su nombre, Para hacer notoria su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 9, 'Y reprendió al mar Bermejo, y secólo; E hízoles ir por el abismo, como por un desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 10, 'Y salvólos de mano del enemigo, Y rescatólos de mano del adversario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 11, 'Y cubrieron las aguas á sus enemigos: No quedó uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 12, 'Entonces creyeron á sus palabras, Y cantaron su alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 13, 'Apresuráronse, olvidáronse de sus obras; No esperaron en su consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 14, 'Y desearon con ansia en el desierto; Y tentaron á Dios en la soledad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 15, 'Y él les dió lo que pidieron; Mas envió flaqueza en sus almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 16, 'Tomaron después celo contra Moisés en el campo, Y contra Aarón el santo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 17, 'Abrióse la tierra, y tragó á Dathán, Y cubrió la compañía de Abiram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 18, 'Y encendióse el fuego en su junta; La llama quemó los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 19, 'Hicieron becerro en Horeb, Y encorváronse á un vaciadizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 20, 'Así trocaron su gloria Por la imagen de un buey que come hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 21, 'Olvidaron al Dios de su salud, Que había hecho grandezas en Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 22, 'Maravillas en la tierra de Châm, Cosas formidables sobre el mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 23, 'Y trató de destruirlos, A no haberse puesto Moisés su escogido al portillo delante de él, A fin de apartar su ira, para que no los destruyese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 24, 'Empero aborrecieron la tierra deseable: No creyeron á su palabra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 25, 'Antes murmuraron en sus tiendas, Y no oyeron la voz de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 26, 'Por lo que alzó su mano á ellos, En orden á postrarlos en el desierto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 27, 'Y humillar su simiente entre las gentes, Y esparcirlos por las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 28, 'Allegáronse asimismo á Baalpeor, Y comieron los sacrificios de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 29, 'Y ensañaron á Dios con sus obras, Y desarrollóse la mortandad en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 30, 'Entonces se levantó Phinees, é hizo juicio; Y se detuvo la plaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 31, 'Y fuéle contado á justicia De generación en generación para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 32, 'También le irritaron en las aguas de Meriba: E hizo mal á Moisés por causa de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 33, 'Porque hicieron se rebelase su espíritu, Como lo expresó con sus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 34, 'No destruyeron los pueblos Que Jehová les dijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 35, 'Antes se mezclaron con las gentes, Y aprendieron sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 36, 'Y sirvieron á sus ídolos; Los cuales les fueron por ruina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 37, 'Y sacrificaron sus hijos y sus hijas á los demonios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 38, 'Y derramaron la sangre inocente, la sangre de sus hijos y de sus hijas, Que sacrificaron á los ídolos de Canaán: Y la tierra fué contaminada con sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 39, 'Contamináronse así con sus obras, Y fornicaron con sus hechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 40, 'Encendióse por tanto el furor de Jehová sobre su pueblo, Y abominó su heredad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 41, 'Y entrególos en poder de las gentes, Y enseñoreáronse de ellos los que los aborrecían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 42, 'Y sus enemigos los oprimieron, Y fueron quebrantados debajo de su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 43, 'Muchas veces los libró; Mas ellos se rebelaron á su consejo, Y fueron humillados por su maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 44, 'El con todo, miraba cuando estaban en angustia, Y oía su clamor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 45, 'Y acordábase de su pacto con ellos, Y arrepentíase conforme á la muchedumbre de sus miseraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 46, 'Hizo asimismo tuviesen de ellos misericordia todos los que los tenían cautivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 47, 'Sálvanos, Jehová Dios nuestro, Y júntanos de entre las gentes, Para que loemos tu santo nombre, Para que nos gloriemos en tus alabanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 106, 48, 'Bendito Jehová Dios de Israel, Desde el siglo y hasta el siglo: Y diga todo el pueblo, Amén. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 1, 'ALABAD á Jehová, porque es bueno; Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 2, 'Digan lo los redimidos de Jehová, Los que ha redimido del poder del enemigo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 3, 'Y los ha congregado de las tierras, Del oriente y del occidente, Del aquilón y de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 4, 'Anduvieron perdidos por el desierto, por la soledad sin camino, No hallando ciudad de población.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 5, 'Hambrientos y sedientos, Su alma desfallecía en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 6, 'Habiendo empero clamado á Jehová en su angustia, Librólos de sus aflicciones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 7, 'Y dirigiólos por camino derecho, Para que viniesen á ciudad de población.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 8, 'Alaben la misericordia de Jehová, Y sus maravillas para con los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 9, 'Porque sació al alma menesterosa, Y llenó de bien al alma hambrienta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 10, 'Los que moraban en tinieblas y sombra de muerte, Aprisionados en aflicción y en hierros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 11, 'Por cuanto fueron rebeldes á las palabras de Jehová, Y aborrecieron el consejo del Altísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 12, 'Por lo que quebrantó él con trabajo sus corazones, Cayeron y no hubo quien los ayudase;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 13, 'Luego que clamaron á Jehová en su angustia, Librólos de sus aflicciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 14, 'Sacólos de las tinieblas y de la sombra de muerte, Y rompió sus prisiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 15, 'Alaben la misericordia de Jehová, Y sus maravillas para con los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 16, 'Porque quebrantó las puertas de bronce, Y desmenuzó los cerrojos de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 17, 'Los insensatos, á causa del camino de su rebelión Y á causa de sus maldades, fueron afligidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 18, 'Su alma abominó toda vianda, Y llegaron hasta las puertas de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 19, 'Mas clamaron á Jehová en su angustia, Y salvólos de sus aflicciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 20, 'Envió su palabra, y curólos, Y librólos de su ruina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 21, 'Alaben la misericordia de Jehová, Y sus maravillas para con los hijos de los hombres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 22, 'Y sacrifiquen sacrificios de alabanza, Y publiquen sus obras con júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 23, 'Los que descienden á la mar en navíos, Y hacen negocio en las muchas aguas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 24, 'Ellos han visto las obras de Jehová, Y sus maravillas en el profundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 25, 'El dijo, é hizo saltar el viento de la tempestad, Que levanta sus ondas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 26, 'Suben á los cielos, descienden á los abismos: Sus almas se derriten con el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 27, 'Tiemblan, y titubean como borrachos, Y toda su ciencia es perdida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 28, 'Claman empero á Jehová en su angustia, Y líbralos de sus aflicciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 29, 'Hace parar la tempestad en sosiego, Y se apaciguan sus ondas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 30, 'Alégranse luego porque se reposaron; Y él los guía al puerto que deseaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 31, 'Alaben la misericordia de Jehová, Y sus maravillas para con los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 32, 'Y ensálcenlo en la congregación del pueblo; Y en consistorio de ancianos lo alaben.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 33, 'El vuelve los ríos en desierto, Y los manantiales de las aguas en secadales;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 34, 'La tierra fructífera en salados, Por la maldad de los que la habitan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 35, 'Vuelve el desierto en estanques de aguas, Y la tierra seca en manantiales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 36, 'Y allí aposenta á los hambrientos, Y disponen ciudad para habitación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 37, 'Y siembran campos, y plantan viñas, Y rinden crecido fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 38, 'Y los bendice, y se multiplican en gran manera; Y no disminuye sus bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 39, 'Y luego son menoscabados y abatidos A causa de tiranía, de males y congojas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 40, 'El derrama menosprecio sobre los príncipes, Y les hace andar errados, vagabundos, sin camino:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 41, 'Y levanta al pobre de la miseria, Y hace multiplicar las familias como rebaños de ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 42, 'Vean los rectos, y alégrense; Y toda maldad cierre su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 107, 43, '¿Quién es sabio y guardará estas cosas, Y entenderá las misericordias de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 1, 'MI corazón está dispuesto, oh Dios; Cantaré y salmearé todavía en mi gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 2, 'Despiértate, salterio y arpa: Despertaré al alba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 3, 'Te alabaré, oh Jehová, entre los pueblos; A ti cantaré salmos entre las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 4, 'Porque grande más que los cielos es tu misericordia, Y hasta los cielos tu verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 5, 'Ensálzate, oh Dios, sobre los cielos; Y sobre toda la tierra tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 6, 'Para que sean librados tus amados, Salva con tu diestra y respóndeme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 7, 'Dios habló por su santuario: alegraréme, Repartiré á Sichêm, y mediré el valle de Succoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 8, 'Mío es Galaad, mío es Manasés; Y Eprhaim es la fortaleza de mi cabeza; Judá es mi legislador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 9, 'Moab, la vasija de mi lavatorio: Sobre Edom echaré mi calzado; Regocijaréme sobre Palestina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 10, '¿Quién me guiará á la ciudad fortalecida? ¿Quién me guiará hasta Idumea?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 11, 'Ciertamente tú, oh Dios, que nos habías desechado; Y no salías, oh Dios, con nuestros ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 12, 'Danos socorro en la angustia: Porque mentirosa es la salud del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 108, 13, 'En Dios haremos proezas; Y él hollará nuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 1, 'OH Dios de mi alabanza, no calles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 2, 'Porque boca de impío y boca de engañador se han abierto sobre mí: Han hablado de mí con lengua mentirosa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 3, 'Y con palabras de odio me rodearon; Y pelearon contra mí sin causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 4, 'En pago de mi amor me han sido adversarios: Mas yo oraba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 5, 'Y pusieron contra mí mal por bien, Y odio por amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 6, 'Pon sobre él al impío: Y Satán esté á su diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 7, 'Cuando fuere juzgado, salga impío; Y su oración sea para pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 8, 'Sean sus días pocos: Tome otro su oficio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 9, 'Sean sus hijos huérfanos, Y su mujer viuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 10, 'Y anden sus hijos vagabundos, y mendiguen; Y procuren su pan lejos de sus desolados hogares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 11, 'Enrede el acreedor todo lo que tiene, Y extraños saqueen su trabajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 12, 'No tenga quien le haga misericordia; Ni haya quien tenga compasión de sus huérfanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 13, 'Su posteridad sea talada; En segunda generación sea raído su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 14, 'Venga en memoria cerca de Jehová la maldad de sus padres, Y el pecado de su madre no sea borrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 15, 'Estén siempre delante de Jehová, Y él corte de la tierra su memoria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 16, 'Por cuanto no se acordo de hacer misericordia, Y persiguió al hombre afligido y menesteroso Y quebrantado de corazón, para matar lo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 17, 'Y amó la maldición, y vínole; Y no quiso la bendición, y ella se alejó de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 18, 'Y vistióse de maldición como de su vestido, Y entró como agua en sus entrañas, Y como aceite en sus huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 19, 'Séale como vestido con que se cubra, Y en lugar de cinto con que se ciña siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 20, 'Este sea el pago de parte de Jehová de los que me calumnian, Y de los que hablan mal contra mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 21, 'Y tú, Jehová Señor, haz conmigo por amor de tu nombre: Líbrame, porque tu misericordia es buena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 22, 'Porque yo estoy afligido y necesitado; Y mi corazón está herido dentro de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 23, 'Voime como la sombra cuando declina; Soy sacudido como langosta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 24, 'Mis rodillas están debilitadas á causa del ayuno, Y mi carne desfallecida por falta de gordura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 25, 'Yo he sido para ellos objeto de oprobio; Mirábanme, y meneaban su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 26, 'Ayúdame, Jehová Dios mío: Sálvame conforme á tu misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 27, 'Y entiendan que ésta es tu mano; Que tú, Jehová, has hecho esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 28, 'Maldigan ellos, y bendice tú: Levántense, mas sean avergonzados, y regocíjese tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 29, 'Sean vestidos de ignominia los que me calumnian; Y sean cubiertos de su confusión como con manto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 30, 'Yo alabaré á Jehová en gran manera con mi boca, Y le loaré en medio de muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 109, 31, 'Porque él se pondrá á la diestra del pobre, Para librar su alma de los que le juzgan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 1, 'JEHOVA dijo á mi Señor: Siéntate á mi diestra, En tanto que pongo tus enemigos por estrado de tus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 2, 'La vara de tu fortaleza enviará Jehová desde Sión: Domina en medio de tus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 3, 'Tu pueblo serálo de buena voluntad en el día de tu poder, En la hermosura de la santidad: desde el seno de la aurora, Tienes tú el rocío de tu juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 4, 'Juró Jehová, y no se arrepentirá: Tú eres sacerdote para siempre Según el orden de Melchîsedech.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 5, 'El Señor á tu diestra Herirá á los reyes en el día de su furor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 6, 'Juzgará en las gentes, Llenará las de cadáveres: Herirá las cabezas en muchas tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 110, 7, 'Del arroyo beberá en el camino: Por lo cual levantará cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 1, 'ALABARÉ á Jehová con todo el corazón, En la compañía y congregación de los rectos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 2, 'Grandes son las obras de Jehová; Buscadas de todos los que las quieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 3, 'Gloria y hermosura es su obra; Y su justicia permanece para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 4, 'Hizo memorables sus maravillas: Clemente y misericordioso es Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 5, 'Dió mantenimiento á los que le temen; Para siempre se acordará de su pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 6, 'El poder de sus obras anunció á su pueblo, Dándole la heredad de las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 7, 'Las obras de sus manos son verdad y juicio: Fieles son todos sus mandamientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 8, 'Afirmados por siglo de siglo, Hechos en verdad y en rectitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 9, 'Redención ha enviado á su pueblo; Para siempre ha ordenado su pacto: Santo y terrible es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 111, 10, 'El principio de la sabiduría es el temor de Jehová: Buen entendimiento tienen cuantos ponen aquéllos por obra: Su loor permanece para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 1, 'BIENAVENTURADO el hombre que teme á Jehová, Y en sus mandamientos se deleita en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 2, 'Su simiente será poderosa en la tierra: La generación de los rectos será bendita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 3, 'Hacienda y riquezas hay en su casa; Y su justicia permanece para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 4, 'Resplandeció en las tinieblas luz á los rectos: Es clemente, y misericordioso, y justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 5, 'El hombre de bien tiene misericordia y presta; Gobierna sus cosas con juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 6, 'Por lo cual no resbalará para siempre: En memoria eterna será el justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 7, 'De mala fama no tendrá temor: Su corazón está apercibido, confiado en Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 8, 'Asentado está su corazón, no temerá, Hasta que vea en sus enemigos su deseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 9, 'Esparce, da á los pobres: Su justicia permanece para siempre; Su cuerno será ensalzado en gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 112, 10, 'Verálo el impío, y se despechará; Crujirá los dientes, y se repudrirá: Perecerá el deseo de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 1, 'ALABAD, siervos de Jehová, Alabad el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 2, 'Sea el nombre de Jehová bendito, Desde ahora y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 3, 'Desde el nacimiento del sol hasta donde se pone, Sea alabado el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 4, 'Alto sobre todas las naciones es Jehová; Sobre los cielos su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 5, '¿Quién como Jehová nuestro Dios, Que ha enaltecido su habitación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 6, 'Que se humilla á mirar En el cielo y en la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 7, 'El levanta del polvo al pobre, Y al menesteroso alza del estiércol,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 8, 'Para hacerlos sentar con los príncipes, Con los príncipes de su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 113, 9, 'El hace habitar en familia á la estéril, Gozosa en ser madre de hijos. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 1, 'CUANDO salió Israel de Egipto, La casa de Jacob del pueblo bárbaro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 2, 'Judá fué su consagrada heredad, Israel su señorío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 3, 'La mar vió, y huyó; El Jordán se volvió atrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 4, 'Los montes saltaron como carneros: Los collados como corderitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 5, '¿Qué tuviste, oh mar, que huiste? ¿Y tú, oh Jordán, que te volviste atrás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 6, 'Oh montes, ¿por qué saltasteis como carneros, Y vosotros, collados, como corderitos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 7, 'A la presencia del Señor tiembla la tierra, A la presencia del Dios de Jacob;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 114, 8, 'El cual tornó la peña en estanque de aguas, Y en fuente de aguas la roca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 1, 'NO á nosotros, oh Jehová, no á nosotros, Sino á tu nombre da gloria; Por tu misericordia, por tu verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 2, 'Por qué dirán las gentes: ¿Dónde está ahora su Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 3, 'Y nuestro Dios está en los cielos: Todo lo que quiso ha hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 4, 'Sus ídolos son plata y oro, Obra de manos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 5, 'Tienen boca, mas no hablarán; Tienen ojos, mas no verán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 6, 'Orejas tienen, mas no oirán; Tienen narices, mas no olerán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 7, 'Manos tienen, mas no palparán; Tienen pies, mas no andarán; No hablarán con su garganta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 8, 'Como ellos son los que los hacen; Cualquiera que en ellos confía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 9, 'Oh Israel, confía en Jehová: El es su ayuda y su escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 10, 'Casa de Aarón, confiad en Jehová: El es su ayuda y su escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 11, 'Los que teméis á Jehová, confiad en Jehová: El es su ayuda y su escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 12, 'Jehová se acordó de nosotros: nos bendecirá: Bendecirá á la casa de Israel; Bendecirá á la casa de Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 13, 'Bendecirá á los que temen á Jehová; A chicos y á grandes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 14, 'Acrecentará Jehová bendición sobre vosotros; Sobre vosotros y sobre vuestros hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 15, 'Benditos vosotros de Jehová, Que hizo los cielos y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 16, 'Los cielos son los cielos de Jehová: Y ha dado la tierra á los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 17, 'No alabarán los muertos á JAH, Ni cuantos descienden al silencio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 115, 18, 'Mas nosotros bendeciremos á JAH, Desde ahora para siempre. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 1, 'AMO á Jehová, pues ha oído Mi voz y mis súplicas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 2, 'Porque ha inclinado á mí su oído, Invocaré le por tanto en todos mis días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 3, 'Rodeáronme los dolores de la muerte, Me encontraron las angustias del sepulcro: Angustia y dolor había yo hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 4, 'Entonces invoqué el nombre de Jehová, diciendo: Libra ahora, oh Jehová, mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 5, 'Clemente es Jehová y justo; Sí, misericordioso es nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 6, 'Jehová guarda á los sinceros: Estaba yo postrado, y salvóme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 7, 'Vuelve, oh alma mía, á tu reposo; Porque Jehová te ha hecho bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 8, 'Pues tú has librado mi alma de la muerte, Mis ojos de lágrimas, Y mis pies de desbarrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 9, 'Andaré delante de Jehová En la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 10, 'Creí; por tanto hablé, Estando afligido en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 11, 'Y dije en mi apresuramiento: Todo hombre es mentiroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 12, '¿Qué pagaré á Jehová Por todos sus beneficios para conmigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 13, 'Tomaré la copa de la salud, E invocaré el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 14, 'Ahora pagaré mis votos á Jehová Delante de todo su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 15, 'Estimada es en los ojos de Jehová La muerte de sus santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 16, 'Oh Jehová, que yo soy tu siervo, Yo tu siervo, hijo de tu sierva: Rompiste mis prisiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 17, 'Te ofreceré sacrificio de alabanza, E invocaré el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 18, 'A Jehová pagaré ahora mis votos Delante de todo su pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 116, 19, 'En los atrios de la casa de Jehová, En medio de ti, oh Jerusalem. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 117, 1, 'ALABAD á Jehová, naciones todas; Pueblos todos, alabadle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 117, 2, 'Porque ha engrandecido sobre nosotros su misericordia; Y la verdad de Jehová es para siempre. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 1, 'ALABAD á Jehová, porque es bueno; Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 2, 'Diga ahora Israel: Que para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 3, 'Diga ahora la casa de Aarón: Que para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 4, 'Digan ahora los que temen á Jehová: Que para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 5, 'Desde la angustia invoqué á JAH; Y respondióme JAH, poniéndome en anchura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 6, 'Jehová está por mí: no temeré Lo que me pueda hacer el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 7, 'Jehová está por mí entre los que me ayudan: Por tanto yo veré mi deseo en los que me aborrecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 8, 'Mejor es esperar en Jehová Que esperar en hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 9, 'Mejor es esperar en Jehová Que esperar en príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 10, 'Todas las gentes me cercaron: En nombre de Jehová, que yo los romperé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 11, 'Cercáronme y asediáronme: En nombre de Jehová, que yo los romperé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 12, 'Cercáronme como abejas; fueron apagados como fuegos de espinos: En nombre de Jehová, que yo los romperé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 13, 'Empujásteme con violencia para que cayese: Empero ayudóme Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 14, 'Mi fortaleza y mi canción es JAH; Y él me ha sido por salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 15, 'Voz de júbilo y de salvación hay en las tiendas de los justos: La diestra de Jehová hace proezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 16, 'La diestra de Jehová sublime: La diestra de Jehová hace valentías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 17, 'No moriré, sino que viviré, Y contaré las obras de JAH.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 18, 'Castigóme gravemente JAH: Mas no me entregó á la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 19, 'Abridme las puertas de la justicia: Entraré por ellas, alabaré á JAH.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 20, 'Esta puerta de Jehová, Por ella entrarán los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 21, 'Te alabaré porque me has oído, Y me fuiste por salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 22, 'La piedra que desecharon los edificadores, Ha venido á ser cabeza del ángulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 23, 'De parte de Jehová es esto: Es maravilla en nuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 24, 'Este es el día que hizo Jehová Nos gozaremos y alegraremos en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 25, 'Oh Jehová, salva ahora, te ruego: Oh Jehová, ruégote hagas prosperar ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 26, 'Bendito el que viene en nombre de Jehová: Desde la casa de Jehová os bendecimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 27, 'Dios es Jehová que nos ha resplandecido: Atad víctimas con cuerdas á los cuernos del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 28, 'Mi Dios eres tú, y á ti alabaré: Dios mío, á ti ensalzaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 118, 29, 'Alabad á Jehová porque es bueno; Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 1, 'ALEPH. BIENAVENTURADOS los perfectos de camino; Los que andan en la ley de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 2, 'Bienaventurados los que guardan sus testimonios, Y con todo el corazón le buscan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 3, 'Pues no hacen iniquidad Los que andan en sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 4, 'Tú encargaste Que sean muy guardados tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 5, '¡Ojalá fuesen ordenados mis caminos A observar tus estatutos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 6, 'Entonces no sería yo avergonzado, Cuando atendiese á todos tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 7, 'Te alabaré con rectitud de corazón, Cuando aprendiere los juicios de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 8, 'Tus estatutos guardaré: No me dejes enteramente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 9, 'BETH. ¿Con qué limpiará el joven su camino? Con guardar tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 10, 'Con todo mi corazón te he buscado: No me dejes divagar de tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 11, 'En mi corazón he guardado tus dichos, Para no pecar contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 12, 'Bendito tú, oh Jehová: Enséñame tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 13, 'Con mis labios he contado Todos los juicios de tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 14, 'Heme gozado en el camino de tus testimonios, Como sobre toda riqueza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 15, 'En tus mandamientos meditaré, Consideraré tus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 16, 'Recrearéme en tus estatutos: No me olvidaré de tus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 17, 'GIMEL. Haz bien á tu siervo; que viva Y guarde tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 18, 'Abre mis ojos, y miraré Las maravillas de tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 19, 'Advenedizo soy yo en la tierra: No encubras de mí tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 20, 'Quebrantada está mi alma de desear Tus juicios en todo tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 21, 'Destruiste á los soberbios malditos, Que se desvían de tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 22, 'Aparta de mí oprobio y menosprecio; Porque tus testimonios he guardado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 23, 'Príncipes también se sentaron y hablaron contra mí: Mas tu siervo meditaba en tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 24, 'Pues tus testimonios son mis deleites, Y mis consejeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 25, 'DALETH. Pegóse al polvo mi alma: Vivifícame según tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 26, 'Mis caminos te conté, y me has respondido: Enséñame tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 27, 'Hazme entender el camino de tus mandamientos, Y hablaré de tus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 28, 'Deshácese mi alma de ansiedad: Corrobórame según tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 29, 'Aparta de mí camino de mentira; Y hazme la gracia de tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 30, 'Escogí el camino de la verdad; He puesto tus juicios delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 31, 'Allegádome he á tus testimonios; Oh Jehová, no me avergüences.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 32, 'Por el camino de tus mandamientos correré, Cuando ensanchares mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 33, 'HE. Enséñame, oh Jehová, el camino de tus estatutos, Y guardarélo hasta el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 34, 'Dame entendimiento, y guardaré tu ley; Y la observaré de todo corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 35, 'Guíame por la senda de tus mandamientos; Porque en ella tengo mi voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 36, 'Inclina mi corazón á tus testimonios, Y no á la avaricia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 37, 'Aparta mis ojos, que no vean la vanidad; Avívame en tu camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 38, 'Confirma tu palabra á tu siervo, Que te teme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 39, 'Quita de mí el oprobio que he temido: Porque buenos son tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 40, 'He aquí yo he codiciado tus mandamientos: Vivifícame en tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 41, 'VAV. Y venga á mí tu misericordia, oh Jehová; Tu salud, conforme á tu dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 42, 'Y daré por respuesta á mi avergonzador, Que en tu palabra he confiado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 43, 'Y no quites de mi boca en nigún tiempo la palabra de verdad; Porque á tu juicio espero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 44, 'Y guardaré tu ley siempre, Por siglo de siglo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 45, 'Y andaré en anchura, Porque busqué tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 46, 'Y hablaré de tus testimonios delante de los reyes, Y no me avergonzaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 47, 'Y deleitaréme en tus mandamientos, Que he amado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 48, 'Alzaré asimismo mis manos á tus mandamientos que amé; Y meditaré en tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 49, 'ZAYIN. Acuérdate de la palabra dada á tu siervo, En la cual me has hecho esperar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 50, 'Esta es mi consuelo en mi aflicción: Porque tu dicho me ha vivificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 51, 'Los soberbios se burlaron mucho de mí: Mas no me he apartado de tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 52, 'Acordéme, oh Jehová, de tus juicios antiguos, Y consoléme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 53, 'Horror se apoderó de mí, á causa De los impíos que dejan tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 54, 'Cánticos me fueron tus estatutos En la mansión de mis peregrinaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 55, 'Acordéme en la noche de tu nombre, oh Jehová, Y guardé tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 56, 'Esto tuve, Porque guardaba tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 57, 'JET. Mi porción, oh Jehová, Dije, será guardar tus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 58, 'Tu presencia supliqué de todo corazón: Ten misericordia de mí según tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 59, 'Consideré mis caminos, Y torné mis pies á tus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 60, 'Apresuréme, y no me retardé En guardar tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 61, 'Compañía de impíos me han robado: Mas no me he olvidado de tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 62, 'A media noche me levantaba á alabarte Sobre los juicios de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 63, 'Compañero soy yo de todos los que te temieren Y guardaren tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 64, 'De tu misericordia, oh Jehová, está llena la tierra: Enséñame tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 65, 'TETH. Bien has hecho con tu siervo, Oh Jehová, conforme á tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 66, 'Enséñame bondad de sentido y sabiduría; Porque tus mandamientos he creído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 67, 'Antes que fuera yo humillado, descarriado andaba; Mas ahora guardo tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 68, 'Bueno eres tú, y bienhechor: Enséñame tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 69, 'Contra mí forjaron mentira los soberbios: Mas yo guardaré de todo corazón tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 70, 'Engrasóse el corazón de ellos como sebo; Mas yo en tu ley me he deleitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 71, 'Bueno me es haber sido humillado, Para que aprenda tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 72, 'Mejor me es la ley de tu boca, Que millares de oro y plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 73, 'YOD. Tus manos me hicieron y me formaron: Hazme entender, y aprenderé tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 74, 'Los que te temen, me verán, y se alegrarán; Porque en tu palabra he esperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 75, 'Conozco, oh Jehová, que tus juicios son justicia, Y que conforme á tu fidelidad me afligiste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 76, 'Sea ahora tu misericordia para consolarme, Conforme á lo que has dicho á tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 77, 'Vengan á mí tus misericordias, y viva; Porque tu ley es mi deleite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 78, 'Sean avergonzados los soberbios, porque sin causa me han calumniado: Yo empero, meditaré en tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 79, 'Tórnense á mí los que te temen Y conocen tus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 80, 'Sea mi corazón íntegro en tus estatutos; Porque no sea yo avergonzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 81, 'KAF. Desfallece mi alma por tu salud, Esperando en tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 82, 'Desfallecieron mis ojos por tu palabra, Diciendo: ¿Cuándo me consolarás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 83, 'Porque estoy como el odre al humo; Mas no he olvidado tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 84, '¿Cuántos son los días de tu siervo? ¿Cuándo harás juicio contra los que me persiguen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 85, 'Los soberbios me han cavado hoyos; Mas no obran según tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 86, 'Todos tus mandamientos son verdad: Sin causa me persiguen; ayúdame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 87, 'Casi me han echado por tierra: Mas yo no he dejado tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 88, 'Vivifícame conforme á tu misericordia; Y guardaré los testimonios de tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 89, 'LAMED. Para siempre, oh Jehová, Permenece tu palabra en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 90, 'Por generación y generación es tu verdad: Tú afirmaste la tierra, y persevera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 91, 'Por tu ordenación perseveran hasta hoy las cosas criadas; Porque todas ellas te sirven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 92, 'Si tu ley no hubiese sido mis delicias, Ya en mi aflicción hubiera perecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 93, 'Nunca jamás me olvidaré de tus mandamientos; Porque con ellos me has vivificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 94, 'Tuyo soy yo, guárdame; Porque he buscado tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 95, 'Los impíos me han aguardado para destruirme: Mas yo entenderé en tus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 96, 'A toda perfección he visto fin: Ancho sobremanera es tu mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 97, 'MEM. ¡Cuánto amo yo tu ley! Todo el día es ella mi meditación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 98, 'Me has hecho más sabio que mis enemigos con tus mandamientos; Porque me son eternos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 99, 'Más que todos mis enseñadores he entendido: Porque tus testimonios son mi meditación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 100, 'Más que los viejos he entendido, Porque he guardado tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 101, 'De todo mal camino contuve mis pies, Para guardar tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 102, 'No me aparté de tus juicios; Porque tú me enseñaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 103, '¡Cuán dulces son á mi paladar tus palabras! Más que la miel á mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 104, 'De tus mandamientos he adquirido inteligencia: Por tanto he aborrecido todo camino de mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 105, 'NUN. Lámpara es á mis pies tu palabra, Y lumbrera á mi camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 106, 'Juré y ratifiqué El guardar los juicios de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 107, 'Afligido estoy en gran manera: oh Jehová, Vivifícame conforme á tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 108, 'Ruégote, oh Jehová, te sean agradables los sacrificios voluntarios de mi boca; Y enséñame tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 109, 'De continuo está mi alma en mi mano: Mas no me he olvidado de tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 110, 'Pusiéronme lazo los impíos: Empero yo no me desvié de tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 111, 'Por heredad he tomado tus testimonios para siempre; Porque son el gozo de mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 112, 'Mi corazón incliné á poner por obra tus estatutos De continuo, hasta el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 113, 'SAMECH. Los pensamientos vanos aborrezco; Mas amo tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 114, 'Mi escondedero y mi escudo eres tú: En tu palabra he esperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 115, 'Apartaos de mí, malignos; Pues yo guardaré los mandamientos de mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 116, 'Susténtame conforme á tu palabra, y viviré: Y no me avergüences de mi esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 117, 'Sosténme, y seré salvo; Y deleitaréme siempre en tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 118, 'Hollaste á todos los que se desvían de tus estatutos: Porque mentira es su engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 119, 'Como escorias hiciste consumir á todos los impíos de la tierra: Por tanto yo he amado tus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 120, 'Mi carne se ha extremecido por temor de ti; Y de tus juicios tengo miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 121, 'AIN. Juicio y justicia he hecho; No me dejes á mis opresores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 122, 'Responde por tu siervo para bien: No me hagan violencia los soberbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 123, 'Mis ojos desfallecieron por tu salud, Y por el dicho de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 124, 'Haz con tu siervo según tu misericordia, Y enséñame tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 125, 'Tu siervo soy yo, dame entendimiento; Para que sepa tus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 126, 'Tiempo es de hacer, oh Jehová; Disipado han tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 127, 'Por eso he amado tus mandamientos Más que el oro, y más que oro muy puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 128, 'Por eso todos los mandamientos de todas las cosas estimé rectos: Aborrecí todo camino de mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 129, 'PE. Maravillosos son tus testimonios: Por tanto los ha guardado mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 130, 'El principio de tus palabras alumbra; Hace entender á los simples.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 131, 'Mi boca abrí y suspiré; Porque deseaba tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 132, 'Mírame, y ten misericordia de mí, Como acostumbras con los que aman tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 133, 'Ordena mis pasos con tu palabra; Y ninguna iniquidad se enseñoree de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 134, 'Redímeme de la violencia de los hombres; Y guardaré tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 135, 'Haz que tu rostro resplandezca sobre tu siervo; Y enséñame tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 136, 'Ríos de agua descendieron de mis ojos, Porque no guardaban tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 137, 'TZADDI. Justo eres tú, oh Jehová, Y rectos tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 138, 'Tus testimonios, que has recomendado, Son rectos y muy fieles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 139, 'Mi celo me ha consumido; Porque mis enemigos se olvidaron de tus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 140, 'Sumamente acendrada es tu palabra; Y la ama tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 141, 'Pequeño soy yo y desechado; Mas no me he olvidado de tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 142, 'Tu justicia es justicia eterna, Y tu ley la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 143, 'Aflicción y angustia me hallaron: Mas tus mandamientos fueron mis deleites.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 144, 'Justicia eterna son tus testimonios; Dame entendimiento, y viviré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 145, 'COPH. Clamé con todo mi corazón; respóndeme, Jehová, Y guardaré tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 146, 'A ti clamé; sálvame, Y guardaré tus testimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 147, 'Anticipéme al alba, y clamé: Esperé en tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 148, 'Previnieron mis ojos las vigilias de la noche, Para meditar en tus dichos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 149, 'Oye mi voz conforme á tu misericordia; Oh Jehová, vivifícame conforme á tu juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 150, 'Acercáronse á la maldad los que me persiguen; Alejáronse de tu ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 151, 'Cercano estás tú, oh Jehová; Y todos tus mandamientos son verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 152, 'Ya ha mucho que he entendido de tus mandamientos, Que para siempre los fundaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 153, 'RESH. Mira mi aflicción, y líbrame; Porque de tu ley no me he olvidado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 154, 'Aboga mi causa, y redímeme: Vivifícame con tu dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 155, 'Lejos está de los impíos la salud; Porque no buscan tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 156, 'Muchas son tus misericordias, oh Jehová: Vivifícame conforme á tus juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 157, 'Muchos son mis perseguidores y mis enemigos; Mas de tus testimonios no me he apartado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 158, 'Veía á los prevaricadores, y carcomíame; Porque no guardaban tus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 159, 'Mira, oh Jehová, que amo tus mandamientos: Vivifícame conforme á tu misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 160, 'El principio de tu palabra es verdad; Y eterno es todo juicio de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 161, 'SIN. Príncipes me han perseguido sin causa; Mas mi corazón tuvo temor de tus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 162, 'Gózome yo en tu palabra, Como el que halla muchos despojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 163, 'La mentira aborrezco y abomino: Tu ley amo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 164, 'Siete veces al día te alabo Sobre los juicios de tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 165, 'Mucha paz tienen los que aman tu ley; Y no hay para ellos tropiezo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 166, 'Tu salud he esperado, oh Jehová; Y tus mandamientos he puesto por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 167, 'Mi alma ha guardado tus testimonios, Y helos amado en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 168, 'Guardado he tus mandamientos y tus testimonios; Porque todos mis caminos están delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 169, 'TAU. Acérquese mi clamor delante de ti, oh Jehová: Dame entendimiento conforme á tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 170, 'Venga mi oración delante de ti: Líbrame conforme á tu dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 171, 'Mis labios rebosarán alabanza, Cuando me enseñares tus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 172, 'Hablará mi lengua tus dichos; Porque todos tus mandamientos son justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 173, 'Sea tu mano en mi socorro; Porque tus mandamientos he escogido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 174, 'Deseado he tu salud, oh Jehová; Y tu ley es mi delicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 175, 'Viva mi alma y alábete; Y tus juicios me ayuden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 119, 176, 'Yo anduve errante como oveja extraviada; busca á tu siervo; Porque no me he olvidado de tus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 1, 'A JEHOVA llamé estando en angustia, Y él me respondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 2, 'Libra mi alma, oh Jehová, de labio mentiroso, De la lengua fraudulenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 3, '¿Qué te dará, ó qué te aprovechará, Oh lengua engañosa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 4, 'Agudas saetas de valiente, Con brasas de enebro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 5, '¡Ay de mí, que peregrino en Mesech, Y habito entre las tiendas de Kedar!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 6, 'Mucho se detiene mi alma Con los que aborrecen la paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 120, 7, 'Yo soy pacífico: Mas ellos, así que hablo, me hacen guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 1, 'ALZARÉ mis ojos á los montes, De donde vendrá mi socorro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 2, 'Mi socorro viene de Jehová, Que hizo los cielos y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 3, 'No dará tu pie al resbaladero; Ni se dormirá el que te guarda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 4, 'He aquí, no se adormecerá ni dormirá El que guarda á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 5, 'Jehová es tu guardador: Jehová es tu sombra á tu mano derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 6, 'El sol no te fatigará de día, Ni la luna de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 7, 'Jehová te guardará de todo mal: El guardará tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 121, 8, 'Jehová guardará tu salida y tu entrada, Desde ahora y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 1, 'YO me alegré con los que me decían: A la casa de Jehová iremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 2, 'Nuestros pies estuvieron En tus puertas, oh Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 3, 'Jerusalem, que se ha edificado Como una ciudad que está bien unida entre sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 4, 'Y allá subieron las tribus, las tribus de JAH, Conforme al testimonio dado á Israel, Para alabar el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 5, 'Porque allá están las sillas del juicio, Las sillas de la casa de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 6, 'Pedid la paz de Jerusalem: Sean prosperados los que te aman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 7, 'Haya paz en tu antemuro, Y descanso en tus palacios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 8, 'Por amor de mis hermanos y mis compañeros Hablaré ahora paz de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 122, 9, 'A causa de la casa de Jehová nuestro Dios, Buscaré bien para ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 123, 1, 'A TI que habitas en los cielos, Alcé mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 123, 2, 'He aquí como los ojos de los siervos miran á la mano de sus señores, Y como los ojos de la sierva á la mano de su señora; Así nuestros ojos miran á Jehová nuestro Dios, Hasta que haya misericordia de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 123, 3, 'Ten misericordia de nosotros, oh Jehová, ten misericordia de nosotros; Porque estamos muy hartos de menosprecio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 123, 4, 'Muy harta está nuestra alma Del escarnio de los holgados, Y del menosprecio de los soberbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 1, 'A NO haber estado Jehová por nosotros, Diga ahora Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 2, 'A no haber estado Jehová por nosotros, Cuando se levantaron contra nosotros los hombres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 3, 'Vivos nos habrían entonces tragado, Cuando se encendió su furor en nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 4, 'Entonces nos habrían inundado las aguas; Sobre nuestra alma hubiera pasado el torrente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 5, 'Hubieran entonces pasado sobre nuestra alma las aguas soberbias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 6, 'Bendito Jehová, Que no nos dió por presa á sus dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 7, 'Nuestra alma escapó cual ave del lazo de los cazadores: Quebróse el lazo, y escapamos nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 124, 8, 'Nuestro socorro es en el nombre de Jehová, Que hizo el cielo y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 125, 1, 'LOS que confían en Jehová Son como el monte de Sión que no deslizará: estará para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 125, 2, 'Como Jerusalem tiene montes alrededor de ella, Así Jehová alrededor de su pueblo Desde ahora y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 125, 3, 'Porque no reposará la vara de la impiedad sobre la suerte de los justos; Porque no extiendan los justos sus manos á la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 125, 4, 'Haz bien, oh Jehová, á los buenos, Y á los que son rectos en sus corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 125, 5, 'Mas á los que se apartan tras sus perversidades, Jehová los llevará con los que obran iniquidad: Y paz sea sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 126, 1, 'CUANDO Jehová hiciere tornar la cautividad de Sión, Seremos como los que sueñan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 126, 2, 'Entonces nuestra boca se henchirá de risa, Y nuestra lengua de alabanza; Entonces dirán entre las gentes: Grandes cosas ha hecho Jehová con éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 126, 3, 'Grandes cosas ha hecho Jehová con nosotros; Estaremos alegres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 126, 4, 'Haz volver nuestra cautividad oh Jehová, Como los arroyos en el austro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 126, 5, 'Los que sembraron con lágrimas, con regocijo segarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 126, 6, 'Irá andando y llorando el que lleva la preciosa simiente; Mas volverá á venir con regocijo, trayendo sus gavillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 127, 1, 'SI Jehová no edificare la casa, En vano trabajan los que la edifican: Si Jehová no guardare la ciudad, En vano vela la guarda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 127, 2, 'Por demás os es el madrugar á levantaros, el veniros tarde á reposar, El comer pan de dolores: Pues que á su amado dará Dios el sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 127, 3, 'He aquí, heredad de Jehová son los hijos: Cosa de estima el fruto del vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 127, 4, 'Como saetas en mano del valiente, Así son los hijos habidos en la juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 127, 5, 'Bienaventurado el hombre que hinchió su aljaba de ellos: No será avergonzado Cuando hablare con los enemigos en la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 128, 1, 'BIENAVENTURADO todo aquel que teme á Jehová, Que anda en sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 128, 2, 'Cuando comieres el trabajo de tus manos, Bienaventurado tú, y tendrás bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 128, 3, 'Tu mujer será como parra que lleva fruto á los lados de tu casa; Tus hijos como plantas de olivas alrededor de tu mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 128, 4, 'He aquí que así será bendito el hombre Que teme á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 128, 5, 'Bendígate Jehová desde Sión, Y veas el bien de Jerusalem todos los días de tu vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 128, 6, 'Y veas los hijos de tus hijos, Y la paz sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 1, 'MUCHO me han angustiado desde mi juventud, Puede decir ahora Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 2, 'Mucho me han angustiado desde mi juventud; Mas no prevalecieron contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 3, 'Sobre mis espaldas araron los aradores: Hicieron largos surcos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 4, 'Jehová es justo; Cortó las coyundas de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 5, 'Serán avergonzados y vueltos atrás Todos los que aborrecen á Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 6, 'Serán como la hierba de los tejados, Que se seca antes que crezca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 7, 'De la cual no hinchió segador su mano, Ni sus brazos el que hace gavillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 129, 8, 'Ni dijeron los que pasaban: Bendición de Jehová sea sobre vosotros; Os bendecimos en el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 1, 'DE los profundos, oh Jehová, á ti clamo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 2, 'Señor, oye mi voz; Estén atentos tus oídos A la voz de mi súplica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 3, 'JAH, si mirares á los pecados, ¿Quién, oh Señor, podrá mantenerse?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 4, 'Empero hay perdón cerca de ti, Para que seas temido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 5, 'Esperé yo á Jehová, esperó mi alma; En su palabra he esperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 6, 'Mi alma espera á Jehová Más que los centinelas á la mañana. Más que los vigilantes á la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 7, 'Espere Israel á Jehová; Porque en Jehová hay misericordia. Y abundante redención con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 130, 8, 'Y él redimirá á Israel De todos sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 131, 1, 'JEHOVA, no se ha envanecido mi corazón, ni mis ojos se enaltecieron; Ni anduve en grandezas, Ni en cosas para mí demasiado sublimes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 131, 2, 'En verdad que me he comportado y he acallado mi alma, Como un niño destetado de su madre: Como un niño destetado está mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 131, 3, 'Espera, oh Israel, en Jehová Desde ahora y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 1, 'ACUÉRDATE, oh Jehová, de David, Y de toda su aflicción;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 2, 'Que juró él á Jehová, Prometió al Fuerte de Jacob:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 3, 'No entraré en la morada de mi casa, Ni subiré sobre el lecho de mi estrado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 4, 'No daré sueño á mis ojos, Ni á mis párpados adormecimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 5, 'Hasta que halle lugar para Jehová, Moradas para el Fuerte de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 6, 'He aquí, en Ephrata oímos de ella: Hallamósla en los campos del bosque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 7, 'Entraremos en sus tiendas; Encorvarnos hemos al estrado de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 8, 'Levántate, oh Jehová, á tu reposo; Tú y el arca de tu fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 9, 'Tus sacerdotes se vistan de justicia, Y regocíjense tus santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 10, 'Por amor de David tu siervo No vuelvas de tu ungido el rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 11, 'En verdad juró Jehová á David, No se apartará de ellos: Del fruto de tu vientre pondré sobre tu trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 12, 'Si tus hijos guardaren mi alianza, Y mi testimonio que yo les enseñaré, Sus hijos también se sentarán sobre tu trono para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 13, 'Porque Jehová ha elegido á Sión; Deseóla por habitación para sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 14, 'Este es mi reposo para siempre: Aquí habitaré, porque la he deseado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 15, 'A su mantenimiento daré bendición: Sus pobres saciaré de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 16, 'Asimismo vestiré á sus sacerdotes de salud, Y sus santos darán voces de júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 17, 'Allí haré reverdecer el cuerno de David: He prevenido lámpara á mi ungido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 132, 18, 'A sus enemigos vestiré de confusión: Mas sobre él florecerá su corona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 133, 1, '¡MIRAD cuán bueno y cuán delicioso es Habitar los hermanos igualmente en uno!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 133, 2, 'Es como el buen óleo sobre la cabeza, El cual desciende sobre la barba, La barba de Aarón, Y que baja hasta el borde de sus vestiduras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 133, 3, 'Como el rocío de Hermón, Que desciende sobre los montes de Sión: Porque allí envía Jehová bendición, Y vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 134, 1, 'MIRAD, bendecid á Jehová, Vosotros todos los siervos de Jehová, Los que en la casa de Jehová estáis por las noches.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 134, 2, 'Alzad vuestras manos al santuario, Y bendecid á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 134, 3, 'Bendígate Jehová desde Sión, El cual ha hecho los cielos y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 1, 'ALABAD el nombre de Jehová; Alabad le, siervos de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 2, 'Los que estáis en la casa de Jehová, En los atrios de la casa de nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 3, 'Alabad á JAH, porque es bueno Jehová: Cantad salmos á su nombre, porque es suave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 4, 'Porque JAH ha escogido á Jacob para sí, A Israel por posesión suya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 5, 'Porque yo se que Jehová es grande, Y el Señor nuestro, mayor que todos los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 6, 'Todo lo que quiso Jehová, ha hecho En los cielos y en la tierra, en las mares y en todos los abismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 7, 'El hace subir las nubes del cabo de la tierra; El hizo los relámpagos para la lluvia; El saca los vientos de sus tesoros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 8, 'El es el que hirió los primogénitos de Egipto, Desde el hombre hasta la bestia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 9, 'Envió señales y prodigios en medio de ti, oh Egipto, Sobre Faraón, y sobre todos sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 10, 'El que hirió muchas gentes, Y mató reyes poderosos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 11, 'A Sehón rey Amorrheo, Y á Og rey de Basán, Y á todos los reinos de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 12, 'Y dió la tierra de ellos en heredad, En heredad á Israel su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 13, 'Oh Jehová, eterno es tu nombre; Tu memoria, oh Jehová para generación y generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 14, 'Porque juzgará Jehová su pueblo, Y arrepentiráse sobre sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 15, 'Los ídolos de las gentes son plata y oro, Obra de manos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 16, 'Tienen boca, y no hablan; Tienen ojos, y no ven;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 17, 'Tienen orejas, y no oyen; Tampoco hay espíritu en sus bocas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 18, 'Como ellos son los que los hacen; Todos los que en ellos confían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 19, 'Casa de Israel, bendecid á Jehová: Casa de Aarón, bendecid á Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 20, 'Casa de Leví, bendecid á Jehová: Los que teméis á Jehová, bendecid á Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 135, 21, 'Bendito de Sión Jehová, Que mora en Jerusalem. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 1, 'ALABAD á Jehová, porque es bueno; Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 2, 'Alabad al Dios de los dioses, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 3, 'Alabad al Señor de los señores, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 4, 'Al solo que hace grandes maravillas, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 5, 'Al que hizo los cielos con entendimiento, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 6, 'Al que tendió la tierra sobre las aguas, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 7, 'Al que hizo las grandes luminarias, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 8, 'El sol para que dominase en el día, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 9, 'La luna y las estrellas para que dominasen en la noche, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 10, 'Al que hirió á Egipto en sus primogénitos, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 11, 'Al que sacó á Israel de en medio de ellos, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 12, 'Con mano fuerte, y brazo extendido, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 13, 'Al que dividió el mar Bermejo en partes, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 14, 'E hizo pasar á Israel por medio de él, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 15, 'Y arrojó á Faraón y á su ejército en el mar Bermejo, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 16, 'Al que pastoreó á su pueblo por el desierto, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 17, 'Al que hirió grandes reyes, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 18, 'Y mató reyes poderosos, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 19, 'A Sehón rey Amorrheo, Porque para siempre es su misericordia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 20, 'Y á Og rey de Basán, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 21, 'Y dió la tierra de ellos en heredad, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 22, 'En heredad á Israel su siervo, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 23, 'El es el que en nuestro abatimiento se acordó de nosotros, Porque para siempre es su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 24, 'Y nos rescató de nuestros enemigos, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 25, 'El da mantenimiento á toda carne, Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 136, 26, 'Alabad al Dios de los cielos: Porque para siempre es su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 1, 'JUNTO á los ríos de Babilonia, Allí nos sentábamos, y aun llorábamos, Acordándonos de Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 2, 'Sobre los sauces en medio de ella Colgamos nuestras arpas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 3, 'Y los que allí nos habían llevado cautivos nos pedían que cantásemos, Y los que nos habían desolado nos pedían alegría, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 4, 'Cantadnos algunos de los himnos de Sión. ¿Cómo cantaremos canción de Jehová En tierra de extraños?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 5, 'Si me olvidare de ti, oh Jerusalem, Mi diestra sea olvidada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 6, 'Mi lengua se pegue á mi paladar, Si de ti no me acordare; Si no ensalzare á Jerusalem Como preferente asunto de mi alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 7, 'Acuérdate, oh Jehová, de los hijos de Edom En el día de Jerusalem; Quienes decían: Arrasadla, arrasadla Hasta los cimientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 8, 'Hija de Babilonia destruída, Bienaventurado el que te diere el pago De lo que tú nos hiciste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 137, 9, 'Bienaventurado el que tomará y estrellará tus niños Contra las piedras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 1, 'ALABARTE he con todo mi corazón: Delante de los dioses te cantaré salmos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 2, 'Encorvaréme al templo de tu santuario, Y alabaré tu nombre por tu misericordia y tu verdad: Porque has hecho magnífico tu nombre, y tu dicho sobre todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 3, 'En el día que clamé, me respondiste; Esforzásteme con fortaleza en mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 4, 'Confesarte han, oh Jehová, todos los reyes de la tierra, Cuando habrán oído los dichos de tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 5, 'Y cantarán de los caminos de Jehová: Que la gloria de Jehová es grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 6, 'Porque el alto Jehová atiende al humilde; Mas al altivo mira de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 7, 'Si anduviere yo en medio de la angustia, tú me vivificarás: Contra la ira de mis enemigos extenderás tu mano, Y salvaráme tu diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 138, 8, 'Jehová cumplirá por mí: Tu misericordia, oh Jehová, es para siempre; No dejarás la obra de tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 1, 'OH Jehová, tú me has examinado y conocido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 2, 'Tú has conocido mi sentarme y mi levantarme, Has entendido desde lejos mis pensamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 3, 'Mi senda y mi acostarme has rodeado, Y estás impuesto en todos mis caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 4, 'Pues aun no está la palabra en mi lengua, Y he aquí, oh Jehová, tú la sabes toda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 5, 'Detrás y delante me guarneciste, Y sobre mí pusiste tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 6, 'Más maravillosa es la ciencia que mi capacidad; Alta es, no puedo comprenderla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 7, '¿Adónde me iré de tu espíritu? ¿Y adónde huiré de tu presencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 8, 'Si subiere á los cielos, allí estás tú: Y si en abismo hiciere mi estrado, he aquí allí tú estás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 9, 'Si tomare las alas del alba, Y habitare en el extremo de la mar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 10, 'Aun allí me guiará tu mano, Y me asirá tu diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 11, 'Si dijere: Ciertamente las tinieblas me encubrirán; Aun la noche resplandecerá tocante á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 12, 'Aun las tinieblas no encubren de ti, Y la noche resplandece como el día: Lo mismo te son las tinieblas que la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 13, 'Porque tú poseiste mis riñones; Cubrísteme en el vientre de mi madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 14, 'Te alabaré; porque formidables, maravillosas son tus obras: Estoy maravillado, Y mi alma lo conoce mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 15, 'No fué encubierto de ti mi cuerpo, Bien que en oculto fuí formado, Y compaginado en lo más bajo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 16, 'Mi embrión vieron tus ojos, Y en tu libro estaban escritas todas aquellas cosas Que fueron luego formadas, Sin faltar una de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 17, 'Así que ¡cuán preciosos me son, oh Dios, tus pensamientos! ¡Cuán multiplicadas son sus cuentas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 18, 'Si los cuento, multiplícanse más que la arena: Despierto, y aun estoy contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 19, 'De cierto, oh Dios, matarás al impío; Apartaos pues de mí, hombres sanguinarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 20, 'Porque blasfemias dicen ellos contra ti: Tus enemigos toman en vano tu nombre');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 21, '¿No tengo en odio, oh Jehová, á los que te aborrecen, Y me conmuevo contra tus enemigos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 22, 'Aborrézcolos con perfecto odio; Téngolos por enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 23, 'Examíname, oh Dios, y conoce mi corazón: Pruébame y reconoce mis pensamientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 139, 24, 'Y ve si hay en mí camino de perversidad, Y guíame en el camino eterno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 1, 'LIBRAME, oh Jehová, de hombre malo: Guárdame de hombre violento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 2, 'Los cuales maquinan males en el corazón, Cada día urden contiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 3, 'Aguzaron su lengua como la serpiente; Veneno de áspid hay debajo de sus labios. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 4, 'Guárdame, oh Jehová, de manos del impío, Presérvame del hombre injurioso; Que han pensado de trastornar mis pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 5, 'Hanme escondido lazo y cuerdas los soberbios; Han tendido red junto á la senda; Me han puesto lazos. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 6, 'He dicho á Jehová: Dios mío eres tú; Escucha, oh Jehová, la voz de mis ruegos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 7, 'Jehová Señor, fortaleza de mi salud, Tú pusiste á cubierto mi cabeza el día de las armas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 8, 'No des, oh Jehová, al impío sus deseos; No saques adelante su pensamiento, que no se ensoberbezca. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 9, 'En cuanto á los que por todas partes me rodean, La maldad de sus propios labios cubrirá su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 10, 'Caerán sobre ellos brasas; Dios los hará caer en el fuego, En profundos hoyos de donde no salgan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 11, 'El hombre deslenguado no será firme en la tierra: El mal cazará al hombre injusto para derribarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 12, 'Yo sé que hará Jehová el juicio del afligido, El juicio de los menesterosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 140, 13, 'Ciertamente los justos alabarán tu nombre; Los rectos morarán en tu presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 1, 'JEHOVA, á ti he clamado; apresúrate á mí; Escucha mi voz, cuando te invocare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 2, 'Sea enderezada mi oración delante de ti como un perfume, El don de mis manos como la ofrenda de la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 3, 'Pon, oh Jehová, guarda á mi boca: Guarda la puerta de mis labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 4, 'No dejes se incline mi corazón á cosa mala, A hacer obras impías Con los que obran iniquidad, Y no coma yo de sus deleites.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 5, 'Que el justo me castigue, será un favor, Y que me reprenda será un excelente bálsamo. Que no me herirá la cabeza: Así que aun mi oración tendrán en sus calamidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 6, 'Serán derribados en lugares peñascosos sus jueces, Y oirán mis palabras, que son suaves.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 7, 'Como quien hiende y rompe la tierra, Son esparcidos nuestros huesos á la boca de la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 8, 'Por tanto á ti, oh Jehová Señor, miran mis ojos: En ti he confiado, no desampares mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 9, 'Guárdame de los lazos que me han tendido, Y de los armadijos de los que obran iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 141, 10, 'Caigan los impíos á una en sus redes, Mientras yo pasaré adelante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 1, 'CON mi voz clamaré á Jehová, Con mi voz pediré á Jehová misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 2, 'Delante de él derramaré mi querella; Delante de él denunciaré mi angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 3, 'Cuando mi espíritu se angustiaba dentro de mí, tú conociste mi senda. En el camino en que andaba, me escondieron lazo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 4, 'Miraba á la mano derecha, y observaba; mas no había quien me conociese; No tuve refugio, no había quien volviese por mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 5, 'Clamé á ti, oh Jehová, Dije: Tú eres mi esperanza, Y mi porción en la tierra de los vivientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 6, 'Escucha mi clamor, que estoy muy afligido; Líbrame de los que me persiguen, porque son más fuertes que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 142, 7, 'Saca mi alma de la cárcel para que alabe tu nombre: Me rodearán los justos, Porque tú me serás propicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 1, 'OH Jehová, oye mi oración, escucha mis ruegos: Respóndeme por tu verdad, por tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 2, 'Y no entres en juicio con tu siervo; Porque no se justificará delante de ti ningún viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 3, 'Porque ha perseguido el enemigo mi alma; Ha postrado en tierra mi vida; Hame hecho habitar en tinieblas como los ya muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 4, 'Y mi espíritu se angustió dentro de mí; Pasmóse mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 5, 'Acordéme de los días antiguos; Meditaba en todas tus obras, Reflexionaba en las obras de tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 6, 'Extendí mis manos á ti; Mi alma á ti como la tierra sedienta. (Selah.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 7, 'Respóndeme presto, oh Jehová que desmaya mi espíritu: No escondas de mí tu rostro, Y venga yo á ser semejante á los que descienden á la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 8, 'Hazme oir por la mañana tu misericordia, Porque en ti he confiado: Hazme saber el camino por donde ande, Porque á ti he alzado mi alma');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 9, 'Líbrame de mis enemigos, oh Jehová: A ti me acojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 10, 'Enséñame á hacer tu voluntad, porque tú eres mi Dios: Tu buen espíritu me guíe á tierra de rectitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 11, 'Por tu nombre, oh Jehová me vivificarás: Por tu justicia, sacarás mi alma de angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 143, 12, 'Y por tu misericordia disiparás mis enemigos, Y destruirás todos los adversarios de mi alma: Porque yo soy tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 1, 'BENDITO sea Jehová, mi roca, Que enseña mis manos á la batalla, Y mis dedos á la guerra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 2, 'Misericordia mía y mi castillo, Altura mía y mi libertador, Escudo mío, en quien he confiado; El que allana mi pueblo delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 3, 'Oh Jehová, ¿qué es el hombre, para que de él conozcas? ¿O el hijo del hombre, para que lo estimes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 4, 'El hombre es semejante á la vanidad: Sus días son como la sombra que pasa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 5, 'Oh Jehová, inclina tus cielos y desciende: Toca los montes, y humeen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 6, 'Despide relámpagos, y disípalos, Envía tus saetas, y contúrbalos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 7, 'Envía tu mano desde lo alto; Redímeme, y sácame de las muchas aguas, De la mano de los hijos de extraños;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 8, 'Cuya boca habla vanidad, Y su diestra es diestra de mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 9, 'Oh Dios, á ti cantaré canción nueva: Con salterio, con decacordio cantaré á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 10, 'Tú, el que da salud á los reyes, El que redime á David su siervo de maligna espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 11, 'Redímeme, y sálvame de mano de los hijos extraños, Cuya boca habla vanidad, Y su diestra es diestra de mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 12, 'Que nuestros hijos sean como plantas crecidas en su juventud; Nuestras hijas como las esquinas labradas á manera de las de un palacio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 13, 'Nuestros graneros llenos, provistos de toda suerte de grano; Nuestros ganados, que paran á millares y diez millares en nuestras plazas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 14, 'Que nuestros bueyes estén fuertes para el trabajo; Que no tengamos asalto, ni que hacer salida, Ni grito de alarma en nuestras plazas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 144, 15, 'Bienaventurado el pueblo que tiene esto: Bienaventurado el pueblo cuyo Dios es Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 1, 'ENSALZARTE he, mi Dios, mi Rey; Y bendeciré tu nombre por siglo y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 2, 'Cada día te bendeciré, Y alabaré tu nombre por siglo y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 3, 'Grande es Jehová y digno de suprema alabanza: Y su grandeza es inescrutable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 4, 'Generación á generación narrará tus obras, Y anunciarán tus valentías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 5, 'La hermosura de la gloria de tu magnificencia, Y tus hechos maravillosos, hablaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 6, 'Y la terribilidad de tus valentías dirán los hombres; Y yo recontaré tu grandeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 7, 'Reproducirán la memoria de la muchedumbre de tu bondad, Y cantarán tu justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 8, 'Clemente y misericordioso es Jehová, Lento para la ira, y grande en misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 9, 'Bueno es Jehová para con todos; Y sus misericordia sobre todas sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 10, 'Alábente, oh Jehová, todas tus obras; Y tus santos te bendigan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 11, 'La gloria de tu reino digan, Y hablen de tu fortaleza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 12, 'Para notificar á los hijos de los hombre sus valentías, Y la gloria de la magnificencia de su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 13, 'Tu reino es reino de todos los siglos, Y tu señorío en toda generación y generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 14, 'Sostiene Jehová á todos los que caen, Y levanta á todos los oprimidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 15, 'Los ojos de todos esperan en ti, Y tú les das su comida en su tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 16, 'Abres tu mano, Y colmas de bendición á todo viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 17, 'Justo es Jehová en todos sus caminos, Y misericordioso en todas sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 18, 'Cercano está Jehová á todos los que le invocan, A todos los que le invocan de veras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 19, 'Cumplirá el deseo de los que le temen; Oirá asimismo el clamor de ellos, y los salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 20, 'Jehová guarda á todos los que le aman; Empero destruirá á todos los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 145, 21, 'La alabanza de Jehová hablará mi boca; Y bendiga toda carne su santo nombre por siglo y para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 1, 'ALABA, oh alma mía, á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 2, 'Alabaré á Jehová en mi vida: Cantaré salmos á mi Dios mientras viviere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 3, 'No confiéis en los príncipes, Ni en hijo de hombre, porque no hay en él salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 4, 'Saldrá su espíritu, tornaráse en su tierra: En aquel día perecerán sus pensamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 5, 'Bienaventurado aquel en cuya ayuda es el Dios de Jacob, Cuya esperanza es en Jehová su Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 6, 'El cual hizo los cielos y la tierra, La mar, y todo lo que en ellos hay; Que guarda verdad para siempre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 7, 'Que hace derecho á los agraviados; Que da pan á los hambrientos: Jehová suelta á los aprisionados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 8, 'Jehová abre los ojos á los ciegos; Jehová levanta á los caídos; Jehová ama á los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 9, 'Jehová guarda á los extranjeros; Al huérfano y á la viuda levanta; Y el camino de los impíos trastorna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 146, 10, 'Reinará Jehová para siempre; Tu Dios, oh Sión, por generación y generación. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 1, 'ALABAD á JAH, Porque es bueno cantar salmos á nuestro Dios; Porque suave y hermosa es la alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 2, 'Jehová edifica á Jerusalem; A los echados de Israel recogerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 3, 'El sana á los quebrantados de corazón, Y liga sus heridas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 4, 'El cuenta el número de las estrellas; A todas ellas llama por sus nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 5, 'Grande es el Señor nuestro, y de mucha potencia; Y de su entendimiento no hay número.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 6, 'Jehová ensalza á los humildes; Humilla los impíos hasta la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 7, 'Cantad á Jehová con alabanza, Cantad con arpa á nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 8, 'El es el que cubre los cielos de nubes, El que prepara la lluvia para la tierra, El que hace á los montes producir hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 9, 'El da á la bestia su mantenimiento, Y á los hijos de los cuervos que claman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 10, 'No toma contentamiento en la fortaleza del caballo, Ni se complace en las piernas del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 11, 'Complácese Jehová en los que le temen, Y en los que esperan en su misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 12, 'Alaba á Jehová, Jerusalem; Alaba á tu Dios, Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 13, 'Porque fortificó los cerrojos de tus puertas; Bendijo á tus hijos dentro de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 14, 'El pone en tu término la paz; Te hará saciar de grosura de trigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 15, 'El envía su palabra á la tierra; Muy presto corre su palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 16, 'El da la nieve como lana, Derrama la escarcha como ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 17, 'El echa su hielo como pedazos: Delante de su frío ¿quién estará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 18, 'Enviará su palabra, y los derretirá: Soplará su viento, y fluirán las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 19, 'El denuncia sus palabras á Jacob, Sus estatutos y sus juicios á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 147, 20, 'No ha hecho esto con toda gente; Y no conocieron sus juicios. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 1, 'ALABAD á Jehová desde los cielos: Alabadle en las alturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 2, 'Alabadle, vosotros todos sus ángeles: Alabadle, vosotros todos sus ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 3, 'Alabadle, sol y luna: Alabadle, vosotras todas, lucientes estrellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 4, 'Alabadle, cielos de los cielos, Y las aguas que están sobre los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 5, 'Alaben el nombre de Jehová; Porque él mandó, y fueron criadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 6, 'Y las hizo ser para siempre por los siglos; Púso les ley que no será quebrantada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 7, 'Alabad á Jehová, de la tierra Los dragones y todos los abismos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 8, 'El fuego y el granizo, la nieve y el vapor, El viento de tempestad que ejecuta su palabra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 9, 'Los montes y todos los collados; El árbol de fruto, y todos los cedros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 10, 'La bestia y todo animal; Reptiles y volátiles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 11, 'Los reyes de la tierra y todos los pueblos; Los príncipes y todos los jueces de la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 12, 'Los mancebos y también las doncellas; Los viejos y los niños,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 13, 'Alaben el nombre de Jehová, Porque sólo su nombre es elevado; Su gloria es sobre tierra y cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 148, 14, 'El ensalzó el cuerno de su pueblo; Aláben le todos sus santos, los hijos de Israel, El pueblo á él cercano. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 1, 'CANTAD á Jehová canción nueva: Su alabanza sea en la congregación de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 2, 'Alégrese Israel en su Hacedor: Los hijos de Sión se gocen en su Rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 3, 'Alaben su nombre con corro: Con adufe y arpa á él canten.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 4, 'Porque Jehová toma contentamiento con su pueblo: Hermoseará á los humildes con salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 5, 'Gozarse han los píos con gloria: Cantarán sobre sus camas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 6, 'Ensalzamientos de Dios modularán en sus gargantas. Y espadas de dos filos habrá en sus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 7, 'Para hacer venganza de las gentes, Y castigo en los pueblos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 8, 'Para aprisionar sus reyes en grillos, Y sus nobles con cadenas de hierro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 149, 9, 'Para ejecutar en ellos el juicio escrito: Gloria será esta para todos sus santos. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 150, 1, 'ALABAD á Dios en su santuario: Alabadle en la extensión de su fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 150, 2, 'Alabadle por sus proezas: Alabadle conforme á la muchedumbre de su grandeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 150, 3, 'Alabadle á son de bocina: Alabadle con salterio y arpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 150, 4, 'Alabadle con adufe y flauta: Alabadle con cuerdas y órgano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 150, 5, 'Alabadle con címbalos resonantes: Alabadle con címbalos de júbilo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 150, 6, 'Todo lo que respira alabe á JAH. Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 1, 'LOS proverbios de Salomón, hijo de David, rey de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 2, 'Para entender sabiduría y doctrina; Para conocer las razones prudentes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 3, 'Para recibir el consejo de prudencia, Justicia, y juicio y equidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 4, 'Para dar sagacidad á los simples, Y á los jóvenes inteligencia y cordura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 5, 'Oirá el sabio, y aumentará el saber; Y el entendido adquirirá consejo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 6, 'Para entender parábola y declaración; Palabras de sabios, y sus dichos oscuros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 7, 'El principio de la sabiduría es el temor de Jehová: Los insensatos desprecian la sabiduría y la enseñanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 8, 'Oye, hijo mío, la doctrina de tu padre, Y no desprecies la dirección de tu madre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 9, 'Porque adorno de gracia serán á tu cabeza, Y collares á tu cuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 10, 'Hijo mío, si los pecadores te quisieren engañar, No consientas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 11, 'Si dijeren: Ven con nosotros, Pongamos asechanzas á la sangre, Acechemos sin motivo al inocente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 12, 'Los tragaremos vivos como el sepulcro, Y enteros, como los que caen en sima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 13, 'Hallaremos riquezas de todas suertes, Henchiremos nuestras casas de despojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 14, 'Echa tu suerte entre nosotros; Tengamos todos una bolsa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 15, 'Hijo mío, no andes en camino con ellos; Aparta tu pie de sus veredas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 16, 'Porque sus pies correrán al mal, E irán presurosos á derramar sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 17, 'Porque en vano se tenderá la red Ante los ojos de toda ave;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 18, 'Mas ellos á su propia sangre ponen asechanzas, Y á sus almas tienden lazo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 19, 'Tales son las sendas de todo el que es dado á la codicia, La cual prenderá el alma de sus poseedores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 20, 'La sabiduría clama de fuera, Da su voz en las plazas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 21, 'Clama en los principales lugares de concurso; En las entradas de las puertas de la ciudad dice sus razones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 22, '¿Hasta cuándo, oh simples, amaréis la simpleza, Y los burladores desearán el burlar, Y los insensatos aborrecerán la ciencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 23, 'Volveos á mi reprensión: He aquí yo os derramaré mi espíritu, Y os haré saber mis palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 24, 'Por cuanto llamé, y no quisisteis: Extendí mi mano, y no hubo quien escuchase;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 25, 'Antes desechasteis todo consejo mío, Y mi reprensión no quisisteis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 26, 'También yo me reiré en vuestra calamidad, Y me burlaré cuando os viniere lo que teméis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 27, 'Cuando viniere como una destrucción lo que teméis, Y vuestra calamidad llegare como un torbellino; Cuando sobre vosotros viniere tribulación y angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 28, 'Entonces me llamarán, y no responderé; Buscarme han de mañana, y no me hallarán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 29, 'Por cuanto aborrecieron la sabiduría, Y no escogieron el temor de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 30, 'Ni quisieron mi consejo, Y menospreciaron toda reprensión mía:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 31, 'Comerán pues del fruto de su camino, Y se hartarán de sus consejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 32, 'Porque el reposo de los ignorantes los matará, Y la prosperidad de los necios los echará á perder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 1, 33, 'Mas el que me oyere, habitará confiadamente, Y vivirá reposado, sin temor de mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 1, 'HIJO mío, si tomares mis palabras, Y mis mandamientos guardares dentro de ti,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 2, 'Haciendo estar atento tu oído á la sabiduría; Si inclinares tu corazón á la prudencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 3, 'Si clamares á la inteligencia, Y á la prudencia dieres tu voz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 4, 'Si como á la plata la buscares, Y la escudriñares como á tesoros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 5, 'Entonces entenderás el temor de Jehová, Y hallarás el conocimiento de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 6, 'Porque Jehová da la sabiduría, Y de su boca viene el conocimiento y la inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 7, 'El provee de sólida sabiduría á los rectos: Es escudo á los que caminan rectamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 8, 'Es el que guarda las veredas del juicio, Y preserva el camino de sus santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 9, 'Entonces entenderás justicia, juicio, Y equidad, y todo buen camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 10, 'Cuando la sabiduría entrare en tu corazón, Y la ciencia fuere dulce á tu alma,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 11, 'El consejo te guardará, Te preservará la inteligencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 12, 'Para librarte del mal camino, De los hombres que hablan perversidades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 13, 'Que dejan las veredas derechas, Por andar en caminos tenebrosos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 14, 'Que se alegran haciendo mal, Que se huelgan en las perversidades del vicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 15, 'Cuyas veredas son torcidas, Y torcidos sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 16, 'Para librarte de la mujer extraña, De la ajena que halaga con sus palabras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 17, 'Que desampara el príncipe de su mocedad, Y se olvida del pacto de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 18, 'Por lo cual su casa está inclinada á la muerte, Y sus veredas hacia los muertos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 19, 'Todos los que á ella entraren, no volverán, Ni tomarán las veredas de la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 20, 'Para que andes por el camino de los buenos, Y guardes las veredas de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 21, 'Porque los rectos habitarán la tierra, Y los perfectos permanecerán en ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 2, 22, 'Mas los impíos serán cortados de la tierra, Y los prevaricadores serán de ella desarraigados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 1, 'HIJO mío, no te olvides de mi ley; Y tu corazón guarde mis mandamientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 2, 'Porque largura de días, y años de vida Y paz te aumentarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 3, 'Misericordia y verdad no te desamparen; Atalas á tu cuello, Escríbelas en la tabla de tu corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 4, 'Y hallarás gracia y buena opinión En los ojos de Dios y de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 5, 'Fíate de Jehová de todo tu corazón, Y no estribes en tu prudencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 6, 'Reconócelo en todos tus caminos, Y él enderezará tus veredas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 7, 'No seas sabio en tu opinión: Teme á Jehová, y apártate del mal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 8, 'Porque será medicina á tu ombligo, Y tuétano á tus huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 9, 'Honra á Jehová de tu sustancia, Y de las primicias de todos tus frutos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 10, 'Y serán llenas tus trojes con abundancia, Y tus lagares rebosarán de mosto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 11, 'No deseches, hijo mío, el castigo de Jehová; Ni te fatigues de su corrección:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 12, 'Porque al que ama castiga, Como el padre al hijo á quien quiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 13, 'Bienaventurado el hombre que halla la sabiduría, Y que obtiene la inteligencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 14, 'Porque su mercadería es mejor que la mercadería de la plata, Y sus frutos más que el oro fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 15, 'Más preciosa es que las piedras preciosas; Y todo lo que puedes desear, no se puede comparar á ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 16, 'Largura de días está en su mano derecha; En su izquierda riquezas y honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 17, 'Sus caminos son caminos deleitosos, Y todas sus veredas paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 18, 'Ella es árbol de vida á los que de ella asen: Y bienaventurados son los que la mantienen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 19, 'Jehová con sabiduría fundó la tierra; Afirmó los cielos con inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 20, 'Con su ciencia se partieron los abismos, Y destilan el rocío los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 21, 'Hijo mío, no se aparten estas cosas de tus ojos; Guarda la ley y el consejo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 22, 'Y serán vida á tu alma, Y gracia á tu cuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 23, 'Entonces andarás por tu camino confiadamente, Y tu pie no tropezará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 24, 'Cuando te acostares, no tendrás temor; Antes te acostarás, y tu sueño será suave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 25, 'No tendrás temor de pavor repentino, Ni de la ruina de los impíos cuando viniere:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 26, 'Porque Jehová será tu confianza, Y él preservará tu pie de ser preso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 27, 'No detengas el bien de sus dueños, Cuando tuvieres poder para hacerlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 28, 'No digas á tu prójimo: Ve, y vuelve, Y mañana te daré; Cuando tienes contigo qué darle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 29, 'No intentes mal contra tu prójimo, Estando él confiado de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 30, 'No pleitees con alguno sin razón, Si él no te ha hecho agravio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 31, 'No envidies al hombre injusto, Ni escojas alguno de sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 32, 'Porque el perverso es abominado de Jehová: Mas su secreto es con los rectos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 33, 'La maldición de Jehová está en la casa del impío; Mas él bendecirá la morada de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 34, 'Ciertamente él escarnecerá á los escarnecedores, Y á los humildes dará gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 3, 35, 'Los sabios heredarán honra: Mas los necios sostendrán ignominia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 1, 'OID, hijos, la doctrina de un padre, Y estad atentos para que conozcáis cordura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 2, 'Porque os doy buena enseñanza; No desamparéis mi ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 3, 'Porque yo fuí hijo de mi padre, Delicado y único delante de mi madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 4, 'Y él me enseñaba, y me decía: Mantenga tu corazón mis razones, Guarda mis mandamientos, y vivirás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 5, 'Adquiere sabiduría, adquiere inteligencia; No te olvides ni te apartes de las razones de mi boca;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 6, 'No la dejes, y ella te guardará; Amala, y te conservará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 7, 'Sabiduría ante todo: adquiere sabiduría: Y ante toda tu posesión adquiere inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 8, 'Engrandécela, y ella te engrandecerá: Ella te honrará, cuando tú la hubieres abrazado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 9, 'Adorno de gracia dará á tu cabeza: Corona de hermosura te entregará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 10, 'Oye, hijo mío, y recibe mis razones; Y se te multiplicarán años de vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 11, 'Por el camino de la sabiduría te he encaminado, Y por veredas derechas te he hecho andar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 12, 'Cuando anduvieres no se estrecharán tus pasos; Y si corrieres, no tropezarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 13, 'Ten el consejo, no lo dejes; Guárdalo, porque eso es tu vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 14, 'No entres por la vereda de los impíos, Ni vayas por el camino de los malos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 15, 'Desampárala, no pases por ella; Apártate de ella, pasa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 16, 'Porque no duermen ellos, si no hicieren mal; Y pierden su sueño, si no han hecho caer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 17, 'Porque comen pan de maldad, y beben vino de robos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 18, 'Mas la senda de los justos es como la luz de la aurora, Que va en aumento hasta que el día es perfecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 19, 'El camino de los impíos es como la oscuridad: No saben en qué tropiezan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 20, 'Hijo mío, está atento á mis palabras; Inclina tu oído á mis razones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 21, 'No se aparten de tus ojos; Guárdalas en medio de tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 22, 'Porque son vida á los que las hallan, Y medicina á toda su carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 23, 'Sobre toda cosa guardada guarda tu corazón; Porque de él mana la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 24, 'Aparta de ti la perversidad de la boca, Y aleja de ti la iniquidad de labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 25, 'Tus ojos miren lo recto, Y tus párpados en derechura delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 26, 'Examina la senda de tus pies, Y todos tus caminos sean ordenados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 4, 27, 'No te apartes á diestra, ni á siniestra: Aparta tu pie del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 1, 'HIJO mío, está atento á mi sabiduría, Y á mi inteligencia inclina tu oído;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 2, 'Para que guardes consejo, Y tus labios conserven la ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 3, 'Porque los labios de la extraña destilan miel, Y su paladar es más blando que el aceite;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 4, 'Mas su fin es amargo como el ajenjo, Agudo como cuchillo de dos filos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 5, 'Sus pies descienden á la muerte; Sus pasos sustentan el sepulcro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 6, 'Sus caminos son instables; no los conocerás, Si no considerares el camino de vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 7, 'Ahora pues, hijos, oidme, Y no os apartéis de las razones de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 8, 'Aleja de ella tu camino, Y no te acerques á la puerta de su casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 9, 'Porque no des á los extraños tu honor, Y tus años á cruel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 10, 'Porque no se harten los extraños de tu fuerza, Y tus trabajos estén en casa del extraño;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 11, 'Y gimas en tus postrimerías, Cuando se consumiere tu carne y tu cuerpo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 12, 'Y digas: ¡Cómo aborrecí el consejo, Y mi corazón menospreció la reprensión;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 13, 'Y no oí la voz de los que me adoctrinaban, Y á los que me enseñaban no incliné mi oído!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 14, 'Casi en todo mal he estado, En medio de la sociedad y de la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 15, 'Bebe el agua de tu cisterna, Y los raudales de tu pozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 16, 'Derrámense por de fuera tus fuentes, En las plazas los ríos de aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 17, 'Sean para ti solo, Y no para los extraños contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 18, 'Sea bendito tu manantial; Y alégrate con la mujer de tu mocedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 19, 'Como cierva amada y graciosa corza, Sus pechos te satisfagan en todo tiempo; Y en su amor recréate siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 20, '¿Y por qué, hijo mío, andarás ciego con la ajena, Y abrazarás el seno de la extraña?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 21, 'Pues que los caminos del hombre están ante los ojos de Jehová, Y él considera todas sus veredas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 22, 'Prenderán al impío sus propias iniquidades, Y detenido será con las cuerdas de su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 5, 23, 'El morirá por falta de corrección; Y errará por la grandeza de su locura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 1, 'HIJO mío, si salieres fiador por tu amigo, Si tocaste tu mano por el extraño,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 2, 'Enlazado eres con las palabras de tu boca, Y preso con las razones de tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 3, 'Haz esto ahora, hijo mío, y líbrate, Ya que has caído en la mano de tu prójimo: Ve, humíllate, y asegúrate de tu amigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 4, 'No des sueño á tus ojos, Ni á tus párpados adormecimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 5, 'Escápate como el corzo de la mano del cazador, Y como el ave de la mano del parancero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 6, 'Ve á la hormiga, oh perezoso Mira sus caminos, y sé sabio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 7, 'La cual no teniendo capitán, Ni gobernador, ni señor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 8, 'Prepara en el verano su comida Y allega en el tiempo de la siega su mantenimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 9, 'Perezoso, ¿hasta cuándo has de dormir? ¿Cuándo te levantarás de tu sueño?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 10, 'Un poco de sueño, un poco de dormitar, Y cruzar por un poco las manos para reposo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 11, 'Así vendrá tu necesidad como caminante, Y tu pobreza como hombre de escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 12, 'El hombre malo, el hombre depravado, Anda en perversidad de boca;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 13, 'Guiña de sus ojos, habla con sus pies, Indica con sus dedos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 14, 'Perversidades hay en su corazón, anda pensando mal en todo tiempo; Enciende rencillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 15, 'Por tanto su calamidad vendrá de repente; Súbitamente será quebrantado, y no habrá remedio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 16, 'Seis cosas aborrece Jehová, Y aun siete abomina su alma:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 17, 'Los ojos altivos, la lengua mentirosa, Las manos derramadoras de sangre inocente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 18, 'El corazón que maquina pensamientos inicuos, Los pies presurosos para correr al mal,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 19, 'El testigo falso que habla mentiras, Y el que enciende rencillas entre los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 20, 'Guarda, hijo mío, el mandamiento de tu padre, Y no dejes la enseñanza de tu madre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 21, 'Atalos siempre en tu corazón, Enlázalos á tu cuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 22, 'Te guiarán cuando anduvieres; cuando durmieres te guardarán; Hablarán contigo cuando despertares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 23, 'Porque el mandamiento es antorcha, y la enseñanza luz; Y camino de vida las reprensiones de la enseñanza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 24, 'Para que te guarden de la mala mujer, De la blandura de la lengua de la extraña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 25, 'No codicies su hermosura en tu corazón, Ni ella te prenda con sus ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 26, 'Porque á causa de la mujer ramera es reducido el hombre á un bocado de pan; Y la mujer caza la preciosa alma del varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 27, '¿Tomará el hombre fuego en su seno, Sin que sus vestidos se quemen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 28, '¿Andará el hombre sobre las brasas, Sin que sus pies se abrasen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 29, 'Así el que entrare á la mujer de su prójimo; No será sin culpa cualquiera que la tocare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 30, 'No tienen en poco al ladrón, cuando hurtare Para saciar su alma teniendo hambre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 31, 'Empero tomado, paga las setenas, Da toda la sustancia de su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 32, 'Mas el que comete adulterio con la mujer, es falto de entendimiento: Corrompe su alma el que tal hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 33, 'Plaga y vergüenza hallará; Y su afrenta nunca será raída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 34, 'Porque los celos son el furor del hombre, Y no perdonará en el día de la venganza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 6, 35, 'No tendrá respeto á ninguna redención; Ni querrá perdonar, aunque multipliques los dones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 1, 'HIJO mío, guarda mis razones, Y encierra contigo mis mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 2, 'Guarda mis mandamientos, y vivirás; Y mi ley como las niñas de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 3, 'Lígalos á tus dedos; Escríbelos en la tabla de tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 4, 'Di á la sabiduría: Tú eres mi hermana; Y á la inteligencia llama parienta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 5, 'Para que te guarden de la mujer ajena, Y de la extraña que ablanda sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 6, 'Porque mirando yo por la ventana de mi casa, Por mi celosía,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 7, 'Vi entre los simples, Consideré entre los jóvenes, Un mancebo falto de entendimiento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 8, 'El cual pasaba por la calle, junto á la esquina de aquella, E iba camino de su casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 9, 'A la tarde del día, ya que oscurecía, En la oscuridad y tiniebla de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 10, 'Y he aquí, una mujer que le sale al encuentro Con atavío de ramera, astuta de corazón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 11, 'Alborotadora y rencillosa, Sus pies no pueden estar en casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 12, 'Unas veces de fuera, ó bien por las plazas, Acechando por todas las esquinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 13, 'Y traba de él, y bésalo; Desvergonzó su rostro, y díjole:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 14, 'Sacrificios de paz había prometido, Hoy he pagado mis votos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 15, 'Por tanto he salido á encontrarte, Buscando diligentemente tu rostro, y te he hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 16, 'Con paramentos he ataviado mi cama, Recamados con cordoncillo de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 17, 'He sahumado mi cámara Con mirra, áloes, y cinamomo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 18, 'Ven, embriaguémonos de amores hasta la mañana; Alegrémonos en amores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 19, 'Porque el marido no está en casa, Hase ido á un largo viaje:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 20, 'El saco de dinero llevó en su mano; El día señalado volverá á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 21, 'Rindiólo con la mucha suavidad de sus palabras, Obligóle con la blandura de sus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 22, 'Vase en pos de ella luego, Como va el buey al degolladero, Y como el loco á las prisiones para ser castigado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 23, 'Como el ave que se apresura al lazo, Y no sabe que es contra su vida, Hasta que la saeta traspasó su hígado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 24, 'Ahora pues, hijos, oidme, Y estad atentos á las razones de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 25, 'No se aparte á sus caminos tu corazón; No yerres en sus veredas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 26, 'Porque á muchos ha hecho caer heridos; Y aun los más fuertes han sido muertos por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 7, 27, 'Caminos del sepulcro son su casa, Que descienden á las cámaras de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 1, '¿NO clama la sabiduría, Y da su voz la inteligencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 2, 'En los altos cabezos, junto al camino, A las encrucijadas de las veredas se para;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 3, 'En el lugar de las puertas, á la entrada de la ciudad, A la entrada de las puertas da voces:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 4, 'Oh hombres, á vosotros clamo; Y mi voz es á los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 5, 'Entended, simples, discreción; Y vosotros, locos, entrad en cordura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 6, 'Oid, porque hablaré cosas excelentes; Y abriré mis labios para cosas rectas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 7, 'Porque mi boca hablará verdad, Y la impiedad abominan mis labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 8, 'En justicia son todas las razones de mi boca; No hay en ellas cosa perversa ni torcida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 9, 'Todas ellas son rectas al que entiende, Y razonables á los que han hallado sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 10, 'Recibid mi enseñanza, y no plata; Y ciencia antes que el oro escogido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 11, 'Porque mejor es la sabiduría que las piedras preciosas; Y todas las cosas que se pueden desear, no son de comparar con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 12, 'Yo, la sabiduría, habito con la discreción, Y hallo la ciencia de los consejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 13, 'El temor de Jehová es aborrecer el mal; La soberbia y la arrogancia, y el mal camino Y la boca perversa, aborrezco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 14, 'Conmigo está el consejo y el ser; Yo soy la inteligencia; mía es la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 15, 'Por mí reinan los reyes, Y los príncipes determinan justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 16, 'Por mí dominan los príncipes, Y todos los gobernadores juzgan la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 17, 'Yo amo á los que me aman; Y me hallan los que madrugando me buscan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 18, 'Las riquezas y la honra están conmigo; Sólidas riquezas, y justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 19, 'Mejor es mi fruto que el oro, y que el oro refinado; Y mi rédito mejor que la plata escogida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 20, 'Por vereda de justicia guiaré, Por en medio de sendas de juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 21, 'Para hacer heredar á mis amigos el ser, Y que yo hincha sus tesoros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 22, 'Jehová me poseía en el principio de su camino, Ya de antiguo, antes de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 23, 'Eternalmente tuve el principado, desde el principio, Antes de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 24, 'Antes de los abismos fuí engendrada; Antes que fuesen las fuentes de las muchas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 25, 'Antes que los montes fuesen fundados, Antes de los collados, era yo engendrada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 26, 'No había aún hecho la tierra, ni las campiñas, Ni el principio del polvo del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 27, 'Cuando formaba los cielos, allí estaba yo; Cuando señalaba por compás la sobrefaz del abismo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 28, 'Cuando afirmaba los cielos arriba, Cuando afirmaba las fuentes del abismo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 29, 'Cuando ponía á la mar su estatuto, Y á las aguas, que no pasasen su mandamiento; Cuando establecía los fundamentos de la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 30, 'Con él estaba yo ordenándolo todo; Y fuí su delicia todos los días, Teniendo solaz delante de él en todo tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 31, 'Huélgome en la parte habitable de su tierra; Y mis delicias son con los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 32, 'Ahora pues, hijos, oidme: Y bienaventurados los que guardaren mis caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 33, 'Atended el consejo, y sed sabios, Y no lo menospreciéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 34, 'Bienaventurado el hombre que me oye, Velando á mis puertas cada día, Guardando los umbrales de mis entradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 35, 'Porque el que me hallare, hallará la vida, Y alcanzará el favor de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 8, 36, 'Mas el que peca contra mí, defrauda su alma: Todos los que me aborrecen, aman la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 1, 'LA sabiduría edificó su casa, Labró sus siete columnas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 2, 'Mató sus víctimas, templó su vino, Y puso su mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 3, 'Envió sus criadas; Sobre lo más alto de la ciudad clamó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 4, 'Cualquiera simple, venga acá. A los faltos de cordura dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 5, 'Venid, comed mi pan, Y bebed del vino que yo he templado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 6, 'Dejad las simplezas, y vivid; Y andad por el camino de la inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 7, 'El que corrige al escarnecedor, afrenta se acarrea: El que reprende al impío, se atrae mancha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 8, 'No reprendas al escarnecedor, porque no te aborrezca: Corrige al sabio, y te amará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 9, 'Da al sabio, y será más sabio: Enseña al justo, y acrecerá su saber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 10, 'El temor de Jehová es el principio de la sabiduría; Y la ciencia de los santos es inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 11, 'Porque por mí se aumentarán tus días, Y años de vida se te añadirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 12, 'Si fueres sabio, para ti lo serás: Mas si fueres escarnecedor, pagarás tú solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 13, 'La mujer loca es alborotadora; Es simple é ignorante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 14, 'Siéntase en una silla á la puerta de su casa, En lo alto de la ciudad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 15, 'Para llamar á los que pasan por el camino, Que van por sus caminos derechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 16, 'Cualquiera simple, dice, venga acá. A los faltos de cordura dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 17, 'Las aguas hurtadas son dulces, Y el pan comido en oculto es suave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 9, 18, 'Y no saben que allí están los muertos; Que sus convidados están en los profundos de la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 1, '- Las sentencias de Salomón. - EL hijo sabio alegra al padre; Y el hijo necio es tristeza de su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 2, 'Los tesoros de maldad no serán de provecho: Mas la justicia libra de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 3, 'Jehová no dejará hambrear el alma del justo: Mas la iniquidad lanzará á los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 4, 'La mano negligente hace pobre: Mas la mano de los diligentes enriquece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 5, 'El que recoge en el estío es hombre entendido: El que duerme en el tiempo de la siega es hombre afrentoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 6, 'Bendiciones sobre la cabeza del justo: Mas violencia cubrirá la boca de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 7, 'La memoria del justo será bendita: Mas el nombre de los impíos se pudrirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 8, 'El sabio de corazón recibirá los mandamientos: Mas el loco de labios caerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 9, 'El que camina en integridad, anda confiado: Mas el que pervierte sus caminos, será quebrantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 10, 'El que guiña del ojo acarrea tristeza; Y el loco de labios será castigado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 11, 'Vena de vida es la boca del justo: Mas violencia cubrirá la boca de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 12, 'El odio despierta rencillas: Mas la caridad cubrirá todas las faltas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 13, 'En los labios del prudente se halla sabiduría: Y vara á las espaldas del falto de cordura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 14, 'Los sabios guardan la sabiduría: Mas la boca del loco es calamidad cercana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 15, 'Las riquezas del rico son su ciudad fuerte; Y el desmayo de los pobres es su pobreza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 16, 'La obra del justo es para vida; Mas el fruto del impío es para pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 17, 'Camino á la vida es guardar la corrección: Mas el que deja la reprensión, yerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 18, 'El que encubre el odio es de labios mentirosos; Y el que echa mala fama es necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 19, 'En las muchas palabras no falta pecado: Mas el que refrena sus labios es prudente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 20, 'Plata escogida es la lengua del justo: Mas el entendimiento de los impíos es como nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 21, 'Los labios del justo apacientan á muchos: Mas los necios por falta de entendimiento mueren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 22, 'La bendición de Jehová es la que enriquece, Y no añade tristeza con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 23, 'Hacer abominación es como risa al insensato: Mas el hombre entendido sabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 24, 'Lo que el impío teme, eso le vendrá: Mas á los justos les será dado lo que desean.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 25, 'Como pasa el torbellino, así el malo no permanece: Mas el justo, fundado para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 26, 'Como el vinagre á los dientes, y como el humo á los ojos, Así es el perezoso á los que lo envían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 27, 'El temor de Jehová aumentará los días: Mas los años de los impíos serán acortados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 28, 'La esperanza de los justos es alegría; Mas la esperanza de los impíos perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 29, 'Fortaleza es al perfecto el camino de Jehová: Mas espanto es á los que obran maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 30, 'El justo eternalmente no será removido: Mas los impíos no habitarán la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 31, 'La boca del justo producirá sabiduría: Mas la lengua perversa será cortada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 10, 32, 'Los labios del justo conocerán lo que agrada: Mas la boca de los impíos habla perversidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 1, 'EL peso falso abominación es á Jehová: Mas la pesa cabal le agrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 2, 'Cuando viene la soberbia, viene también la deshonra: Mas con los humildes es la sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 3, 'La integridad de los rectos los encaminará: Mas destruirá á los pecadores la perversidad de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 4, 'No aprovecharán las riquezas en el día de la ira: Mas la justicia librará de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 5, 'La justicia del perfecto enderezará su camino: mas el impío por su impiedad caerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 6, 'La justicia de los rectos los librará: Mas los pecadores en su pecado serán presos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 7, 'Cuando muere el hombre impío, perece su esperanza; Y la espectativa de los malos perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 8, 'El justo es librado de la tribulación: Mas el impío viene en lugar suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 9, 'El hipócrita con la boca daña á su prójimo: Mas los justos son librados con la sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 10, 'En el bien de los justos la ciudad se alegra: Mas cuando los impíos perecen, hay fiestas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 11, 'Por la bendición de los rectos la ciudad será engrandecida: Mas por la boca de los impíos ella será trastornada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 12, 'El que carece de entendimiento, menosprecia á su prójimo: Mas el hombre prudente calla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 13, 'El que anda en chismes, descubre el secreto: Mas el de espíritu fiel encubre la cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 14, 'Cuando faltaren las industrias, caerá el pueblo: Mas en la multitud de consejeros hay salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 15, 'Con ansiedad será afligido el que fiare al extraño: Mas el que aborreciere las fianzas vivirá confiado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 16, 'La mujer graciosa tendrá honra: Y los fuertes tendrán riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 17, 'A su alma hace bien el hombre misericordioso: Mas el cruel atormenta su carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 18, 'El impío hace obra falsa: Mas el que sembrare justicia, tendrá galardón firme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 19, 'Como la justicia es para vida, Así el que sigue el mal es para su muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 20, 'Abominación son á Jehová los perversos de corazón: Mas los perfectos de camino le son agradables.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 21, 'Aunque llegue la mano á la mano, el malo no quedará sin castigo: Mas la simiente de los justos escapará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 22, 'Zarcillo de oro en la nariz del puerco, Es la mujer hermosa y apartada de razón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 23, 'El deseo de los justos es solamente bien: Mas la esperanza de los impíos es enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 24, 'Hay quienes reparten, y les es añadido más: Y hay quienes son escasos más de lo que es justo, mas vienen á pobreza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 25, 'El alma liberal será engordada: Y el que saciare, él también será saciado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 26, 'Al que retiene el grano, el pueblo lo maldecirá: Mas bendición será sobre la cabeza del que vende.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 27, 'El que madruga al bien, buscará favor: Mas el que busca el mal, vendrále.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 28, 'El que confía en sus riquezas, caerá: Mas los justos reverdecerán como ramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 29, 'El que turba su casa heredará viento; Y el necio será siervo del sabio de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 30, 'El fruto del justo es árbol de vida: Y el que prende almas, es sabio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 11, 31, 'Ciertamente el justo será pagado en la tierra: ¡Cuánto más el impío y el pecador!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 1, 'EL que ama la corrección ama la sabiduría: Mas el que aborrece la reprensión, es ignorante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 2, 'El bueno alcanzará favor de Jehová: Mas él condenará al hombre de malos pensamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 3, 'El hombre no se afirmará por medio de la impiedad: Mas la raíz de los justos no será movida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 4, 'La mujer virtuosa corona es de su marido: Mas la mala, como carcoma en sus huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 5, 'Los pensamientos de los justos son rectitud; Mas los consejos de los impíos, engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 6, 'Las palabras de los impíos son para acechar la sangre: Mas la boca de los rectos los librará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 7, 'Dios trastornará á los impíos, y no serán más: Mas la casa de los justos permanecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 8, 'Según su sabiduría es alabado el hombre: Mas el perverso de corazón será en menosprecio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 9, 'Mejor es el que es menospreciado y tiene servidores, Que el que se precia, y carece de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 10, 'El justo atiende á la vida de su bestia: Mas las entrañas de los impíos son crueles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 11, 'El que labra su tierra, se hartará de pan: Mas el que sigue los vagabundos es falto de entendimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 12, 'Desea el impío la red de los malos: Mas la raíz de los justos dará fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 13, 'El impío es enredado en la prevaricación de sus labios: Mas el justo saldrá de la tribulación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 14, 'El hombre será harto de bien del fruto de su boca: Y la paga de las manos del hombre le será dada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 15, 'El camino del necio es derecho en su opinión: Mas el que obedece al consejo es sabio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 16, 'El necio luego al punto da á conocer su ira: Mas el que disimula la injuria es cuerdo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 17, 'El que habla verdad, declara justicia; Mas el testigo mentiroso, engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 18, 'Hay quienes hablan como dando estocadas de espada: Mas la lengua de los sabios es medicina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 19, 'El labio de verdad permanecerá para siempre: Mas la lengua de mentira por un momento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 20, 'Engaño hay en el corazón de los que piensan mal: Mas alegría en el de los que piensan bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 21, 'Ninguna adversidad acontecerá al justo: Mas los impíos serán llenos de mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 22, 'Los labios mentirosos son abominación á Jehová: Mas los obradores de verdad su contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 23, 'El hombre cuerdo encubre la ciencia: Mas el corazón de los necios publica la necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 24, 'La mano de los diligentes se enseñoreará: Mas la negligencia será tributaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 25, 'El cuidado congojoso en el corazón del hombre, lo abate; Mas la buena palabra lo alegra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 26, 'El justo hace ventaja á su prójimo: Mas el camino de los impíos les hace errar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 27, 'El indolente no chamuscará su caza: Mas el haber precioso del hombre es la diligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 12, 28, 'En el camino de la justicia está la vida; Y la senda de su vereda no es muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 1, 'EL hijo sabio toma el consejo del padre: Mas el burlador no escucha las reprensiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 2, 'Del fruto de su boca el hombre comerá bien: Mas el alma de los prevaricadores hallará mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 3, 'El que guarda su boca guarda su alma: Mas el que mucho abre sus labios tendrá calamidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 4, 'Desea, y nada alcanza el alma del perezoso: Mas el alma de los diligentes será engordada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 5, 'El justo aborrece la palabra de mentira: Mas el impío se hace odioso é infame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 6, 'La justicia guarda al de perfecto camino: Mas la impiedad trastornará al pecador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 7, 'Hay quienes se hacen ricos, y no tienen nada: Y hay quienes se hacen pobres, y tienen muchas riquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 8, 'La redención de la vida del hombre son sus riquezas: Pero el pobre no oye censuras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 9, 'La luz de los justos se alegrará: Mas apagaráse la lámpara de los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 10, 'Ciertamente la soberbia parirá contienda: Mas con los avisados es la sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 11, 'Disminuiránse las riquezas de vanidad: Empero multiplicará el que allega con su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 12, 'La esperanza que se prolonga, es tormento del corazón: Mas árbol de vida es el deseo cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 13, 'El que menosprecia la palabra, perecerá por ello: Mas el que teme el mandamiento, será recompensado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 14, 'la ley del sabio es manantial de vida, Para apartarse de los lazos de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 15, 'El buen entendimiento conciliará gracia: Mas el camino de los prevaricadores es duro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 16, 'Todo hombre cuerdo obra con sabiduría: Mas el necio manifestará necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 17, 'El mal mensajero caerá en mal: Mas el mensajero fiel es medicina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 18, 'Pobreza y vergüenza tendrá el que menosprecia el consejo: Mas el que guarda la corrección, será honrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 19, 'El deseo cumplido deleita el alma: Pero apartarse del mal es abominación á los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 20, 'El que anda con los sabios, sabio será; Mas el que se allega á los necios, será quebrantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 21, 'Mal perseguirá á los pecadores: Mas á los justos les será bien retribuído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 22, 'El bueno dejará herederos á los hijos de los hijos; Y el haber del pecador, para el justo está guardado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 23, 'En el barbecho de los pobres hay mucho pan: Mas piérdese por falta de juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 24, 'El que detiene el castigo, á su hijo aborrece: Mas el que lo ama, madruga á castigarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 13, 25, 'El justo come hasta saciar su alma: Mas el vientre de los impíos tendrá necesidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 1, 'LA mujer sabia edifica su casa: Mas la necia con sus manos la derriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 2, 'El que camina en su rectitud teme á Jehová: Mas el pervertido en sus caminos lo menosprecia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 3, 'En la boca del necio está la vara de la soberbia: Mas los labios de los sabios los guardarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 4, 'Sin bueyes el granero está limpio: Mas por la fuerza del buey hay abundancia de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 5, 'El testigo verdadero no mentirá: Mas el testigo falso hablará mentiras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 6, 'Busca el escarnecedor la sabiduría, y no la halla: Mas la sabiduría al hombre entendido es fácil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 7, 'Vete de delante del hombre necio, Porque en él no advertirás labios de ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 8, 'La ciencia del cuerdo es entender su camino: Mas la indiscreción de los necios es engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 9, 'Los necios se mofan del pecado: Mas entre los rectos hay favor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 10, 'El corazón conoce la amargura de su alma; Y extraño no se entrometerá en su alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 11, 'La casa de los impíos será asolada: Mas florecerá la tienda de los rectos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 12, 'Hay camino que al hombre parece derecho; Empero su fin son caminos de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 13, 'Aun en la risa tendrá dolor el corazón; Y el término de la alegría es congoja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 14, 'De sus caminos será harto el apartado de razón: Y el hombre de bien estará contento del suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 15, 'El simple cree á toda palabra: Mas el avisado entiende sus pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 16, 'El sabio teme, y se aparta del mal: Mas el necio se arrebata, y confía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 17, 'El que presto se enoja, hará locura: Y el hombre malicioso será aborrecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 18, 'Los simples heredarán necedad: Mas los cuerdos se coronarán de sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 19, 'Los malos se inclinarán delante de los buenos, Y los impíos á las puertas del justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 20, 'El pobre es odioso aun á su amigo: Pero muchos son los que aman al rico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 21, 'Peca el que menosprecia á su prójimo: Mas el que tiene misericordia de los pobres, es bienaventurado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 22, '¿No yerran los que piensan mal? Misericordia empero y verdad alcanzarán los que piensan bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 23, 'En toda labor hay fruto: Mas la palabra de los labios solamente empobrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 24, 'Las riquezas de los sabios son su corona: Mas es infatuación la insensatez de los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 25, 'El testigo verdadero libra las almas: Mas el engañoso hablará mentiras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 26, 'En el temor de Jehová está la fuerte confianza; Y esperanza tendrán sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 27, 'El temor de Jehová es manantial de vida, Para apartarse de los lazos de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 28, 'En la multitud de pueblo está la gloria del rey: Y en la falta de pueblo la flaqueza del príncipe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 29, 'El que tarde se aira, es grande de entendimiento: Mas el corto de espíritu engrandece el desatino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 30, 'El corazón apacible es vida de las carnes: Mas la envidia, pudrimiento de huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 31, 'El que oprime al pobre, afrenta á su Hacedor: Mas el que tiene misericordia del pobre, lo honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 32, 'Por su maldad será lanzado el impío: Mas el justo en su muerte tiene esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 33, 'En el corazón del cuerdo reposa la sabiduría; Y es conocida en medio de los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 34, 'La justicia engrandece la nación: Mas el pecado es afrenta de las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 14, 35, 'La benevolencia del rey es para con el ministro entendido: Mas su enojo contra el que lo avergüenza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 1, 'LA blanda respuesta quita la ira: Mas la palabra áspera hace subir el furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 2, 'La lengua de los sabios adornará la sabiduría: Mas la boca de los necios hablará sandeces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 3, 'Los ojos de Jehová están en todo lugar, Mirando á los malos y á los buenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 4, 'La sana lengua es árbol de vida: Mas la perversidad en ella es quebrantamiento de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 5, 'El necio menosprecia el consejo de su padre: Mas el que guarda la corrección, vendrá á ser cuerdo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 6, 'En la casa del justo hay gran provisión; Empero turbación en las ganancias del impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 7, 'Los labios de los sabios esparcen sabiduría: Mas no así el corazón de los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 8, 'El sacrificio de los impíos es abominación á Jehová: Mas la oración de los rectos es su gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 9, 'Abominación es á Jehová el camino del impío: Mas él ama al que sigue justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 10, 'La reconvención es molesta al que deja el camino: Y el que aborreciere la corrección, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 11, 'El infierno y la perdición están delante de Jehová: ¡Cuánto más los corazones de los hombres!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 12, 'El escarnecedor no ama al que le reprende; Ni se allega á los sabios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 13, 'El corazón alegre hermosea el rostro: Mas por el dolor de corazón el espíritu se abate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 14, 'El corazón entendido busca la sabiduría: Mas la boca de los necios pace necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 15, 'Todos los días del afligido son trabajosos: Mas el de corazón contento tiene un convite continuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 16, 'Mejor es lo poco con el temor de Jehová, Que el gran tesoro donde hay turbación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 17, 'Mejor es la comida de legumbres donde hay amor, Que de buey engordado donde hay odio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 18, 'El hombre iracundo mueve contiendas: Mas el que tarde se enoja, apaciguará la rencilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 19, 'El camino del perezoso es como seto de espinos: Mas la vereda de los rectos como una calzada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 20, 'El hijo sabio alegra al padre: Mas el hombre necio menosprecia á su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 21, 'La necedad es alegría al falto de entendimiento: Mas el hombre entendido enderezará su proceder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 22, 'Los pensamientos son frustrados donde no hay consejo; Mas en la multitud de consejeros se afirman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 23, 'Alégrase el hombre con la respuesta de su boca: Y la palabra á su tiempo, ¡cuán buena es!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 24, 'El camino de la vida es hacia arriba al entendido, Para apartarse del infierno abajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 25, 'Jehová asolará la casa de los soberbios: Mas él afirmará el término de la viuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 26, 'Abominación son á Jehová los pensamientos del malo: Mas las expresiones de los limpios son limpias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 27, 'Alborota su casa el codicioso: Mas el que aborrece las dádivas vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 28, 'El corazón del justo piensa para responder: Mas la boca de los impíos derrama malas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 29, 'Lejos está Jehová de los impíos: Mas él oye la oración de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 30, 'La luz de los ojos alegra el corazón; Y la buena fama engorda los huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 31, 'La oreja que escucha la corrección de vida, Entre los sabios morará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 32, 'El que tiene en poco la disciplina, menosprecia su alma: Mas el que escucha la corrección, tiene entendimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 15, 33, 'El temor de Jehová es enseñanza de sabiduría: Y delante de la honra está la humildad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 1, 'DEL hombre son las disposiciones del corazón: Mas de Jehová la respuesta de la lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 2, 'Todos los caminos del hombre son limpios en su opinión: Mas Jehová pesa los espíritus.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 3, 'Encomienda á Jehová tus obras, Y tus pensamientos serán afirmados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 4, 'Todas las cosas ha hecho Jehová por sí mismo, Y aun al impío para el día malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 5, 'Abominación es á Jehová todo altivo de corazón: Aunque esté mano sobre mano, no será reputado inocente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 6, 'Con misericordia y verdad se corrige el pecado: Y con el temor de Jehová se apartan del mal los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 7, 'Cuando los caminos del hombre son agradables á Jehová, Aun á sus enemigos pacificará con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 8, 'Mejor es lo poco con justicia, Que la muchedumbre de frutos sin derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 9, 'El corazón del hombre piensa su camino: Mas Jehová endereza sus pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 10, 'Adivinación está en los labios del rey: En juicio no prevaricará su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 11, 'Peso y balanzas justas son de Jehová: Obra suya son todas las pesas de la bolsa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 12, 'Abominación es á los reyes hacer impiedad: Porque con justicia será afirmado el trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 13, 'Los labios justos son el contentamiento de los reyes; Y aman al que habla lo recto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 14, 'La ira del rey es mensajero de muerte: Mas el hombre sabio la evitará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 15, 'En la alegría del rostro del rey está la vida; Y su benevolencia es como nube de lluvia tardía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 16, 'Mejor es adquirir sabiduría que oro preciado; Y adquirir inteligencia vale más que la plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 17, 'El camino de los rectos es apartarse del mal: Su alma guarda el que guarda su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 18, 'Antes del quebrantamiento es la soberbia; Y antes de la caída la altivez de espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 19, 'Mejor es humillar el espíritu con los humildes, Que partir despojos con los soberbios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 20, 'El entendido en la palabra, hallará el bien: Y el que confía en Jehová, él es bienaventurado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 21, 'El sabio de corazón es llamado entendido: Y la dulzura de labios aumentará la doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 22, 'Manantial de vida es el entendimiento al que lo posee: Mas la erudición de los necios es necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 23, 'El corazón del sabio hace prudente su boca; Y con sus labios aumenta la doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 24, 'Panal de miel son los dichos suaves. Suavidad al alma y medicina á los huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 25, 'Hay camino que parece derecho al hombre, Mas su salida son caminos de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 26, 'El alma del que trabaja, trabaja para sí; Porque su boca le constriñe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 27, 'El hombre perverso cava el mal; Y en sus labios hay como llama de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 28, 'El hombre perverso levanta contienda; Y el chismoso aparta los mejores amigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 29, 'El hombre malo lisonjea á su prójimo, Y le hace andar por el camino no bueno:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 30, 'Cierra sus ojos para pensar perversidades; Mueve sus labios, efectúa el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 31, 'Corona de honra es la vejez, Que se hallará en el camino de justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 32, 'Mejor es el que tarde se aira que el fuerte; Y el que se enseñorea de su espíritu, que el que toma una ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 16, 33, 'La suerte se echa en el seno: Mas de Jehová es el juicio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 1, 'MEJOR es un bocado seco, y en paz, Que la casa de contienda llena de víctimas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 2, 'El siervo prudente se enseñoreará del hijo que deshonra, Y entre los hermanos partirá la herencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 3, 'El crisol para la plata, y la hornaza para el oro: Mas Jehová prueba los corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 4, 'El malo está atento al labio inicuo; Y el mentiroso escucha á la lengua detractora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 5, 'El que escarnece al pobre, afrenta á su Hacedor: Y el que se alegra en la calamidad, no quedará sin castigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 6, 'Corona de los viejos son los hijos de los hijos; Y la honra de los hijos, sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 7, 'No conviene al necio la altilocuencia: ¡Cuánto menos al príncipe el labio mentiroso!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 8, 'Piedra preciosa es el cohecho en ojos de sus dueños: A donde quiera que se vuelve, da prosperidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 9, 'El que cubre la prevaricación, busca amistad: Mas el que reitera la palabra, aparta al amigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 10, 'Aprovecha la reprensión en el entendido, Más que si cien veces hiriese en el necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 11, 'El rebelde no busca sino mal; Y mensajero cruel será contra él enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 12, 'Mejor es se encuentre un hombre con una osa á la cual han robado sus cachorros, Que con un fatuo en su necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 13, 'El que da mal por bien, No se apartará el mal de su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 14, 'El que comienza la pendencia es como quien suelta las aguas: Deja pues la porfía, antes que se enmarañe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 15, 'El que justifica al impío, y el que condena al justo, Ambos á dos son abominación á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 16, '¿De qué sirve el precio en la mano del necio para comprar sabiduría, No teniendo entendimiento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 17, 'En todo tiempo ama el amigo; Y el hermano para la angustia es nacido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 18, 'El hombre falto de entendimiento toca la mano, Fiando á otro delante de su amigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 19, 'La prevaricación ama el que ama pleito; Y el que alza su portada, quebrantamiento busca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 20, 'El perverso de corazón nunca hallará bien: Y el que revuelve con su lengua, caerá en mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 21, 'El que engendra al necio, para su tristeza lo engendra: Y el padre del fatuo no se alegrará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 22, 'El corazón alegre produce buena disposición: Mas el espíritu triste seca los huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 23, 'El impío toma dádiva del seno Para pervertir las sendas del derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 24, 'En el rostro del entendido aparece la sabiduría: Mas los ojos del necio vagan hasta el cabo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 25, 'El hijo necio es enojo á su padre, Y amargura á la que lo engendró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 26, 'Ciertamente no es bueno condenar al justo, Ni herir á los príncipes que hacen lo recto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 27, 'Detiene sus dichos el que tiene sabiduría: De prudente espíritu es el hombre entendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 17, 28, 'Aun el necio cuando calla, es contado por sabio: El que cierra sus labios es entendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 1, 'SEGUN su antojo busca el que se desvía, Y se entremete en todo negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 2, 'No toma placer el necio en la inteligencia, Sino en lo que su corazón se descubre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 3, 'Cuando viene el impío, viene también el menosprecio, Y con el deshonrador la afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 4, 'Aguas profundas son las palabras de la boca del hombre; Y arroyo revertiente, la fuente de la sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 5, 'Tener respeto á la persona del impío, Para hacer caer al justo de su derecho, no es bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 6, 'Los labios del necio vienen con pleito; Y su boca á cuestiones llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 7, 'La boca del necio es quebrantamiento para sí, Y sus labios son lazos para su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 8, 'Las palabras del chismoso parecen blandas, Y descienden hasta lo íntimo del vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 9, 'También el que es negligente en su obra Es hermano del hombre disipador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 10, 'Torre fuerte es el nombre de Jehová: A él correrá el justo, y será levantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 11, 'Las riquezas del rico son la ciudad de su fortaleza, Y como un muro alto en su imaginación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 12, 'Antes del quebrantamiento se eleva el corazón del hombre, Y antes de la honra es el abatimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 13, 'El que responde palabra antes de oir, Le es fatuidad y oprobio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 14, 'El ánimo del hombre soportará su enfermedad: Mas ¿quién soportará al ánimo angustiado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 15, 'El corazón del entendido adquiere sabiduría; Y el oído de los sabios busca la ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 16, 'El presente del hombre le ensancha el camino, Y le lleva delante de los grandes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 17, 'El primero en su propia causa parece justo; Y su adversario viene, y le sondea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 18, 'La suerte pone fin á los pleitos, Y desparte los fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 19, 'El hermano ofendido es más tenaz que una ciudad fuerte: Y las contiendas de los hermanos son como cerrojos de alcázar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 20, 'Del fruto de la boca del hombre se hartará su vientre; Hartaráse del producto de sus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 21, 'La muerte y la vida están en poder de la lengua; Y el que la ama comerá de sus frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 22, 'El que halló esposa halló el bien, Y alcanzó la benevolencia de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 23, 'El pobre habla con ruegos; Mas el rico responde durezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 18, 24, 'El hombre que tiene amigos, ha de mostrarse amigo: Y amigo hay más conjunto que el hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 1, 'MEJOR es el pobre que camina en su sencillez, Que el de perversos labios y fatuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 2, 'El alma sin ciencia no es buena; Y el presuroso de pies peca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 3, 'La insensatez del hombre tuerce su camino; Y contra Jehová se aira su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 4, 'Las riquezas allegan muchos amigos: Mas el pobre, de su amigo es apartado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 5, 'El testigo falso no quedará sin castigo; Y el que habla mentiras no escapará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 6, 'Muchos rogarán al príncipe: Mas cada uno es amigo del hombre que da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 7, 'Todos los hermanos del pobre le aborrecen: ¡Cuánto más sus amigos se alejarán de él! Buscará la palabra y no la hallará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 8, 'El que posee entendimiento, ama su alma: El que guarda la inteligencia, hallará el bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 9, 'El testigo falso no quedará sin castigo; Y el que habla mentiras, perecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 10, 'No conviene al necio el deleite: ¡Cuánto menos al siervo ser señor de los príncipes!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 11, 'La cordura del hombre detiene su furor; Y su honra es disimular la ofensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 12, 'Como el bramido del cachorro de león es la ira del rey; Y su favor como el rocío sobre la hierba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 13, 'Dolor es para su padre el hijo necio; Y gotera continua las contiendas de la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 14, 'La casa y las riquezas herencia son de los padres: Mas de Jehová la mujer prudente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 15, 'La pereza hace caer en sueño; Y el alma negligente hambreará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 16, 'El que guarda el mandamiento, guarda su alma: Mas el que menospreciare sus caminos, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 17, 'A Jehová empresta el que da al pobre, Y él le dará su paga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 18, 'Castiga á tu hijo en tanto que hay esperanza; Mas no se excite tu alma para destruirlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 19, 'El de grande ira llevará la pena: Y si usa de violencias, añadirá nuevos males.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 20, 'Escucha el consejo, y recibe la corrección, Para que seas sabio en tu vejez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 21, 'Muchos pensamientos hay en el corazón del hombre; Mas el consejo de Jehová permanecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 22, 'Contentamiento es á los hombres hacer misericordia: Pero mejor es el pobre que el mentiroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 23, 'El temor de Jehová es para vida; Y con él vivirá el hombre, lleno de reposo; No será visitado de mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 24, 'El perezoso esconde su mano en el seno: Aun á su boca no la llevará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 25, 'Hiere al escarnecedor, y el simple se hará avisado; Y corrigiendo al entendido, entenderá ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 26, 'El que roba á su padre y ahuyenta á su madre, Hijo es avergonzador y deshonrador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 27, 'Cesa, hijo mío, de oir la enseñanza Que induce á divagar de las razones de sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 28, 'El testigo perverso se burlará del juicio; Y la boca de los impíos encubrirá la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 19, 29, 'Aparejados están juicios para los escarnecedores, Y azotes para los cuerpos de los insensatos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 1, 'EL vino es escarnecedor, la cerveza alborotadora; Y cualquiera que por ello errare, no será sabio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 2, 'Como bramido de cachorro de león es el terror del rey: El que lo hace enfurecerse, peca contra su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 3, 'Honra es del hombre dejarse de contienda: Mas todo insensato se envolverá en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 4, 'El perezoso no ara á causa del invierno; Pedirá pues en la siega, y no hallará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 5, 'Como aguas profundas es el consejo en el corazón del hombre: Mas el hombre entendido lo alcanzará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 6, 'Muchos hombres publican cada uno su liberalidad: Mas hombre de verdad, ¿quién lo hallará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 7, 'El justo que camina en su integridad, Bienaventurados serán sus hijos después de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 8, 'El rey que se sienta en el trono de juicio, Con su mirar disipa todo mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 9, '¿Quién podrá decir: Yo he limpiado mi corazón, Limpio estoy de mi pecado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 10, 'Doble pesa y doble medida, Abominación son á Jehová ambas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 11, 'Aun el muchacho es conocido por sus hechos, Si su obra fuere limpia y recta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 12, 'El oído que oye, y el ojo que ve, Ambas cosas ha igualmente hecho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 13, 'No ames el sueño, porque no te empobrezcas; Abre tus ojos, y te hartarás de pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 14, 'El que compra dice: Malo es, malo es: Mas en apartándose, se alaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 15, 'Hay oro y multitud de piedras preciosas: Mas los labios sabios son vaso precioso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 16, 'Quítale su ropa al que salió por fiador del extraño; Y tómale prenda al que fía la extraña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 17, 'Sabroso es al hombre el pan de mentira; Mas después su boca será llena de cascajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 18, 'Los pensamientos con el consejo se ordenan: Y con industria se hace la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 19, 'El que descubre el secreto, en chismes anda: No te entrometas, pues, con el que lisonjea con sus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 20, 'El que maldice á su padre ó á su madre, Su lámpara será apagada en oscuridad tenebrosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 21, 'La herencia adquirida de priesa al principio, Aun su postrimería no será bendita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 22, 'No digas, yo me vengaré; Espera á Jehová, y él te salvará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 23, 'Abominación son á Jehová las pesas dobles; Y el peso falso no es bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 24, 'De Jehová son los pasos del hombre: ¿Cómo pues entenderá el hombre su camino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 25, 'Lazo es al hombre el devorar lo santo, Y andar pesquisando después de los votos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 26, 'El rey sabio esparce los impíos. Y sobre ellos hace tornar la rueda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 27, 'Candela de Jehová es el alma del hombre, Que escudriña lo secreto del vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 28, 'Misericordia y verdad guardan al rey; Y con clemencia sustenta su trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 29, 'La gloria de los jóvenes es su fortaleza, Y la hermosura de los viejos la vejez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 20, 30, 'Las señales de las heridas son medicina para lo malo: Y las llagas llegan á lo más secreto del vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 1, 'COMO los repartimientos de las aguas, así está el corazón del rey en la mano de Jehová: A todo lo que quiere lo inclina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 2, 'Todo camino del hombre es recto en su opinión: Mas Jehová pesa los corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 3, 'Hacer justicia y juicio es á Jehová Más agradable que sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 4, 'Altivez de ojos, y orgullo de corazón, Y el brillo de los impíos, son pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 5, 'Los pensamientos del solícito ciertamente van á abundancia; Mas todo presuroso, indefectiblemente á pobreza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 6, 'Allegar tesoros con lengua de mentira, Es vanidad desatentada de aquellos que buscan la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 7, 'La rapiña de los impíos los destruirá; Por cuanto no quisieron hacer juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 8, 'El camino del hombre perverso es torcido y extraño: Mas la obra del limpio es recta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 9, 'Mejor es vivir en un rincón de zaquizamí. Que con la mujer rencillosa en espaciosa casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 10, 'El alma del impío desea mal: Su prójimo no le parece bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 11, 'Cuando el escarnecedor es castigado, el simple se hace sabio; Y cuando se amonestare al sabio, aprenderá ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 12, 'Considera el justo la casa del impío: Cómo los impíos son trastornados por el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 13, 'El que cierra su oído al clamor del pobre, También él clamará, y no será oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 14, 'El presente en secreto amansa el furor, Y el don en el seno, la fuerte ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 15, 'Alegría es al justo hacer juicio; Mas quebrantamiento á los que hacen iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 16, 'El hombre que se extravía del camino de la sabiduría, Vendrá á parar en la compañía de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 17, 'Hombre necesitado será el que ama el deleite: Y el que ama el vino y ungüentos no enriquecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 18, 'El rescate del justo es el impío, Y por los rectos el prevaricador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 19, 'Mejor es morar en tierra del desierto, Que con la mujer rencillosa é iracunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 20, 'Tesoro codiciable y pingüe hay en la casa del sabio; Mas el hombre insensato lo disipará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 21, 'El que sigue la justicia y la misericordia, Hallará la vida, la justicia, y la honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 22, 'La ciudad de los fuertes tomó el sabio, Y derribó la fuerza en que ella confiaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 23, 'El que guarda su boca y su lengua, Su alma guarda de angustias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 24, 'Soberbio y presuntuoso escarnecedor es el nombre Del que obra con orgullosa saña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 25, 'El deseo del perezoso le mata, Porque sus manos no quieren trabajar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 26, 'Hay quien todo el día codicia: Mas el justo da, y no desperdicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 27, 'El sacrificio de los impíos es abominación: ¡Cuánto más ofreciéndolo con maldad!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 28, 'El testigo mentiroso perecerá: Mas el hombre que oye, permanecerá en su dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 29, 'El hombre impío afirma rostro: Mas el recto ordena sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 30, 'No hay sabiduría, ni inteligencia, Ni consejo, contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 21, 31, 'El caballo se apareja para el día de la batalla: Mas de Jehová es el salvar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 1, 'DE más estima es la buena fama que las muchas riquezas; Y la buena gracia más que la plata y el oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 2, 'El rico y el pobre se encontraron: A todos ellos hizo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 3, 'El avisado ve el mal, y escóndese: Mas los simples pasan, y reciben el daño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 4, 'Riquezas, y honra, y vida, Son la remuneración de la humildad y del temor de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 5, 'Espinas y lazos hay en el camino del perverso: El que guarda su alma se alejará de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 6, 'Instruye al niño en su carrera: Aun cuando fuere viejo no se apartará de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 7, 'El rico se enseñoreará de los pobres; Y el que toma prestado, siervo es del que empresta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 8, 'El que sembrare iniquidad, iniquidad segará: Y consumiráse la vara de su ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 9, 'El ojo misericordioso será bendito, Porque dió de su pan al indigente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 10, 'Echa fuera al escarnecedor, y saldrá la contienda, Y cesará el pleito y la afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 11, 'El que ama la limpieza de corazón, Por la gracia de sus labios su amigo será el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 12, 'Los ojos de Jehová miran por la ciencia; Mas él trastorna las cosas de los prevaricadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 13, 'Dice el perezoso: El león está fuera; En mitad de las calles seré muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 14, 'Sima profunda es la boca de las extrañas: Aquel contra el cual estuviere Jehová airado, caerá en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 15, 'La necedad está ligada en el corazón del muchacho; Mas la vara de la corrección la hará alejar de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 16, 'El que oprime al pobre para aumentarse él, Y que da al rico, ciertamente será pobre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 17, 'Inclina tu oído, y oye las palabras de los sabios, Y pon tu corazón á mi sabiduría:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 18, 'Porque es cosa deleitable, si las guardares en tus entrañas; Y que juntamente sean ordenadas en tus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 19, 'Para que tu confianza sea en Jehová, Te las he hecho saber hoy á ti también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 20, '¿No te he escrito tres veces En consejos y ciencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 21, 'Para hacerte saber la certidumbre de las razones verdaderas, Para que puedas responder razones de verdad á los que á ti enviaren?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 22, 'No robes al pobre, porque es pobre, Ni quebrantes en la puerta al afligido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 23, 'Porque Jehová juzgará la causa de ellos, Y despojará el alma de aquellos que los despojaren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 24, 'No te entrometas con el iracundo, Ni te acompañes con el hombre de enojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 25, 'Porque no aprendas sus maneras, Y tomes lazo para tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 26, 'No estés entre los que tocan la mano, Entre los que fían por deudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 27, 'Si no tuvieres para pagar, ¿Por qué han de quitar tu cama de debajo de ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 28, 'No traspases el término antiguo Que pusieron tus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 22, 29, '¿Has visto hombre solícito en su obra? delante de los reyes estará; No estará delante de los de baja suerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 1, 'CUANDO te sentares á comer con algún señor, Considera bien lo que estuviere delante de ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 2, 'Y pon cuchillo á tu garganta, Si tienes gran apetito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 3, 'No codicies sus manjares delicados, Porque es pan engañoso');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 4, 'No trabajes por ser rico; Pon coto á tu prudencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 5, '¿Has de poner tus ojos en las riquezas, siendo ningunas? Porque hacerse han alas, Como alas de águila, y volarán al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 6, 'No comas pan de hombre de mal ojo, Ni codicies sus manjares:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 7, 'Porque cual es su pensamiento en su alma, tal es él. Come y bebe, te dirá; Mas su corazón no está contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 8, 'Vomitarás la parte que tú comiste, Y perderás tus suaves palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 9, 'No hables á oídos del necio; Porque menospreciará la prudencia de tus razones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 10, 'No traspases el término antiguo, Ni entres en la heredad de los huérfanos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 11, 'Porque el defensor de ellos es el Fuerte, El cual juzgará la causa de ellos contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 12, 'Aplica tu corazón á la enseñanza, Y tus oídos á las palabras de sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 13, 'No rehuses la corrección del muchacho: Porque si lo hirieres con vara, no morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 14, 'Tú lo herirás con vara, Y librarás su alma del infierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 15, 'Hijo mío, si tu corazón fuere sabio, También á mí se me alegrará el corazón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 16, 'Mis entrañas también se alegrarán, Cuando tus labios hablaren cosas rectas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 17, 'No tenga tu corazón envidia de los pecadores, Antes persevera en el temor de Jehová todo tiempo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 18, 'Porque ciertamente hay fin, Y tu esperanza no será cortada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 19, 'Oye tú, hijo mío, y sé sabio, Y endereza tu corazón al camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 20, 'No estés con los bebedores de vino, Ni con los comedores de carne:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 21, 'Porque el bebedor y el comilón empobrecerán: Y el sueño hará vestir vestidos rotos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 22, 'Oye á tu padre, á aquel que te engendró; Y cuando tu madre envejeciere, no la menosprecies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 23, 'Compra la verdad, y no la vendas; La sabiduría, la enseñanza, y la inteligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 24, 'Mucho se alegrará el padre del justo: Y el que engendró sabio se gozará con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 25, 'Alégrense tu padre y tu madre, Y gócese la que te engendró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 26, 'Dame, hijo mío, tu corazón, Y miren tus ojos por mis caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 27, 'Porque sima profunda es la ramera, Y pozo angosto la extraña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 28, 'También ella, como robador, acecha, Y multiplica entre los hombres los prevaricadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 29, '¿Para quién será el ay? ¿para quién el ay? ¿para quién las rencillas? ¿Para quién las quejas? ¿para quién las heridas en balde? ¿Para quién lo amoratado de los ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 30, 'Fkpara los que se detienen mucho en el vino, Para los que van buscando la mistura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 31, 'No mires al vino cuando rojea, Cuando resplandece su color en el vaso: Entrase suavemente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 32, 'Mas al fin como serpiente morderá, Y como basilisco dará dolor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 33, 'Tus ojos mirarán las extrañas, Y tu corazón hablará perversidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 34, 'Y serás como el que yace en medio de la mar, O como el que está en la punta de un mastelero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 23, 35, 'Y dirás: Hiriéronme, mas no me dolió; Azotáronme, mas no lo sentí; Cuando despertare, aun lo tornaré á buscar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 1, 'NO tengas envidia de los hombres malos, Ni desees estar con ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 2, 'Porque su corazón piensa en robar, E iniquidad hablan sus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 3, 'Con sabiduría se edificará la casa, Y con prudencia se afirmará;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 4, 'Y con ciencia se henchirán las cámaras De todo bien preciado y agradable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 5, 'El hombre sabio es fuerte; Y de pujante vigor el hombre docto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 6, 'Porque con ingenio harás la guerra: Y la salud está en la multitud de consejeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 7, 'Alta está para el insensato la sabiduría: En la puerta no abrirá él su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 8, 'Al que piensa mal hacer Le llamarán hombre de malos pensamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 9, 'El pensamiento del necio es pecado: Y abominación á los hombres el escarnecedor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 10, 'Si fueres flojo en el día de trabajo, Tu fuerza será reducida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 11, 'Si dejares de librar los que son tomados para la muerte, Y los que son llevados al degolladero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 12, 'Si dijeres: Ciertamente no lo supimos; ¿No lo entenderá el que pesa los corazones? El que mira por tu alma, él lo conocerá, Y dará al hombre según sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 13, 'Come, hijo mío, de la miel, porque es buena, Y del panal dulce á tu paladar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 14, 'Tal será el conocimiento de la sabiduría á tu alma: Si la hallares tendrá recompensa, Y al fin tu esperanza no será cortada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 15, 'Oh impío, no aceches la tienda del justo, No saquees su cámara;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 16, 'Porque siete veces cae el justo, y se torna á levantar; Mas los impíos caerán en el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 17, 'Cuando cayere tu enemigo, no te huelgues; Y cuando tropezare, no se alegre tu corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 18, 'Porque Jehová no lo mire, y le desagrade, Y aparte de sobre él su enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 19, 'No te entrometas con los malignos, Ni tengas envidia de los impíos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 20, 'Porque para el malo no habrá buen fin, Y la candela de los impíos será apagada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 21, 'Teme á Jehová, hijo mío, y al rey; No te entrometas con los veleidosos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 22, 'Porque su quebrantamiento se levantará de repente; Y el quebrantamiento de ambos, ¿quién lo comprende?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 23, 'También estas cosas pertenecen á los sabios. Tener respeto á personas en el juicio no es bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 24, 'El que dijere al malo, Justo eres, Los pueblos lo maldecirán, y le detestarán las naciones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 25, 'Mas los que lo reprenden, serán agradables, Y sobre ellos vendrá bendición de bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 26, 'Besados serán los labios Del que responde palabras rectas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 27, 'Apresta tu obra de afuera, Y disponla en tu heredad; Y después edificarás tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 28, 'No seas sin causa testigo contra tu prójimo; Y no lisonjees con tus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 29, 'No digas: Como me hizo, así le haré; Daré el pago al hombre según su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 30, 'Pasé junto á la heredad del hombre perezoso, Y junto á la viña del hombre falto de entendimiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 31, 'Y he aquí que por toda ella habían ya crecido espinas, Ortigas habían ya cubierto su haz, Y su cerca de piedra estaba ya destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 32, 'Y yo miré, y púse lo en mi corazón: Vi lo, y tomé consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 33, 'Un poco de sueño, cabeceando otro poco, Poniendo mano sobre mano otro poco para dormir;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 24, 34, 'Así vendrá como caminante tu necesidad, Y tu pobreza como hombre de escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 1, 'TAMBIÉN estos son proverbios de Salomón, los cuales copiaron los varones de Ezechîas, rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 2, 'Gloria de Dios es encubrir la palabra; Mas honra del rey es escudriñar la palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 3, 'Para la altura de los cielos, y para la profundidad de la tierra, Y para el corazón de los reyes, no hay investigación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 4, 'Quita las escorias de la plata, Y saldrá vaso al fundidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 5, 'Aparta al impío de la presencia del rey, Y su trono se afirmará en justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 6, 'No te alabes delante del rey, Ni estés en el lugar de los grandes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 7, 'Porque mejor es que se te diga, Sube acá, Que no que seas humillado delante del príncipe Que miraron tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 8, 'No salgas á pleito presto, No sea que no sepas qué hacer al fin, Después que tu prójimo te haya dejado confuso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 9, 'Trata tu causa con tu compañero Y no descubras el secreto á otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 10, 'No sea que te deshonre el que lo oyere, Y tu infamia no pueda repararse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 11, 'Manzana de oro con figuras de plata Es la palabra dicha como conviene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 12, 'Como zarcillo de oro y joyel de oro fino, Es el que reprende al sabio que tiene oído dócil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 13, 'Como frío de nieve en tiempo de la siega, Así es el mensajero fiel á los que lo envían: Pues al alma de su señor da refrigerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 14, 'Como nubes y vientos sin lluvia, Así es el hombre que se jacta de vana liberalidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 15, 'Con larga paciencia se aplaca el príncipe; Y la lengua blanda quebranta los huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 16, '¿Hallaste la miel? come lo que te basta; No sea que te hartes de ella, y la vomites.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 17, 'Detén tu pie de la casa de tu vecino, Porque harto de ti no te aborrezca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 18, 'Martillo y cuchillo y saeta aguda, Es el hombre que habla contra su prójimo falso testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 19, 'Diente quebrado y pie resbalador, Es la confianza en el prevaricador en tiempo de angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 20, 'El que canta canciones al corazón afligido, Es como el que quita la ropa en tiempo de frío, ó el que sobre el jabón echa vinagre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 21, 'Si el que te aborrece tuviere hambre, dale de comer pan; Y si tuviere sed, dale de beber agua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 22, 'Porque ascuas allegas sobre su cabeza, Y Jehová te lo pagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 23, 'El viento del norte ahuyenta la lluvia, Y el rostro airado la lengua detractora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 24, 'Mejor es estar en un rincón de casa, Que con la mujer rencillosa en espaciosa casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 25, 'Como el agua fría al alma sedienta, Así son las buenas nuevas de lejanas tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 26, 'Como fuente turbia y manantial corrompido, Es el justo que cae delante del impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 27, 'Comer mucha miel no es bueno: Ni el buscar la propia gloria es gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 25, 28, 'Como ciudad derribada y sin muro, Es el hombre cuyo espíritu no tiene rienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 1, 'COMO la nieve en el verano, y la lluvia en la siega, Así conviene al necio la honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 2, 'Como el gorrión en su vagar, y como la golondrina en su vuelo, Así la maldición sin causa nunca vendrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 3, 'El látigo para el caballo, y el cabestro para el asno, Y la vara para la espalda del necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 4, 'Nunca respondas al necio en conformidad á su necedad, Para que no seas tú también como él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 5, 'Responde al necio según su necedad, Porque no se estime sabio en su opinión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 6, 'Como el que se corta los pies y bebe su daño, Así es el que envía algo por mano de un necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 7, 'Alzar las piernas del cojo. Así es el proverbio en la boca del necio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 8, 'Como quien liga la piedra en la honda, Así hace el que al necio da honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 9, 'Espinas hincadas en mano del embriagado, Tal es el proverbio en la boca de los necios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 10, 'El grande cría todas las cosas; y da la paga al insensato, Y la da á los transgresores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 11, 'Como perro que vuelve á su vómito, Así el necio que repite su necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 12, '¿Has visto hombre sabio en su opinión? Más esperanza hay del necio que de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 13, 'Dice el perezoso: El león está en el camino; El león está en las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 14, 'Las puertas se revuelven en sus quicios: Así el perezoso en su cama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 15, 'Esconde el perezoso su mano en el seno; Cánsase de tornarla á su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 16, 'A su ver es el perezoso más sabio Que siete que le den consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 17, 'El que pasando se deja llevar de la ira en pleito ajeno, Es como el que toma al perro por las orejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 18, 'Como el que enloquece, y echa llamas Y saetas y muerte,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 19, 'Tal es el hombre que daña á su amigo, Y dice: Ciertamente me chanceaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 20, 'Sin leña se apaga el fuego: Y donde no hay chismoso, cesa la contienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 21, 'El carbón para brasas, y la leña para el fuego: Y el hombre rencilloso para encender contienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 22, 'Las palabras del chismoso parecen blandas; Mas ellas entran hasta lo secreto del vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 23, 'Como escoria de plata echada sobre el tiesto, Son los labios enardecidos y el corazón malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 24, 'Otro parece en los labios al que aborrece; Mas en su interior pone engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 25, 'Cuando hablare amigablemente, no le creas; Porque siete abominaciones hay en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 26, 'Encúbrese el odio con disimulo; Mas su malicia será descubierta en la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 27, 'El que cavare sima, caerá en ella: Y el que revuelva la piedra, á él volverá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 26, 28, 'La falsa lengua atormenta al que aborrece: Y la boca lisonjera hace resbaladero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 1, 'NO te jactes del día de mañana; Porque no sabes qué dará de sí el día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 2, 'Alábete el extraño, y no tu boca; El ajeno, y no tus labios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 3, 'Pesada es la piedra, y la arena pesa; Mas la ira del necio es más pesada que ambas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 4, 'Cruel es la ira, é impetuoso el furor; Mas ¿quién parará delante de la envidia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 5, 'Mejor es reprensión manifiesta Que amor oculto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 6, 'Fieles son las heridas del que ama; Pero importunos los besos del que aborrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 7, 'El alma harta huella el panal de miel; Mas al alma hambrienta todo lo amargo es dulce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 8, 'Cual ave que se va de su nido, Tal es el hombre que se va de su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 9, 'El ungüento y el perfume alegran el corazón: Y el amigo al hombre con el cordial consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 10, 'No dejes á tu amigo, ni al amigo de tu padre; Ni entres en casa de tu hermano el día de tu aflicción. Mejor es el vecino cerca que el hermano lejano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 11, 'Sé sabio, hijo mío, y alegra mi corazón, Y tendré qué responder al que me deshonrare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 12, 'El avisado ve el mal, y escóndese, Mas los simples pasan, y llevan el daño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 13, 'Quítale su ropa al que fió al extraño; Y al que fió á la extraña, tómale prenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 14, 'El que bendice á su amigo en alta voz, madrugando de mañana, Por maldición se le contará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 15, 'Gotera continua en tiempo de lluvia, Y la mujer rencillosa, son semejantes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 16, 'El que pretende contenerla, arresta el viento: O el aceite en su mano derecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 17, 'Hierro con hierro se aguza; Y el hombre aguza el rostro de su amigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 18, 'El que guarda la higuera, comerá su fruto; Y el que guarda á su señor, será honrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 19, 'Como un agua se parece á otra, Así el corazón del hombre al otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 20, 'El sepulcro y la perdición nunca se hartan: Así los ojos del hombre nunca están satisfechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 21, 'El crisol prueba la plata, y la hornaza el oro: Y al hombre la boca del que lo alaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 22, 'Aunque majes al necio en un mortero entre granos de trigo á pisón majados, No se quitará de él su necedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 23, 'Considera atentamente el aspecto de tus ovejas; Pon tu corazón á tus rebaños:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 24, 'Porque las riquezas no son para siempre; ¿Y será la corona para perpetuas generaciones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 25, 'Saldrá la grama, aparecerá la hierba, Y segaránse las hierbas de los montes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 26, 'Los corderos para tus vestidos, Y los cabritos para el precio del campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 27, 27, 'Y abundancia de leche de las cabras para tu mantenimiento, y para mantenimiento de tu casa, Y para sustento de tus criadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 1, 'HUYE el impío sin que nadie lo persiga: Mas el justo está confiado como un leoncillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 2, 'Por la rebelión de la tierra sus príncipes son muchos: Mas por el hombre entendido y sabio permanecerá sin mutación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 3, 'El hombre pobre y robador de los pobres, Es lluvia de avenida y sin pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 4, 'Los que dejan la ley, alaban á los impíos: Mas los que la guardan, contenderán con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 5, 'Los hombres malos no entienden el juicio: Mas los que buscan á Jehová, entienden todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 6, 'Mejor es el pobre que camina en su integridad, Que el de perversos caminos, y rico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 7, 'El que guarda la ley es hijo prudente: Mas el que es compañero de glotones, avergüenza á su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 8, 'El que aumenta sus riquezas con usura y crecido interés, Para que se dé á los pobres lo allega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 9, 'El que aparta su oído para no oir la ley, Su oración también es abominable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 10, 'El que hace errar á los rectos por el mal camino, Él caerá en su misma sima: Mas los perfectos heredarán el bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 11, 'El hombre rico es sabio en su opinión: Mas el pobre entendido lo examinará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 12, 'Cuando los justos se alegran, grande es la gloria; Mas cuando los impíos son levantados, es buscado el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 13, 'El que encubre sus pecados, no prosperará: Mas el que los confiesa y se aparta, alcanzará misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 14, 'Bienaventurado el hombre que siempre está temeroso: Mas el que endurece su corazón, caerá en mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 15, 'León rugiente y oso hambriento, Es el príncipe impío sobre el pueblo pobre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 16, 'El príncipe falto de entendimiento multiplicará los agravios: Mas el que aborrece la avaricia, prolongará sus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 17, 'El hombre que hace violencia con sangre de persona, Huirá hasta el sepulcro, y nadie le detendrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 18, 'El que en integridad camina, será salvo; Mas el de perversos caminos caerá en alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 19, 'El que labra su tierra, se hartará de pan: Mas el que sigue los ociosos, se hartará de pobreza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 20, 'El hombre de verdad tendrá muchas bendiciones: Mas el que se apresura á enriquecer, no será sin culpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 21, 'Tener acepción de personas, no es bueno: Hasta por un bocado de pan prevaricará el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 22, 'Apresúrase á ser rico el hombre de mal ojo; Y no conoce que le ha de venir pobreza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 23, 'El que reprende al hombre, hallará después mayor gracia Que el que lisonjea con la lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 24, 'El que roba á su padre ó á su madre, y dice que no es maldad, Compañero es del hombre destruidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 25, 'El altivo de ánimo suscita contiendas: Mas el que en Jehová confía, medrará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 26, 'El que confía en su corazón es necio; Mas el que camina en sabiduría, será salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 27, 'El que da al pobre, no tendrá pobreza: Mas el que aparta sus ojos, tendrá muchas maldiciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 28, 28, 'Cuando los impíos son levantados, esconderáse el hombre: Mas cuando perecen, los justos se multiplican.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 1, 'EL hombre que reprendido endurece la cerviz, De repente será quebrantado; ni habrá para él medicina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 2, 'Cuando los justos dominan, el pueblo se alegra: Mas cuando domina el impío, el pueblo gime.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 3, 'El hombre que ama la sabiduría, alegra á su padre: Mas el que mantiene rameras, perderá la hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 4, 'El rey con el juicio afirma la tierra: Mas el hombre de presentes la destruirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 5, 'El hombre que lisonjea á su prójimo, Red tiende delante de sus pasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 6, 'En la prevaricación del hombre malo hay lazo: Mas el justo cantará y se alegrará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 7, 'Conoce el justo la causa de los pobres: Mas el impío no entiende sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 8, 'Los hombres escarnecedores enlazan la ciudad: Mas los sabios apartan la ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 9, 'Si el hombre sabio contendiere con el necio, Que se enoje ó que se ría, no tendrá reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 10, 'Los hombres sanguinarios aborrecen al perfecto: Mas los rectos buscan su contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 11, 'El necio da suelta á todo su espíritu; Mas el sabio al fin le sosiega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 12, 'Del señor que escucha la palabra mentirosa, Todos sus ministros son impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 13, 'El pobre y el usurero se encontraron: Jehová alumbra los ojos de ambos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 14, 'El rey que juzga con verdad á los pobres, Su trono será firme para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 15, 'La vara y la corrección dan sabiduría: Mas el muchacho consentido avergonzará á su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 16, 'Cuando los impíos son muchos, mucha es la prevaricación; Mas los justos verán la ruina de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 17, 'Corrige á tu hijo, y te dará descanso, Y dará deleite á tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 18, 'Sin profecía el pueblo será disipado: Mas el que guarda la ley, bienaventurado él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 19, 'El siervo no se corregirá con palabras: Porque entiende, mas no corresponde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 20, '¿Has visto hombre ligero en sus palabras? Más esperanza hay del necio que de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 21, 'El que regala á su siervo desde su niñez, A la postre será su hijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 22, 'El hombre iracundo levanta contiendas; Y el furioso muchas veces peca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 23, 'La soberbia del hombre le abate; Pero al humilde de espíritu sustenta la honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 24, 'El aparcero del ladrón aborrece su vida; Oirá maldiciones, y no lo denunciará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 25, 'El temor del hombre pondrá lazo: Mas el que confía en Jehová será levantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 26, 'Muchos buscan el favor del príncipe: Mas de Jehová viene el juicio de cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 29, 27, 'Abominación es á los justos el hombre inicuo; Y abominación es al impío el de rectos caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 1, 'PALABRAS de Agur, hijo de Jachê: La profecía que dijo el varón á Ithiel, á Ithiel y á Ucal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 2, 'Ciertamente más rudo soy yo que ninguno, Ni tengo entendimiento de hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 3, 'Yo ni aprendí sabiduría, Ni conozco la ciencia del Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 4, '¿Quién subió al cielo, y descendió? ¿Quién encerró los vientos en sus puños? ¿Quién ató las aguas en un paño? ¿Quién afirmó todos los términos de la tierra? ¿Cuál es su nombre, y el nombre de su hijo, si sabes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 5, 'Toda palabra de Dios es limpia: Es escudo á los que en él esperan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 6, 'No añadas á sus palabras, porque no te reprenda, Y seas hallado mentiroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 7, 'Dos cosas te he demandado; No me las niegues antes que muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 8, 'Vanidad y palabra mentirosa aparta de mí. No me des pobreza ni riquezas; Manténme del pan que he menester;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 9, 'No sea que me harte, y te niegue, y diga, ¿Quién es Jehová? O no sea que siendo pobre, hurte, Y blasfeme el nombre de mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 10, 'No acuses al siervo ante su señor, Porque no te maldiga, y peques.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 11, 'Hay generación que maldice á su padre, Y á su madre no bendice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 12, 'Hay generación limpia en su opinión, Si bien no se ha limpiado su inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 13, 'Hay generación cuyos ojos son altivos, Y cuyos párpados son alzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 14, 'Hay generación cuyos dientes son espadas, y sus muelas cuchillos, Para devorar á los pobres de la tierra, y de entre los hombres á los menesterosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 15, 'La sanguijuela tiene dos hijas que se llaman, Trae, trae. Tres cosas hay que nunca se hartan; Aun la cuarta nunca dice, Basta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 16, 'El sepulcro, y la matriz estéril, La tierra no harta de aguas, Y el fuego que jamás dice, Basta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 17, 'El ojo que escarnece á su padre, Y menosprecia la enseñanza de la madre, Los cuervos lo saquen de la arroyada, Y tráguenlo los hijos del águila.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 18, 'Tres cosas me son ocultas; Aun tampoco sé la cuarta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 19, 'El rastro del águila en el aire; El rastro de la culebra sobre la peña; El rastro de la nave en medio de la mar; Y el rastro del hombre en la moza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 20, 'Tal es el rastro de la mujer adúltera: Come, y limpia su boca, Y dice: No he hecho maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 21, 'Por tres cosas se alborota la tierra, Y la cuarta no puede sufrir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 22, 'Por el siervo cuando reinare; Y por el necio cuando se hartare de pan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 23, 'Por la aborrecida cuando se casare; Y por la sierva cuando heredare á su señora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 24, 'Cuatro cosas son de las más pequeñas de la tierra, Y las mismas son más sabias que los sabios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 25, 'Las hormigas, pueblo no fuerte, Y en el verano preparan su comida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 26, 'Los conejos, pueblo nada esforzado, Y ponen su casa en la piedra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 27, 'Las langostas, no tienen rey, Y salen todas acuadrilladas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 28, 'La araña, ase con las manos, Y está en palacios de rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 29, 'Tres cosas hay de hermoso andar, Y la cuarta pasea muy bien:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 30, 'El león, fuerte entre todos los animales, Que no torna atrás por nadie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 31, 'El lebrel ceñido de lomos; asimismo el macho cabrío; Y un rey contra el cual ninguno se levanta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 32, 'Si caiste, fué porque te enalteciste; Y si mal pensaste, Pon el dedo sobre la boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 30, 33, 'Ciertamente el que exprime la leche, sacará manteca; Y el que recio se suena las narices, sacará sangre: Y el que provoca la ira, causará contienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 1, 'PALABRAS del rey Lemuel; la profecía con que le enseñó su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 2, '¿Qué, hijo mío? ¿y qué, hijo de mi vientre? ¿Y qué, hijo de mis deseos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 3, 'No des á las mujeres tu fuerza, Ni tus caminos á lo que es para destruir los reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 4, 'No es de los reyes, oh Lemuel, no es de los reyes beber vino, Ni de los príncipes la cerveza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 5, 'No sea que bebiendo olviden la ley, Y perviertan el derecho de todos los hijos afligidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 6, 'Dad la cerveza al desfallecido, Y el vino á los de amargo ánimo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 7, 'Beban, y olvídense de su necesidad, Y de su miseria no más se acuerden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 8, 'Abre tu boca por el mudo, En el juicio de todos los hijos de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 9, 'Abre tu boca, juzga justicia, Y el derecho del pobre y del menesteroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 10, 'Mujer fuerte, ¿quién la hallará? Porque su estima sobrepuja largamente á la de piedras preciosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 11, 'El corazón de su marido está en ella confiado, Y no tendrá necesidad de despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 12, 'Darále ella bien y no mal, Todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 13, 'Buscó lana y lino, Y con voluntad labró de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 14, 'Fué como navío de mercader: Trae su pan de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 15, 'Levantóse aun de noche, Y dió comida á su familia, Y ración á sus criadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 16, 'Consideró la heredad, y compróla; Y plantó viña del fruto de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 17, 'Ciñó sus lomos de fortaleza, Y esforzó sus brazos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 18, 'Gustó que era buena su granjería: Su candela no se apagó de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 19, 'Aplicó sus manos al huso, Y sus manos tomaron la rueca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 20, 'Alargó su mano al pobre, Y extendió sus manos al menesteroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 21, 'No tendrá temor de la nieve por su familia, Porque toda su familia está vestida de ropas dobles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 22, 'Ella se hizo tapices; De lino fino y púrpura es su vestido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 23, 'Conocido es su marido en las puertas, Cuando se sienta con los ancianos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 24, 'Hizo telas, y vendió; Y dió cintas al mercader.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 25, 'Fortaleza y honor son su vestidura; Y en el día postrero reirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 26, 'Abrió su boca con sabiduría: Y la ley de clemencia está en su lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 27, 'Considera los caminos de su casa, Y no come el pan de balde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 28, 'Levantáronse sus hijos, y llamáronla bienaventurada; Y su marido también la alabó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 29, 'Muchas mujeres hicieron el bien; Mas tú las sobrepujaste á todas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 30, 'Engañosa es la gracia, y vana la hermosura: La mujer que teme á Jehová, ésa será alabada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PRO', 'Proverbios', 31, 31, 'Dadle el fruto de sus manos, Y alábenla en las puertas sus hechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 1, 'CANCION de canciones, la cual es de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 2, '¡Oh si él me besara con ósculos de su boca! Porque mejores son tus amores que el vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 3, 'Por el olor de tus suaves unguüentos, (Ungüento derramado es tu nombre,) Por eso las doncellas te amaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 4, 'Llévame en pos de ti, correremos. Metióme el rey en sus cámaras: Nos gozaremos y alegraremos en ti; Acordarémonos de tus amores más que del vino: Los rectos te aman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 5, 'Morena soy, oh hijas de Jerusalem, Mas codiciable; Como las cabañas de Cedar, Como las tiendas de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 6, 'No miréis en que soy morena, Porque el sol me miró. Los hijos de mi madre se airaron contra mí, Hiciéronme guarda de viñas; Y mi viña, que era mía, no guardé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 7, 'Hazme saber, ó tú á quien ama mi alma, Dónde repastas, dónde haces tener majada al medio día: Porque, ¿por qué había yo de estar como vagueando Tras los rebaños de tus compañeros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 8, 'Si tú no lo sabes, oh hermosa entre las mujeres, Sal, yéndote por las huellas del rebaño, Y apacienta tus cabritas junto á las cabañas de los pastores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 9, 'A yegua de los carros de Faraón Te he comparado, amiga mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 10, 'Hermosas son tus mejillas entre los pendientes, Tu cuello entre los collares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 11, 'Zarcillos de oro te haremos, Con clavos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 12, 'Mientras que el rey estaba en su reclinatorio, Mi nardo dió su olor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 13, 'Mi amado es para mí un manojito de mirra, Que reposa entre mis pechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 14, 'Racimo de copher en las viñas de Engadi Es para mí mi amado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 15, 'He aquí que tú eres hermosa, amiga mía; He aquí que eres bella: tus ojos de paloma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 16, 'He aquí que tú eres hermoso, amado mío, y suave: Nuestro lecho también florido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 1, 17, 'Las vigas de nuestra casa son de cedro, Y de ciprés los artesonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 1, 'YO soy la rosa de Sarón, Y el lirio de los valles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 2, 'Como el lirio entre las espinas, Así es mi amiga entre las doncellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 3, 'Como el manzano entre los árboles silvestres, Así es mi amado entre los mancebos: Bajo la sombra del deseado me senté, Y su fruto fué dulce en mi paladar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 4, 'Llevóme á la cámara del vino, Y su bandera sobre mí fué amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 5, 'Sustentadme con frascos, corroboradme con manzanas; Porque estoy enferma de amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 6, 'Su izquierda esté debajo de mi cabeza, Y su derecha me abrace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 7, 'Yo os conjuro, oh doncellas de Jerusalem, Por las gamas y por las ciervas del campo, Que no despertéis ni hagáis velar al amor Hasta que quiera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 8, '¡La voz de mi amado! He aquí él viene Saltando sobre los montes, brincando sobre los collados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 9, 'Mi amado es semejante al gamo, ó al cabrito de los ciervos. Helo aquí, está tras nuestra pared, Mirando por las ventanas, Mostrándose por las rejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 10, 'Mi amado habló, y me dijo: Levántate, oh amiga mía, hermosa mía, y vente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 11, 'Porque he aquí ha pasado el invierno, Hase mudado, la lluvia se fué;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 12, 'Hanse mostrado las flores en la tierra, El tiempo de la canción es venido, Y en nuestro país se ha oído la voz de la tórtola;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 13, 'La higuera ha echado sus higos, Y las vides en cierne Dieron olor: Levántate, oh amiga mía, hermosa mía, y vente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 14, 'Paloma mía, que estás en los agujeros de la peña, en lo escondido de escarpados parajes, Muéstrame tu rostro, hazme oir tu voz; Porque dulce es la voz tuya, y hermoso tu aspecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 15, 'Cazadnos las zorra, las zorras pequeñas, que echan á perder las viñas; Pues que nuestras viñas están en cierne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 16, 'Mi amado es mío, y yo suya; El apacienta entre lirios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 2, 17, 'Hasta que apunte el día, y huyan las sombras, Tórnate, amado mío; sé semejante al gamo, ó al cabrito de los ciervos, Sobre los montes de Bether.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 1, 'POR las noches busqué en mi lecho al que ama mi alma: Busquélo, y no lo hallé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 2, 'Levantaréme ahora, y rodearé por la ciudad; Por las calles y por las plazas Buscaré al que ama mi alma: Busquélo, y no lo hallé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 3, 'Halláronme los guardas que rondan la ciudad, Y díjeles: ¿Habéis visto al que ama mi alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 4, 'Pasando de ellos un poco, Hallé luego al que mi alma ama: Trabé de él, y no lo dejé, Hasta que lo metí en casa de mi madre, Y en la cámara de la que me engendró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 5, 'Yo os conjuro, oh doncellas de Jerusalem, Por las gamas y por las ciervas del campo, Que no despertéis ni hagáis velar al amor, Hasta que quiera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 6, '¿Quién es ésta que sube del desierto como columnita de humo, Sahumada de mirra y de incienso, Y de todos polvos aromáticos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 7, 'He aquí es la litera de Salomón: Sesenta valientes la rodean, De los fuertes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 8, 'Todos ellos tienen espadas, diestros en la guerra; Cada uno su espada sobre su muslo, Por los temores de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 9, 'El rey Salomón se hizo una carroza De madera del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 10, 'Sus columnas hizo de plata, Su respaldo de oro, su cielo de grana, Su interior enlosado de amor, Por las doncellas de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 3, 11, 'Salid, oh doncellas de Sión, y ved al rey Salomón Con la corona con que le coronó su madre el día de su desposorio, Y el día del gozo de su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 1, 'HE aquí que tú eres hermosa, amiga mía, he aquí que tú eres hermosa; Tus ojos entre tus guedejas como de paloma; Tus cabellos como manada de cabras, Que se muestran desde el monte de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 2, 'Tus dientes, como manadas de trasquiladas ovejas, Que suben del lavadero, Todas con crías mellizas, Y ninguna entre ellas estéril.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 3, 'Tus labios, como un hilo de grana, Y tu habla hermosa; Tus sienes, como cachos de granada á la parte adentro de tus guedejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 4, 'Tu cuello, como la torre de David, edificada para muestra; Mil escudos están colgados de ella, Todos escudos de valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 5, 'Tus dos pechos, como dos cabritos mellizos de gama, Que son apacentados entre azucenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 6, 'Hasta que apunte el día y huyan las sombras, Iréme al monte de la mirra, Y al collado del incienso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 7, 'Toda tú eres hermosa, amiga mía Y en ti no hay mancha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 8, 'Conmigo del Líbano, oh esposa, Conmigo ven del Líbano: Mira desde la cumbre de Amana, Desde la cumbre de Senir y de Hermón, Desde las guaridas de los leones, Desde los montes de los tigres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 9, 'Prendiste mi corazón, hermana, esposa mía; Has preso mi corazón con uno de tus ojos, Con una gargantilla de tu cuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 10, '¡Cuán hermosos son tus amores, hermana, esposa mía! ¡Cuánto mejores que el vino tus amores, Y el olor de tus ungüentos que todas las especias aromáticas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 11, 'Como panal de miel destilan tus labios, oh esposa; Miel y leche hay debajo de tu lengua; Y el olor de tus vestidos como el olor del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 12, 'Huerto cerrado eres, mi hermana, esposa mía; Fuente cerrada, fuente sellada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 13, 'Tus renuevos paraíso de granados, con frutos suaves, De cámphoras y nardos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 14, 'Nardo y azafrán, Caña aromática y canela, con todos los árboles de incienso; Mirra y áloes, con todas las principales especias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 15, 'Fuente de huertos, Pozo de aguas vivas, Que corren del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 4, 16, 'Levántate, Aquilón, y ven, Austro: Sopla mi huerto, despréndanse sus aromas. Venga mi amado á su huerto, Y coma de su dulce fruta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 1, 'YO vine á mi huerto, oh hermana, esposa mía: Cogido he mi mirra y mis aromas; He comido mi panal y mi miel, Mi vino y mi leche he bebido. Comed, amigos; Babed, amados, y embriagaos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 2, 'Yo dormía, pero mi corazón velaba: La voz de mi amado que llamaba: Abreme, hermana mía, amiga mía, paloma mía, perfecta mía; Porque mi cabeza está llena de rocío, Mis cabellos de las gotas de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 3, 'Heme desnudado mi ropa; ¿cómo la tengo de vestir? He lavado mis pies; ¿cómo los tengo de ensuciar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 4, 'Mi amado metió su mano por el agujero, Y mis entrañas se conmovieron dentro de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 5, 'Yo me levanté para abrir á mi amado, Y mis manos gotearon mirra, Y mis dedos mirra que corría Sobre las aldabas del candado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 6, 'Abrí yo á mi amado; Mas mi amado se había ido, había ya pasado: Y tras su hablar salió mi alma: Busquélo, y no lo hallé; Llamélo, y no me respondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 7, 'Halláronme los guardas que rondan la ciudad: Hiriéronme, llagáronme, Quitáronme mi manto de encima los guardas de los muros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 8, 'Yo os conjuro, oh doncellas de Jerusalem, si hallareis á mi amado, Que le hagáis saber cómo de amor estoy enferma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 9, '¿Qué es tu amado más que otro amado, Oh la más hermosa de todas las mujeres? ¿Qué es tu amado más que otro amado, Que así nos conjuras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 10, 'Mi amado es blanco y rubio, Señalado entre diez mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 11, 'Su cabeza, como, oro finísimo; Sus cabellos crespos, negros como el cuervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 12, 'Sus ojos, como palomas junto á los arroyos de las aguas, Que se lavan con leche, y a la perfección colocados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 13, 'Sus mejillas, como una era de especias aromáticas, como fragantes flores: Sus labios, como lirios que destilan mirra que trasciende.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 14, 'Sus manos, como anillos de oro engastados de jacintos: Su vientre, como claro marfil cubierto de zafiros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 15, 'Sus piernas, como columnas de mármol fundadas sobre basas de fino oro: Su aspecto como el Líbano, escogido como los cedros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 5, 16, 'Su paladar, dulcísimo: y todo él codiciable. Tal es mi amado, tal es mi amigo, Oh doncellas de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 1, '¿DONDE se ha ido tu amado, Oh la más hermosa de todas las mujeres? ¿Adónde se apartó tu amado, Y le buscaremos contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 2, 'Mi amado descendió á su huerto, á las eras de los aromas Para apacentar en los huertos, y para coger los lirios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 3, 'Yo soy de mi amado, y mi amado es mío: El apacienta entre los lirios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 4, 'Hermosa eres tú, oh amiga mía, como Tirsa; De desear, como Jerusalem; Imponente como ejércitos en orden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 5, 'Aparta tus ojos de delante de mí, Porque ellos me vencieron. Tu cabello es como manada de cabras, Que se muestran en Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 6, 'Tus dientes, como manada de ovejas Que suben del lavadero, Todas con crías mellizas, Y estéril no hay entre ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 7, 'Como cachos de granada son tus sienes Entre tus guedejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 8, 'Sesenta son las reinas, y ochenta las concubinas, Y las doncellas sin cuento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 9, 'Mas una es la paloma mía, la perfecta mía; Unica es á su madre, Escogida á la que la engendró. Viéronla las doncellas, y llamáronla bienaventurada; Las reinas y las concubinas, y la alabaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 10, '¿Quién es ésta que se muestra como el alba, Hermosa como la luna, Esclarecida como el sol, Imponente como ejércitos en orden?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 11, 'Al huerto de los nogales descendí A ver los frutos del valle, Y para ver si brotaban las vides, Si florecían los granados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 12, 'No lo supe: hame mi alma hecho Como los carros de Amminadab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 6, 13, 'Tórnate, tórnate, oh Sulamita; Tórnate, tórnate, y te miraremos. ¿Qué veréis en la Sulamita? Como la reunión de dos campamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 1, '¡CUAN hermosos son tus pies en los calzados, oh hija de príncipe! Los contornos de tus muslos son como joyas, Obra de mano de excelente maestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 2, 'Tu ombligo, como una taza redonda, Que no le falta bebida. Tu vientre, como montón de trigo, Cercado de lirios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 3, 'Tus dos pechos, como dos cabritos Mellizos de gama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 4, 'Tu cuello, como torre de marfil; Tus ojos, como las pesqueras de Hesbón junto á la puerta de Bat-rabbim; Tu nariz, como la torre del Líbano, Que mira hacia Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 5, 'Tu cabeza encima de ti, como el Carmelo; Y el cabello de tu cabeza, como la púrpura del rey Ligada en los corredores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 6, '¡Qué hermosa eres, y cuán suave, Oh amor deleitoso!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 7, 'Y tu estatura es semejante á la palma, Y tus pechos á los racimos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 8, 'Yo dije: Subiré á la palma, Asiré sus ramos: Y tus pechos serán ahora como racimos de vid, Y el olor de tu boca como de manzanas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 9, 'Y tu paladar como el buen vino, Que se entra á mi amado suavemente, Y hace hablar los labios de los viejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 10, 'Yo soy de mi amado, Y conmigo tiene su contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 11, 'Ven, oh amado mío, salgamos al campo, Moremos en las aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 12, 'Levantémonos de mañana á las viñas; Veamos si brotan las vides, si se abre el cierne, Si han florecido los granados; Allí te daré mis amores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 7, 13, 'Las mandrágoras han dado olor, Y á nuestras puertas hay toda suerte de dulces frutas, nuevas y añejas. Que para ti, oh amado mío, he guardado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 1, '¡OH quién te me diese como hermano Que mamó los pechos de mi madre; De modo que te halle yo fuera, y te bese, Y no me menosprecien!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 2, 'Yo te llevaría, te metiera en casa de mi madre: Tú me enseñarías, Y yo te hiciera beber vino Adobado del mosto de mis granadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 3, 'Su izquierda esté debajo de mi cabeza, Y su derecha me abrace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 4, 'Conjúroos, oh doncellas de Jerusalem, Que no despertéis, ni hagáis velar al amor, Hasta que quiera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 5, '¿Quién es ésta que sube del desierto, Recostada sobre su amado? Debajo de un manzano te desperté: Allí tuvo tu madre dolores, Allí tuvo dolores la que te parió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 6, 'Ponme como un sello sobre tu corazón, como una marca sobre tu brazo: Porque fuerte es como la muerte el amor; Duro como el sepulcro el celo: Sus brasas, brasas de fuego, Fuerte llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 7, 'Las muchas aguas no podrán apagar el amor, Ni lo ahogarán los ríos. Si diese el hombre toda la hacienda de su casa por este amor, De cierto lo menospreciaran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 8, 'Tenemos una pequeña hermana, Que no tiene pechos: ¿Qué haremos á nuestra hermana Cuando de ella se hablare?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 9, 'Si ella es muro, Edificaremos sobre él un palacio de plata: Y si fuere puerta, La guarneceremos con tablas de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 10, 'Yo soy muro, y mis pechos como torres, Desde que fuí en sus ojos como la que halla paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 11, 'Salomón tuvo una viña en Baal-hamón, La cual entregó á guardas, Cada uno de los cuales debía traer mil monedas de plata por su fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 12, 'Mi viña, que es mía, está delante de mí: Las mil serán tuyas, oh Salomón, Y doscientas, de los que guardan su fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 13, 'Oh tú la que moras en los huertos, Los compañeros escuchan tu voz: Házmela oir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('SNG', 'Cantares', 8, 14, 'Huye, amado mío; Y sé semejante al gamo, ó al cervatillo, Sobre las montañas de los aromas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 1, 'PALABRA de Jehová que fué á Oseas hijo de Beeri, en días de Ozías, Joathán, Achâz, y Ezechîas, reyes de Judá, y en días de Jeroboam hijo de Joas, rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 2, 'El principio de la palabra de Jehová con Oseas. Y dijo Jehová á Oseas: Ve, tómate una mujer fornicaria, é hijos de fornicaciones: porque la tierra se dará á fornicar apartándose de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 3, 'Fué pues, y tomó á Gomer hija de Diblaim, la cual concibió y le parió un hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 4, 'Y díjole Jehová: Ponle por nombre Jezreel; porque de aquí á poco yo visitaré las sangres de Jezreel sobre la casa de Jehú, y haré cesar el reino de la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 5, 'Y acaecerá que en aquel día quebraré yo el arco de Israel en el valle de Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 6, 'Y concibió aún, y parió una hija. Y díjole Dios: Ponle por nombre Lo-ruhama: porque no más tendré misericordia de la casa de Israel, sino que los quitaré del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 7, 'Mas de la casa de Judá tendré misericordia, y salvarélos en Jehová su Dios: y no los salvaré con arco, ni con espada, ni con batalla, ni con caballos ni caballeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 8, 'Y después de haber destetado á Lo-ruhama, concibió y parió un hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 9, 'Y dijo Dios: Ponle por nombre Lo-ammi: porque vosotros no sois mi pueblo, ni yo seré vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 10, 'Con todo será el número de los hijos de Israel como la arena de la mar, que ni se puede medir ni contar. Y será, que donde se les ha dicho: Vosotros no sois mi pueblo, les será dicho: Sois hijos del Dios viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 1, 11, 'Y los hijos de Judá y de Israel serán congregados en uno, y levantarán para sí una cabeza, y subirán de la tierra: porque el día de Jezreel será grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 1, 'DECID á vuestros hermanos, Ammi, y vuestras hermanas, Ruhama:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 2, 'Pleitead con vuestra madre, pleitead; porque ella no es mi mujer, ni yo su marido; quite pues sus fornicaciones de su rostro, y sus adulterios de entre sus pechos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 3, 'No sea que yo la despoje desnuda, y la haga tornar como el día en que nació, y la ponga como un desierto, y la deje como tierra seca, y la mate de sed.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 4, 'Ni tendré misericordia de sus hijos: porque son hijos de fornicaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 5, 'Porque su madre fornicó; la que los engendró fué avergonzada; porque dijo: Iré tras mis amantes, que me dan mi pan y mi agua, mi lana y mi lino, mi aceite y mi bebida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 6, 'Por tanto, he aquí yo cerco tu camino con espinas, y la cercaré con seto, y no hallará sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 7, 'Y seguirá sus amantes, y no los alcanzará; buscarálos, y no los hallará. Entonces dira: Iré, y volvéreme á mi primer marido; porque mejor me iba entonces que ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 8, 'Y ella no reconoció que yo le daba el trigo, y el vino, y el aceite, y que les multipliqué la plata y el oro con que hicieron á Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 9, 'Por tanto yo tornaré, y tomaré mi trigo á su tiempo, y mi vino á su sazón, y quitaré mi lana y mi lino que había dado para cubrir su desnudez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 10, 'Y ahora descubriré yo su locura delante de los ojos de sus amantes, y nadie la librará de mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 11, 'Y haré cesar todo su gozo, sus fiestas, sus nuevas lunas y sus sábados, y todas sus festividades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 12, 'Y haré talar sus vides y sus higueras, de que ha dicho: Mi salario me son, que me han dado mis amantes. Y reducirélas á un matorral, y las comerán las bestias del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 13, 'Y visitaré sobre ella los tiempos de los Baales, á los cuales incensaba, y adornábase de sus zarcillos y de sus joyeles, é íbase tras sus amantes olvidada de mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 14, 'Empero he aquí, yo la induciré, y la llevaré al desierto, y hablaré á su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 15, 'Y daréle sus viñas desde allí, y el valle de Achôr por puerta de esperanza; y allí cantará como en los tiempos de su juventud, y como en el día de su subida de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 16, 'Y será que en aquel tiempo, dice Jehová, me llamarás Marido mío, y nunca más me llamarás Baali.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 17, 'Porque quitaré de su boca los nombres de los Baales, y nunca más serán mentados por sus nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 18, 'Y haré por ellos concierto en aquel tiempo con las bestias del campo, y con las aves del cielo, y con las serpientes de la tierra: y quebraré arco, y espada, y batalla de la tierra, y harélos dormir seguros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 19, 'Y te desposaré conmigo para siempre; desposarte he conmigo en justicia, y juicio, y misericordia, y miseraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 20, 'Y te desposaré conmigo en fe, y conocerás á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 21, 'Y será que en aquel tiempo responderé, dice Jehová, yo responderé á los cielos, y ellos responderán á la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 22, 'Y la tierra responderá al trigo, y al vino, y al aceite, y ellos responderán á Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 2, 23, 'Y sembraréla para mí en la tierra, y tendré misericordia de Lo-ruhama: y diré á Lo-ammi: Pueblo mío tú; y él dirá: Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 3, 1, 'Y DIJOME otra vez Jehová: Ve, ama una mujer amada de su compañero, aunque adúltera, como el amor de Jehová para con los hijos de Israel; los cuales miran á dioses ajenos, y aman frascos de vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 3, 2, 'Compréla entonces para mí por quince dineros de plata, y un homer y medio de cebada;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 3, 3, 'Y díjele: Tú estarás por mía muchos días: no fornicarás, ni tomáras otro varón; ni tampoco yo vendré á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 3, 4, 'Porque muchos días estarán los hijos de Israel sin rey, y sin príncipe, y sin sacrificio, y sin estatua, y sin ephod, y sin teraphim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 3, 5, 'Después volverán los hijos de Israel, y buscarán á Jehová su Dios, y á David su rey; y temerán á Jehová y á su bondad en el fin de los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 1, 'OID palabra de Jehová, hijos de Israel, porque Jehová pleitea con los moradores de la tierra; porque no hay verdad, ni misericordia, ni conocimiento de Dios en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 2, 'Perjurar, y mentir, y matar, y hurtar y adulterar prevalecieron, y sangres se tocaron con sangres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 3, 'Por lo cual, se enlutará la tierra, y extenuaráse todo morador de ella, con las bestias del campo, y las aves del cielo: y aun los peces de la mar fallecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 4, 'Ciertamente hombre no contienda ni reprenda á hombre, porque tu pueblo es como los que resisten al sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 5, 'Caerás por tanto en el día, y caerá también contigo el profeta de noche; y á tu madre talaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 6, 'Mi pueblo fué talado, porque le faltó sabiduría. Porque tú desechaste la sabiduría, yo te echaré del sacerdocio: y pues que olvidaste la ley de tu Dios, también yo me olvidaré de tus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 7, 'Conforme á su grandeza así pecaron contra mí: trocaré su honra en afrenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 8, 'Comen del pecado de mi pueblo, y en su maldad levantan su alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 9, 'Tal será el pueblo como el sacerdote: y visitaré sobre él sus caminos, y pagaréle conforme á sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 10, 'Y comerán, mas no se hartarán; fornicarán, mas no se aumentarán: porque dejaron de atender á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 11, 'Fornicación, y vino, y mosto quitan el corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 12, 'Mi pueblo á su madero pregunta, y su palo le responde: porque espíritu de fornicaciones lo engañó, y fornicaron debajo de sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 13, 'Sobre las cabezas de los montes sacrificaron, é incensaron sobre los collados, debajo de encinas, y álamos, y olmos que tuviesen buena sombra: por tanto, vuestras hijas fornicarán, y adulterarán vuestras nueras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 14, 'No visitaré sobre vuestras hijas cuando fornicaren, y sobre vuestras nueras cuando adulteraren: porque ellos ofrecen con las rameras, y con las malas mujeres sacrifican: por tanto, el pueblo sin entendimiento caerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 15, 'Si fornicarés tú, Israel, á lo menos no peque Judá: y no entréis en Gilgal, ni subáis á Beth-aven; ni juréis, Vive Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 16, 'Porque como becerra cerrera se apartó Israel: ¿apacentarálos ahora Jehová como á carneros en anchura?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 17, 'Ephraim es dado á ídolos; déjalo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 18, 'Su bebida se corrompió; fornicaron pertinazmente: sus príncipes amaron las dádivas, afrenta de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 4, 19, 'Atóla el viento en sus alas, y de sus sacrificios serán avergonzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 1, 'SACERDOTES, oid esto, y estad atentos, casa de Israel; y casa del rey, escuchad: porque á vosotros es el juicio, pues habéis sido lazo en Mizpa, y red extendida sobre Tabor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 2, 'Y haciendo víctimas han bajado hasta el profundo: por tanto yo seré la corrección de todos ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 3, 'Yo conozco á Ephraim, é Israel no me es desconocido; porque ahora, oh Ephraim, has fornicado, y se ha contaminado Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 4, 'No pondrán sus pensamientos en volverse á su Dios, porque espíritu de fornicación está en medio de ellos, y no conocen á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 5, 'Y la soberbia de Israel le desmentirá en su cara: é Israel y Ephraim tropezarán en su pecado: tropezará también Judá con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 6, 'Con sus ovejas y con sus vacas andarán buscando á Jehová, y no le hallarán; apartóse de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 7, 'Contra Jehová prevaricaron, porque hijos extraños han engendrado: ahora los devorará un mes con sus heredades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 8, 'Tocad bocina en Gabaa, trompreta en Ramá: sonad tambor en Beth-aven: tras ti, oh Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 9, 'Ephraim será asolado el día del castigo: en las tribus de Israel hice conocer verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 10, 'Los príncipes de Judá fueron como los que traspasan mojones: derramaré sobre ellos como agua mi ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 11, 'Ephraim es vejado, quebrantado en juicio, porque quiso andar en pos de mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 12, 'Yo pues seré como polilla á Ephraim, y como carcoma á la casa de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 13, 'Y verá Ephraim su enfermedad, y Judá su llaga: irá entonces Ephraim al Assur, y enviará al rey Jareb; mas él no os podrá sanar, ni os curará la llaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 14, 'Porque yo seré como león á Ephraim, y como cachorro de león á la casa de Judá: yo, yo arrebataré, y andaré; tomaré, y no habrá quien liberte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 5, 15, 'Andaré, y tornaré á mi lugar hasta que conozcan su pecado, y busquen mi rostro. En su angustia madrugarán á mi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 1, 'VENID y volvámonos á Jehová: que él arrebató, y nos curará; hirió, y nos vendará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 2, 'Darános vida después de dos días: al tercer día nos resucitará y viviremos delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 3, 'Y conoceremos, y proseguiremos en conocer á Jehová: como el alba está aparejada su salida, y vendrá á nosotros como la lluvia, como la lluvia tardía y temprana á la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 4, '¿Qué haré á ti, Ephraim? ¿Qué hare á ti, oh Judá? La piedad vuestra es como la nube de la mañana, y como el rocío que de madrugada viene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 5, 'Por esta causa corté con los profetas, con las palabras de mi boca los maté; y tus juicios serán como luz que sale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 6, 'Porque misericordia quise, y no sacrificio; y conocimiento de Dios más que holocaustos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 7, 'Mas ellos, cual Adam, traspasaron el pacto: allí prevaricaron contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 8, 'Galaad, ciudad de obradores de iniquidad, ensuciada de sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 9, 'Y como ladrones que esperan á algún hombre, así junta de sacerdotes mancomunadamente mata en el camino: porque ponen en efecto la abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 10, 'En la casa de Israel he visto suciedad: allí fornicó Ephraim, se contaminó Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 6, 11, 'También Judá puso en ti una planta, habiendo yo vuelto la cautividad de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 1, 'ESTANDO yo curando á Israel, descubrióse la iniquidad de Ephraim, y las maldades de Samaria; porque obraron engaño: y viene el ladrón, y el salteador despoja de fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 2, 'Y no dicen en su corazón que tengo en la memoria toda su maldad: ahora los rodearán sus obras; delante de mí están.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 3, 'Con su maldad alegran al rey, y á los príncipes con sus mentiras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 4, 'Todos ellos adúlteros; son como horno encendido por el hornero, el cual cesará de avivar después que esté hecha la masa, hasta que esté leuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 5, 'El día de nuestro rey los príncipes lo hicieron enfermar con vasos de vino: extendió su mano con los escarnecedores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 6, 'Porque aplicaron su corazón, semejante á un horno, á sus artificios: toda la noche duerme su hornero; á la mañana está encendido como llama de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 7, 'Todos ellos arden como un horno, y devoraron á sus jueces: cayeron todos sus reyes: no hay entre ellos quien á mí clame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 8, 'Ephraim se envolvió con los pueblos; Ephraim fué torta no vuelta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 9, 'Comieron extraños su sustancia, y él no lo supo; y aun vejez se ha esparcido por él, y él no lo entendió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 10, 'Y la soberbia de Israel testificará contra él en su cara: y no se tornaron á Jehová su Dios, ni lo buscaron con todo esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 11, 'Y fué Ephraim como paloma incauta, sin entendimiento: llamarán á Egipto, acudirán al Asirio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 12, 'Cuando fueren, extenderé sobre ellos mi red, hacerlos he caer como aves del cielo; castigarélos conforme á lo que se ha oído en sus congregaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 13, '¡Ay de ellos! porque se apartaron de mí: destrucción sobre ellos, porque contra mí se rebelaron; yo los redimí, y ellos hablaron contra mí mentiras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 14, 'Y no clamaron a mí con su corazón cuando aullaron sobre sus camas, para el trigo y el mosto se congregaron, rebeláronse contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 15, 'Y yo los ceñi, esforcé sus brazos, y contra mí pensaron mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 7, 16, 'Tornáronse, mas no al Altísimo: fueron como arco engañoso: cayeron sus príncipes á cuchillo por la soberbia de su lengua: éste será su escarnio en la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 1, 'PON á tu boca trompeta. Vendrá como águila contra la casa de Jehová, porque traspasaron mi pacto, y se rebelaron contra mi ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 2, 'A mí clamará Israel: Dios mío, te hemos conocido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 3, 'Israel desamparó el bien: enemigo lo perseguirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 4, 'Ellos hicieron reyes, mas no por mí; constituyeron príncipes, mas yo no lo supe: de su plata y de su oro hicieron ídolos para sí, para ser talados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 5, 'Tu becerro, oh Samaria, te hizo alejar; encendióse mi enojo contra ellos, hasta que no pudieron alcanzar inocencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 6, 'Porque de Israel es, y artífice lo hizo; que no es Dios: por lo que en pedazos será deshecho el becerro de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HOS', 'Oseas', 8, 7, 'Porque sembraron viento, y torbellino segarán: no tendrán mies, ni el fruto hará harina; si la hiciere, extraños la tragarán.');
